            box-shadow: 0 0 6px rgba(200, 160, 70, 0.6);
        }
        .base-currency-icon {
            font-size: 28px;
            flex-shrink: 0;
            position: relative;
            z-index: 1;
            filter: drop-shadow(0 0 10px rgba(200, 160, 70, 0.5));
        }
        .sub-item-block {
            background: var(--sub-block-bg);
            border: 1px solid var(--sub-block-border);
            border-top: none;
            border-radius: 0 0 var(--radius-md) var(--radius-md);
            padding: 8px 14px 10px 14px;
            margin: 0;
            color: var(--ink-mid);
        }
        .sub-item-title {
            font-weight: 700;
            font-size: 0.85rem;
            color: var(--sub-block-title-color) !important;
            margin-bottom: 6px;
        }
        .sub-item-line {
            padding: 3px 0 3px 12px;
            border-left: 2px solid var(--sub-block-line-border);
            margin-left: 6px;
