        }
        .climate-phase-wrap {
            background: var(--climate-wrap-bg);
            border-radius: var(--radius-md);
            padding: 10px 14px;
            margin-bottom: 8px;
            border: 1px solid var(--climate-wrap-border);
        }
        .potential-era-group,
        .twist-event-group {
            margin: 8px 0;
            border-radius: 12px;
