        }
        .spec-sentiment-euphoria { background: rgba(220, 150, 30, 0.15); color: #c88c20; border: 1px solid rgba(220, 150, 30, 0.4); }
        .spec-sentiment-optimistic { background: rgba(130, 180, 110, 0.15); color: #5e8c4a; border: 1px solid rgba(130, 180, 110, 0.4); }
        .spec-sentiment-cautious { background: rgba(180, 160, 120, 0.15); color: #8b7a5c; border: 1px solid rgba(180, 150, 90, 0.3); }
        .spec-sentiment-panic { background: rgba(200, 90, 70, 0.15); color: #b8503a; border: 1px solid rgba(200, 90, 70, 0.4); }
        .spec-sentiment-depression { background: rgba(140, 140, 150, 0.2); color: #6b6d80; border: 1px solid rgba(140, 140, 150, 0.4); }
        .theme-dark .spec-sentiment-euphoria { background: rgba(220, 160, 40, 0.2); color: #e8b840; border-color: rgba(220, 160, 40, 0.4); }
        .theme-dark .spec-sentiment-optimistic { background: rgba(130, 190, 110, 0.2); color: #8cd870; border-color: rgba(130, 190, 110, 0.4); }
        .theme-dark .spec-sentiment-cautious { background: rgba(200, 170, 120, 0.15); color: #c4b080; border-color: rgba(200, 165, 90, 0.35); }
        .theme-dark .spec-sentiment-panic { background: rgba(210, 100, 80, 0.25); color: #f09080; border-color: rgba(210, 100, 80, 0.5); }
        .theme-dark .spec-sentiment-depression { background: rgba(120, 120, 140, 0.25); color: #9a9cae; border-color: rgba(120, 120, 140, 0.4); }
        .spec-stock-grid {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
            gap: 10px;
            margin: 10px 0;
        }
        .spec-stock-card {
            background: var(--spec-card-bg);
