                    if (policyMatch) {
                        html += '<div style="margin:8px 0 0 8px;"><span style="font-weight:700;">📜 贸易政策</span></div>';
                        parseTradeSubItems(policyMatch[1]).forEach(item => {
                            html += `<div class="stat-item"><span class="stat-icon">📋</span><span class="stat-value">${escapeHtml(item.substring(0,180))}</span></div>`;
