                if (evMatch) {
                    html += '<div class="sub-card"><div class="l3-toggle" data-l3-role="toggle"><span class="l3-arrow">▼</span><div class="sub-card-title">📰 经济事件</div></div><div class="l3-body open">';
                    parseSubItems(evMatch[1]).forEach(item => {
                        let name = '', rest = item;
                        const bm = item.match(/^\[([^\]]+)\]/);
                        if (bm) {
                            name = bm[1].trim();
                            rest = item.substring(bm[0].length).replace(/^[:：]\s*/, '');
                        } else {
                            const ci = item.search(/[:：]/);
                            if (ci !== -1) { name = item.substring(0, ci).trim(); rest = item.substring(ci + 1).trim(); }
                            else { name = ''; rest = item; }
