                        if (!name) return;
                        const dim = (rest.match(/影响维度:\s*([^|¦]+)/) || [])[1] || '';
                        const status = (rest.match(/当前态势:\s*([^|¦\n]+)/) || [])[1] || '';
                        let desc = rest.replace(/影响维度:\s*[^|¦]+\|?\s*/, '').replace(/当前态势:\s*[^|¦\n]+\s*/, '').replace(/^\s*\|?\s*/, '').trim();
                        // ★ 修复：彻底移除残留的分隔符
                        desc = desc.replace(/[|¦]/g, '').trim();
                        let statusClass = '';
                        if (/恶化|危机|崩溃/i.test(status)) statusClass = 'status-critical';
