            function setupL3ToggleDelegation() {
                const inner = document.getElementById('dynamicContent');
                if (!inner) return;
                if (inner._l3ClickHandler) inner.removeEventListener('click', inner._l3ClickHandler);
                const handler = function(e) {
                    const toggle = e.target.closest('[data-l3-role="toggle"]');
                    if (!toggle) return;
                    let body = null;
                    const pg = toggle.closest('.potential-era-group, .twist-event-group');
                    if (pg) body = pg.querySelector(':scope > .l3-body');
                    else {
                        const sc = toggle.closest('.sub-card');
                        if (sc) body = sc.querySelector(':scope > .l3-body');
                    }
                    if (!body) return;
                    const arrow = toggle.querySelector('.l3-arrow');
                    const isOpen = body.classList.contains('open');
                    if (isOpen) {
                        body.classList.remove('open');
                        if (arrow) arrow.classList.add('collapsed');
                    } else {
                        body.classList.add('open');
                        if (arrow) arrow.classList.remove('collapsed');
                    }
                    e.stopPropagation();
                };
                inner._l3ClickHandler = handler;
                inner.addEventListener('click', handler);
            }

            function renderWorldPaper() {
                try {
                    const containerEl = document.getElementById('dynamicContent');
                    const dateSpan = document.getElementById('briefDatetime');
                    if (!containerEl) return;
                    const rawDataArea = document.getElementById('rawWorldPaperData');
                    let msgText = rawDataArea ? rawDataArea.value : '';
                    if (!msgText || msgText.trim() === '') {
                        containerEl.innerHTML = '<div style="padding:20px;color:var(--ink-light);">📜 没有可用的世界时局数据</div>';
                        if (dateSpan) dateSpan.innerText = '无数据';
                        return;
                    }
                    const worldMatch = msgText.match(/<WorldPaper[^>]*>([\s\S]*?)<\/WorldPaper>/);
                    if (!worldMatch) {
                        containerEl.innerHTML = '<div style="padding:20px;color:#e07060;">⚠️ 未检测到有效的WorldPaper标签</div>';
                        if (dateSpan) dateSpan.innerText = '格式错误';
                        return;
                    }
                    const parsed = parseWorldPaper(worldMatch[1]);
                    if (dateSpan) dateSpan.innerText = '🕰️ ' + (parsed.eraSection.stage || '未知时代');
                    containerEl.innerHTML = `<div class="section-card"><div class="section-header" data-section="eraToggle"><span class="section-header-icon">👑</span><span class="section-header-text">时代快讯<span class="section-badge">ERA</span></span><span class="section-arrow" id="eraArrow">▼</span></div><div class="section-content" id="eraContent">${parsed.eraSection.mainHtml}${parsed.eraSection.potentialHtml}${parsed.eraSection.dynamicsHtml}${parsed.eraSection.chronicleHtml}</div></div><div class="section-card"><div class="section-header" data-section="econToggle"><span class="section-header-icon">💰</span><span class="section-header-text">世界经济简报<span class="section-badge">ECONOMY</span></span><span class="section-arrow" id="econArrow">▼</span></div><div class="section-content" id="econContent">${parsed.economySection.mainHtml||'<div style="color:var(--ink-light);">📉 本期无经济详报</div>'}</div></div>`;
                    setupSectionToggle('eraToggle', 'eraContent', 'eraArrow');
                    setupSectionToggle('econToggle', 'econContent', 'econArrow');
                    setupL3ToggleDelegation();
                } catch (e) {
                    console.error(e);
                    const containerEl = document.getElementById('dynamicContent');
                    if (containerEl) containerEl.innerHTML = '<div style="color:#e07060;">渲染出错，请检查控制台</div>';
                }
            }

            function setupSectionToggle(attr, contentId, arrowId) {
                const header = document.querySelector(`[data-section="${attr}"]`);
                const content = document.getElementById(contentId);
                const arrow = document.getElementById(arrowId);
                if (header && content && arrow) {
                    header.addEventListener('click', (e) => {
                        e.stopPropagation();
                        const isOpen = content.classList.contains('open');
                        content.classList.toggle('open');
                        arrow.style.transform = isOpen ? 'rotate(0deg)' : 'rotate(180deg)';
                    });
                }
            }

            const globalBody = document.getElementById('worldpaperBody');
            const globalHeader = document.getElementById('globalHeader');
            const globalArrow = document.getElementById('globalArrow');
            const globalHint = document.getElementById('globalHint');
            if (globalHeader && globalBody) {
                globalHeader.addEventListener('click', () => {
                    const isShow = globalBody.classList.contains('show');
                    if (isShow) {
                        globalBody.classList.remove('show');
                        globalArrow.style.transform = 'rotate(0deg)';
                        globalHint.innerText = '展开卷宗';
                    } else {
                        globalBody.classList.add('show');
                        globalArrow.style.transform = 'rotate(180deg)';
                        globalHint.innerText = '合上卷轴';
                        if (!document.getElementById('dynamicContent')?.querySelector('.section-card')) renderWorldPaper();
                    }
                });
            }
        })();
