.ql-card{background:var(--bg-card);border:1px solid var(--border);border-left:4px solid var(--ql-bar);border-radius:0 var(--r2) var(--r2) 0;padding:0;margin-bottom:10px;box-shadow:inset 0 2px 4px rgba(0,0,0,.12),0 2px 8px rgba(0,0,0,.2);overflow:hidden}
.ql-header{display:flex;align-items:center;gap:10px;padding:10px 12px 6px}
.ql-badge{display:inline-flex;align-items:center;font-size:.7em;font-weight:bold;padding:2px 10px;border-radius:10px;background:var(--ql-bg);color:var(--ql-bar);border:1px solid var(--ql-bar);letter-spacing:.05em;flex-shrink:0}
.ql-name{font-size:1.05em;font-weight:bold;color:var(--text-m);flex:1;min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
.ql-ring-wrap{position:relative;width:32px;height:32px;flex-shrink:0;display:flex;align-items:center;justify-content:center}
.ql-ring{width:32px;height:32px}.ql-ring-bg{opacity:.25}
.ql-ring-num{position:absolute;font-size:.55em;font-weight:bold;color:var(--text-m);top:50%;left:50%;transform:translate(-50%,-50%)}
.ql-summary{font-size:.82em;color:var(--text-s);font-style:italic;padding:0 12px 10px;margin-bottom:4px;border-bottom:1px dashed var(--border);opacity:.85}
.ql-steps{padding:2px 8px 8px 8px;display:flex;flex-direction:column;gap:2px}
.ql-empty{font-size:.82em;color:var(--text-s);opacity:.5;padding:8px 12px;text-align:center}
.ql-step{display:flex;align-items:flex-start;padding:5px 8px;border-radius:6px;transition:var(--t-fast);gap:10px}
.ql-step:hover{background:var(--bg-tag)}
.ql-step-dot{width:10px;height:10px;min-width:10px;border-radius:50%;margin-top:4px;background:var(--bg-card);border:2px solid var(--border);transition:all .25s}
.ql-step-txt{font-size:.9em;line-height:1.5;flex:1}
.ql-step.done .ql-step-dot{background:var(--c-ok);border-color:var(--c-ok);box-shadow:0 0 4px var(--c-ok)}
.ql-step.done .ql-step-txt{opacity:.35;text-decoration:line-through;text-decoration-color:currentColor}
.ql-step.active .ql-step-dot{background:var(--t-hi);border-color:var(--t-hi);box-shadow:0 0 0 0 var(--t-hi);animation:qlPulse 1.5s ease-out infinite}
.ql-step.active .ql-step-txt{font-weight:bold;color:var(--t-hi)}
.ql-step.pending .ql-step-dot{opacity:.4;border-color:var(--text-s)}
.ql-step.pending .ql-step-txt{color:var(--text-s)}
.ql-step.converge .ql-step-dot{background:var(--accent);border-color:var(--accent);opacity:1;box-shadow:0 0 4px 1px var(--accent);animation:qlBreathe 4s ease-in-out infinite}
.ql-step.converge .ql-step-txt{font-style:italic;color:var(--text-s)}
.ql-step.child{padding-left:30px}
.ql-step.child .ql-step-dot{width:7px;height:7px;min-width:7px;margin-top:6px;border-width:1.5px}
@keyframes qlPulse{0%{box-shadow:0 0 0 0 var(--accent)}70%{box-shadow:0 0 0 6px transparent}100%{box-shadow:0 0 0 0 transparent}}
@keyframes qlRingFill{from{stroke-dasharray:0 100}to{}}
@keyframes qlCardIn{from{opacity:0;transform:translateX(-24px)}to{opacity:1;transform:translateX(0)}}
@keyframes qlBreathe{0%{transform:scale(0.85);box-shadow:0 0 4px 1px var(--accent)}50%{transform:scale(1.1);box-shadow:0 0 10px 2px var(--accent)}100%{transform:scale(0.85);box-shadow:0 0 4px 1px var(--accent)}}
@keyframes qlRingFill{from{stroke-dasharray:0 100}to{}}
@keyframes qlEmptyIn{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:translateY(0)}}
.ql-empty-state{max-width:420px;margin:32px auto;padding:24px 20px;text-align:center;color:var(--text-s);line-height:1.85;animation:qlEmptyIn .6s ease-out both}.ql-empty-state .ql-empty-icon{display:block;font-size:2.4em;color:var(--accent);margin:0 auto 10px;line-height:1;opacity:.35;animation:qlEmptyIn .5s ease-out .05s both}.ql-empty-state h2{font-size:1.15em;font-weight:bold;color:var(--text-m);margin:0 0 12px;letter-spacing:.05em;animation:qlEmptyIn .55s ease-out .1s both}.ql-empty-state p{font-size:.88em;margin:0 0 16px;animation:qlEmptyIn .55s ease-out .15s both}.ql-empty-state p+p{animation-delay:.22s}.ql-empty-state p:last-child{margin-top:2px;margin-bottom:0;color:var(--accent);font-style:italic;animation-delay:.3s}@media (max-width:480px){.ql-empty-state .ql-empty-icon{font-size:1.8em;margin-bottom:8px}.ql-empty-state{padding:16px 14px}.ql-empty-state p{font-size:.84em;margin-bottom:10px}}
.qp-container{display:flex;flex-direction:column;gap:12px}
.qp-card{background:var(--bg-card);border:1px solid var(--border);border-left:4px solid var(--qp-bar);border-radius:0 var(--r2) var(--r2) 0;padding:0;margin-bottom:10px;box-shadow:inset 0 2px 4px rgba(0,0,0,.12),0 2px 8px rgba(0,0,0,.2);overflow:hidden}
.qp-empty{font-size:.85em;color:var(--text-s);opacity:.5;text-align:center;padding:20px}
.qp-empty-state{max-width:420px;margin:32px auto;padding:24px 20px;text-align:center;color:var(--text-s);line-height:1.85;animation:qlEmptyIn .6s ease-out both}.qp-empty-state .qp-empty-icon{display:block;font-size:2.4em;color:var(--accent);margin:0 auto 10px;line-height:1;opacity:.35;animation:qlEmptyIn .5s ease-out .05s both}.qp-empty-state h2{font-size:1.15em;font-weight:bold;color:var(--text-m);margin:0 0 12px;letter-spacing:.05em;animation:qlEmptyIn .55s ease-out .1s both}.qp-empty-state p{font-size:.88em;margin:0 0 16px;animation:qlEmptyIn .55s ease-out .15s both}.qp-empty-state p+p{animation-delay:.22s}.qp-empty-state p:last-child{margin-top:2px;margin-bottom:0;color:var(--accent);font-style:italic;animation-delay:.3s}@media (max-width:480px){.qp-empty-state .qp-empty-icon{font-size:1.8em;margin-bottom:8px}.qp-empty-state{padding:16px 14px}.qp-empty-state p{font-size:.84em;margin-bottom:10px}}
.qp-header{display:flex;align-items:center;gap:10px;padding:10px 12px 6px;flex-wrap:wrap}
.qp-badge{display:inline-flex;align-items:center;font-size:.7em;font-weight:bold;padding:2px 10px;border-radius:10px;background:var(--qp-bar);color:var(--bg-panel);border:1px solid var(--qp-bar);letter-spacing:.05em;flex-shrink:0}
.qp-name{font-size:1.05em;font-weight:bold;color:var(--text-m);flex:1;min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
