.qp-meta-pill.pace{color:var(--accent);border:1px solid var(--border)}
.qp-meta-pill.ext{color:#c8913a;border:1px solid rgba(200,145,58,.35)}
/* header inline thermo */.qp-temp-dot.t-lo{background:var(--t-lo)}
.qp-temp-dot.t-mi{background:var(--t-mi)}
.qp-temp-dot.t-hi{background:var(--t-hi)}
.qp-temp-dot.t-vh{background:var(--t-vh)}
/* thermo row */
.qp-thermo-row{display:flex;align-items:center;gap:6px;padding:2px 12px 6px}
.qp-thermo-gauge{flex:1;height:5px;background:var(--bg-tag);border-radius:3px;overflow:hidden}
.qp-thermo-fill{height:100%;border-radius:3px;transition:width .5s ease}
.qp-thermo-fill.t-lo{background:var(--t-lo)}
.qp-thermo-fill.t-mi{background:var(--t-mi)}
.qp-thermo-fill.t-hi{background:var(--t-hi)}
