.qp-thermo-val{font-size:.72em;font-weight:bold;white-space:nowrap;}.qp-thermo-val.t-lo{color:#5adb5e}.qp-thermo-val.t-mi{color:#b8c44a}.qp-thermo-val.t-hi{color:#e8a840}.qp-thermo-val.t-vh{color:#ff5c5c}
/* branch list */
.qp-ocard-list{margin:6px 12px 8px;display:flex;flex-direction:column;gap:6px}
.qp-ocard{padding:6px 10px;border:1px solid var(--border);border-radius:6px;font-size:.82em;background:var(--bg-card)}
.qp-ocard.primary{border:2px solid var(--accent);box-shadow:0 0 8px rgba(224,184,96,.12)}
.qp-ocard-head{display:flex;align-items:baseline;justify-content:space-between;gap:8px;margin-bottom:2px}
.qp-ocard-label{font-size:.55em;font-weight:bold;padding:1px 6px;border-radius:3px;letter-spacing:.06em;flex-shrink:0;color:var(--text-s);opacity:.5;border:1px solid var(--border);white-space:nowrap}
