.qp-ocard-cons{font-size:.8em;color:var(--text-s);opacity:.7;line-height:1.35}
.qp-ocard.primary .qp-ocard-cons{opacity:.9}
.qp-term{margin:2px 12px 8px;background:var(--bg-term);border:1px solid color-mix(in srgb,var(--term-color) 15%,transparent);font-family:inherit;overflow:hidden}
.qp-term-prompt{padding:6px 12px;font-size:.68em;color:color-mix(in srgb,var(--term-color) 60%,transparent);letter-spacing:.06em}
.qp-term-prompt::before{content:'';display:inline-block;width:6px;height:6px;background:color-mix(in srgb,var(--term-color) 40%,transparent);border-radius:50%;margin-right:8px;animation:termBlink 1.5s step-end infinite}
.qp-term-div{height:1px;background:color-mix(in srgb,var(--term-color) 10%,transparent);margin:0 12px}
.qp-term-body{padding:8px 12px}
.qp-term-row{margin-bottom:6px}
.qp-term-row:last-child{margin-bottom:0}
.qp-term-label{font-size:.6em;font-weight:bold;color:color-mix(in srgb,var(--term-color) 45%,transparent);letter-spacing:.1em;display:block;margin-bottom:2px}
.qp-term-val{font-size:.82em;color:var(--text-m);line-height:1.5;display:block}
.qp-term-actions{display:flex;gap:0;padding:6px 12px}
.qp-term-actions span{font-size:.55em;color:color-mix(in srgb,var(--term-color) 25%,transparent);padding:2px 8px;border:1px solid color-mix(in srgb,var(--term-color) 10%,transparent);margin-right:4px;letter-spacing:.05em}
@keyframes termBlink{0%,100%{opacity:1}50%{opacity:.2}}
.qp-spoiler{margin:0 12px 10px;border:1px dashed var(--c-warn);background:var(--bg-dossier);overflow:hidden}
.qp-spoiler-btn{cursor:pointer;padding:8px 12px;font-size:.72em;font-weight:bold;color:var(--c-warn);background:rgba(255,92,92,.1);text-align:center;transition:background .25s,color .25s;user-select:none;letter-spacing:.08em;border-bottom:1px solid rgba(255,92,92,.15)}
.qp-spoiler-btn:hover{background:rgba(255,92,92,.25)}
.qp-spoiler-body{display:none;padding:8px}
.qp-zone{margin-bottom:8px}
.qp-zone:last-child{margin-bottom:0}
.qp-zone-head{font-size:.75em;font-weight:bold;padding:3px 10px;border-radius:6px;display:inline-block;margin-bottom:4px;background:var(--bg-tag);color:var(--text-s)}
.qp-zone-head.active{background:var(--accent);color:var(--bg-panel)}
.qp-zone-beats{display:flex;flex-direction:column;gap:2px}
.qp-beat{display:flex;align-items:center;gap:8px;padding:5px 8px;border-radius:6px;transition:var(--t-fast);font-size:.85em}
.qp-beat:hover{background:var(--bg-tag)}
.qp-beat-num{width:22px;height:22px;min-width:22px;border-radius:50%;background:var(--bg-tag);display:flex;align-items:center;justify-content:center;font-size:.75em;font-weight:bold;color:var(--text-s)}
.qp-beat-tbar{width:3px;height:14px;border-radius:2px;flex-shrink:0}
.qp-beat-tbar.t-lo{background:var(--t-lo)}
.qp-beat-tbar.t-mi{background:var(--t-mi)}
.qp-beat-tbar.t-hi{background:var(--t-hi)}
.qp-beat-tbar.t-vh{background:var(--t-vh)}
.qp-beat-event{flex:1;color:var(--text-m);line-height:1.4;min-width:0}
.qp-beat-info{font-size:.75em;background:var(--bg-tag);padding:1px 6px;border-radius:4px;color:var(--text-s);white-space:nowrap}
.qp-beat-span{font-size:.75em;color:var(--text-s);white-space:nowrap;display:flex;align-items:center;gap:2px}
.qp-beat-span i{font-style:normal;opacity:.5}

