                   return res.replace(/\\n/g, '\n').replace(/\\"/g, '"');
               };

               let valB = m.qrf_plot_tasks ? unescapeTasks(m.qrf_plot_tasks) : null;

               let valA = m.qrf_plot;
               if (!valA && m.extra?.qrf_plot) valA = m.extra.qrf_plot;
               if (!valA && m.swipes && Array.isArray(m.swipes)) {
                   const sid = m.swipe_id ?? (m.swipes.length - 1);
                   if (m.swipes[sid]?.extra?.qrf_plot) valA = m.swipes[sid].extra.qrf_plot;
               }
               if (valA && typeof valA !== 'string') valA = JSON.stringify(valA, null, 2);

               if (target === 'A') return valA || null;
               if (target === 'B') return valB || null;
               // target === 'C' (优先B,其次A)
               return valB || valA || null;
           };

           const mode = localStorage.getItem('st_scenario_fetch_mode_v1') || 'basic';
           let startIdx = typeof specificIdx === 'number' ? specificIdx : chat.length - 1;

           if (mode === 'basic') {
               startIdx = chat.length - 1; // 强制从最新层开始找
           } else if (mode === 'fallback' && typeof specificIdx === 'number') {
               startIdx = specificIdx - 1; // 跳过当前层,从上一层开始向回找
           }

          if (mode === 'precise') {
               if (startIdx >= 0 && chat[startIdx]) {
                   const p = getPlot(chat[startIdx]);
                   if (p) { window.lastFetchedIdx = startIdx; return p; }
               }
               window.lastFetchedIdx = -1;
               return "";
           }

           for(let i = startIdx; i >= 0; i--) {
               const p = getPlot(chat[i]);
               if (p) { window.lastFetchedIdx = i; return p; }
           }
       } catch (e) { console.error("History Extract Error:", e); }
       window.lastFetchedIdx = -1;
       return "";
   }

