           window.srSearch = () => {
               const chat = window.SillyTavern?.chat || (typeof getContext==='function'?getContext()?.chat:[]);
               const myContent = $('time-capsule').value.split('--- START OF FILE')[0].trim();
               let targetIdx = chat.length - 1;
               for (let i = chat.length - 1; i >= 0; i--) {
                   if (chat[i].mes && chat[i].mes.includes(myContent)) { targetIdx = i; break; }
               }
               const msg = chat[targetIdx];
               if (!msg) return;

               const searchWord = $('srSearchInput').value;
               if (!searchWord) {
                   $('srResultHint').innerText = "请输入要搜索的词语。";
                   return;
               }

               let count = 0;
               const regex = new RegExp(searchWord.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g');

               let mesText = msg.mes;
               const sid = msg.swipes ? (msg.swipe_id ?? (msg.swipes.length - 1)) : null;
               if (sid !== null && msg.swipes[sid]) {
                   mesText = msg.swipes[sid].mes;
               }
               const mesMatches = mesText ? (mesText.match(regex) || []) :[];

               let plotText = msg.qrf_plot || "";
               const plotMatches = plotText ? (plotText.match(regex) || []) :[];

               count = mesMatches.length + plotMatches.length;

               $('srResultHint').innerText = `找到 ${count} 处匹配 (原始文本 ${mesMatches.length} 处, &#36;6文本 ${plotMatches.length} 处)。`;
               window.srLastSearch = { word: searchWord, count: count, targetIdx: targetIdx, sid: sid };
           };

           window.srReplace = async () => {
               if (!window.srLastSearch || window.srLastSearch.count === 0) {
                   alert("请先进行有效搜索!");
                   return;
               }
               const replaceWord = $('srReplaceInput').value;
               const searchWord = window.srLastSearch.word;
               const targetIdx = window.srLastSearch.targetIdx;
               const sid = window.srLastSearch.sid;

               if (!confirm(`确定将楼层 ${targetIdx} 中的 "${searchWord}" 替换为 "${replaceWord}" 吗?(共 ${window.srLastSearch.count} 处)`)) return;

               const chat = window.SillyTavern?.chat || (typeof getContext==='function'?getContext()?.chat:[]);
               const msg = chat[targetIdx];
               if (!msg) return;

               const regex = new RegExp(searchWord.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g');

               // 同步修改正文与分支文本
               if (sid !== null && msg.swipes[sid]) {
                   if (msg.swipes[sid].mes) msg.swipes[sid].mes = msg.swipes[sid].mes.replace(regex, replaceWord);
                   if (msg.mes) msg.mes = msg.mes.replace(regex, replaceWord);
               } else {
                   if (msg.mes) msg.mes = msg.mes.replace(regex, replaceWord);
               }

               // 修改 $6 文本
               if (msg.qrf_plot) {
                   msg.qrf_plot = msg.qrf_plot.replace(regex, replaceWord);
               }

               if (typeof SillyTavern?.saveChat === 'function') await SillyTavern.saveChat();
               else if (typeof saveChat === 'function') await saveChat();

               alert("替换完成!\n※ 为确保正文显示同步更新,可能需要手动重载楼层。");
               $('srSearchInput').value = '';
               $('srReplaceInput').value = '';
               $('srResultHint').innerText = "等待搜索...";
               window.srLastSearch = null;
               render(); // 重新渲染面板
           };

