   async function render() {
       const chat = window.SillyTavern?.chat || (typeof getContext==='function'?getContext()?.chat:[]);
       let targetIdx = chat.length - 1;
       const myContent = capsule.value.split('--- START OF FILE')[0].trim();
       for (let i = chat.length - 1; i >= 0; i--) {
           if (chat[i].mes && chat[i].mes.includes(myContent)) { targetIdx = i; break; }
       }

       // 动态获取当前楼层最新的原始文本(支持分支切换和外部实时修改刷新)
       let liveMesText = capsule.value;
       if (targetIdx >= 0 && chat[targetIdx]) {
           const msg = chat[targetIdx];
           liveMesText = msg.mes;
           if (msg.swipes && Array.isArray(msg.swipes)) {
               const sid = msg.swipe_id ?? (msg.swipes.length - 1);
               if (msg.swipes[sid] && msg.swipes[sid].mes) liveMesText = msg.swipes[sid].mes;
           }
       }

   try {
       // --- 10.1 数据加载 ---
       const menuBar = document.querySelector('#render-target .tabs-bar'), amBar = document.querySelector('#render-target .tag-list.scroll-mode');
       const lastMenuX = menuBar ? menuBar.scrollLeft : 0, lastAmX = amBar ? amBar.scrollLeft : 0;

       const unfilteredRaw = liveMesText;
       const unfilteredSix = await fetchContext(targetIdx);
       // 过滤旧格式标签(thought / dm_set / dm_plan 来自旧版 prompt,新 prompt 已不产出,保留兼容 $6 历史数据)
       const filterBlacklist = (text) => text ? text.replace(/<(?:thought|dm_set|dm_plan)>[\s\S]*?(?:<\/(?:thought|dm_set|dm_plan)>|$)/gi, '') : text;
       let raw = filterBlacklist(unfilteredRaw);
       window.lastFullCtx = filterBlacklist(unfilteredSix);

       const btnRaw = $('btn-view-raw'); btnRaw.classList.remove('flash-red');
