                   }

                   var summaryHTML = summary ? '<div class="ql-summary">' + summary + '</div>' : '';

                   return '<div class="ql-card" style="--ql-bar:' + tc.bar + ';--ql-bg:' + tc.bg + ';animation:qlCardIn .4s ease-out ' + (cardIdx * 0.08) + 's both">' +
                       '<div class="ql-header"><span class="ql-badge">' + type + '</span><span class="ql-name">' + name + '</span>' + ringHTML + '</div>' +
                       summaryHTML +
                       '<div class="ql-steps">' + (stepsHTML || '<div class="ql-empty">暂无步骤</div>') + '</div>' +
                       '</div>';
               }).filter(function(c){return c;}).join('');

               return cards || null;
           }
           const questLogResult = renderQuestLog(raw);
           const questLogHtml = questLogResult === '__EMPTY__' ? '<div class="ql-empty-state"><span class="ql-empty-icon">✧</span><h2>暂无待行之约</h2><p>远山的轮廓在暮色里渐渐隐去，某个无名隘口的岗哨上，守夜人正拨亮灯火。世界不曾停驻，它只是在你视线之外，独自呼吸、移动、准备着下一幕的登场。</p><p>旧歌谣尚未唱完，因为你还没有踏上那条路。而当晨钟敲响，风会带来方向——也许是一封盖着陌生纹章的信，也许只是某个旅人推门而入时，夹在斗篷间的一声闷雷。</p><p>夜色仍长，炉火未熄。</p></div>' : questLogResult;

           // --- 10.3 任务大纲渲染 ---
           function renderQuestPlan(content) {
               if (!content) return '__EMPTY__';
