                   if (paceMatch) { paceDesc = paceMatch[1]; taskName = taskName.replace(paceMatch[0], ''); }
                   var tempSeq = '';
                   const tempMatch = rest.match(/温度序列[：:]\s*\[([^\]]+)\]/);
                   if (tempMatch) tempSeq = tempMatch[1].trim();
                   var extended = '';
                   const extMatch = rest.match(/生命周期[：:]\s*(.+?)(?=\s*[|¦]|\s*$)/);
                   if (extMatch) { extended = extMatch[1].trim(); taskName = taskName.replace(extMatch[0], ''); }
                   taskName = taskName.replace(/[|\uff5c¦]/g, '').replace(/温度序列[：:]\s*\[[^\]]*\]/, '').replace(/生命周期[：:]\s*\S+/, '').trim();

                   var activeBranch = '';
                   const activeMatch = block.match(/当前激活分支[：:]\s*([^\n]+)/i);
                   if (activeMatch) activeBranch = activeMatch[1].trim();

                   var branchHtml = '';
                   const branchSection = block.match(/分支预案[：:]\s*([\s\S]*?)(?=\n当前激活分支|\n关键NPC|\n节拍规划|$)/i);
                   if (branchSection) {
                       const branchLines = branchSection[1].split(/\r?\n/).filter(l => l.trim().startsWith('-'));
                       if (branchLines.length) {
                           var items = branchLines.map((line, i) => {
                               var letters = ['A','B','C','D','E'];
                               var raw = line.replace(/^\s*-\s*/, '').trim();
                               var branchName = raw.match(/^(.+?)[：:]/); branchName = branchName ? branchName[1].trim() : '';
                               var consIdx = raw.search(/后果[：:]/);
                               var dirText, consText;
                               if (consIdx > 0) {
                                   dirText = raw.substring(0, consIdx).trim();
