        .hgw-servant-class-prefix.hgw-class-saber, .hgw-card.hgw-class-saber .hgw-servant-class-en { color: #4A90E2; }
        .hgw-servant-class-prefix.hgw-class-archer, .hgw-card.hgw-class-archer .hgw-servant-class-en { color: #5FA83F; }
        .hgw-servant-class-prefix.hgw-class-lancer, .hgw-card.hgw-class-lancer .hgw-servant-class-en { color: #3B5EA5; }
        .hgw-servant-class-prefix.hgw-class-rider, .hgw-card.hgw-class-rider .hgw-servant-class-en { color: #DAA520; }
        .hgw-servant-class-prefix.hgw-class-caster, .hgw-card.hgw-class-caster .hgw-servant-class-en { color: #9B59B6; }
        .hgw-servant-class-prefix.hgw-class-assassin, .hgw-card.hgw-class-assassin .hgw-servant-class-en { color: #8E2323; }
        .hgw-servant-class-prefix.hgw-class-berserker, .hgw-card.hgw-class-berserker .hgw-servant-class-en { color: #C0392B; }
        .hgw-servant-class-prefix.hgw-class-ruler, .hgw-card.hgw-class-ruler .hgw-servant-class-en { color: #E0C068; }
        .hgw-servant-class-prefix.hgw-class-avenger, .hgw-card.hgw-class-avenger .hgw-servant-class-en { color: #6B0F0F; }
        .hgw-servant-class-prefix.hgw-class-alterego, .hgw-card.hgw-class-alterego .hgw-servant-class-en { color: #E84393; }
        .hgw-servant-class-prefix.hgw-class-mooncancer, .hgw-card.hgw-class-mooncancer .hgw-servant-class-en { color: #E67E22; }
        .hgw-servant-class-prefix.hgw-class-foreigner, .hgw-card.hgw-class-foreigner .hgw-servant-class-en { color: #16A085; }
        .hgw-servant-class-prefix.hgw-class-pretender, .hgw-card.hgw-class-pretender .hgw-servant-class-en { color: #8E44AD; }
        .hgw-servant-class-prefix.hgw-class-shielder, .hgw-card.hgw-class-shielder .hgw-servant-class-en { color: #85C1E9; }
        .hgw-servant-class-prefix.hgw-class-beast, .hgw-card.hgw-class-beast .hgw-servant-class-en { color: #AA0000; }
        .hgw-servant-class-prefix.hgw-class-watcher, .hgw-card.hgw-class-watcher .hgw-servant-class-en { color: #95A5A6; }
        .hgw-servant-class-prefix.hgw-class-gatekeeper, .hgw-card.hgw-class-gatekeeper .hgw-servant-class-en { color: #6C3483; }
        .hgw-servant-class-prefix.hgw-class-faker, .hgw-card.hgw-class-faker .hgw-servant-class-en { color: #5D6D7E; }
        .hgw-servant-class-prefix.hgw-class-funnyvamp, .hgw-card.hgw-class-funnyvamp .hgw-servant-class-en { color: #F78DA7; }
        .hgw-servant-class-prefix.hgw-class-gunner, .hgw-card.hgw-class-gunner .hgw-servant-class-en { color: #D4AC0D; }
        .hgw-servant-class-prefix.hgw-class-saver, .hgw-card.hgw-class-saver .hgw-servant-class-en { color: #F4D03F; }

        /* 冠位特效同样拆分，英文部分继承冠位渐变和动画 */
        .hgw-servant-class-en.hgw-grand {
            background: linear-gradient(135deg, #F9E0A0 0%, #F5D76E 30%, #E6B800 70%, #DAA520 100%);
            -webkit-background-clip: text;
            background-clip: text;
            color: transparent !important;
            font-weight: 900;
            animation: grandPulse 2.8s ease-in-out infinite;
        }
        .hgw-servant-class-en.hgw-grand::after {
            content: " ✦";
            font-size: 11px;
            background: inherit;
            -webkit-background-clip: text;
            background-clip: text;
            color: transparent;
            display: inline-block;
            margin-left: 4px;
        }

        @keyframes grandPulse {
            0%, 100% { text-shadow: 0 0 6px currentColor; opacity: 1; }
            50% { text-shadow: 0 0 14px currentColor, 0 0 20px rgba(255,215,0,0.5); opacity: 0.95; }
        }

        .hgw-servant-state {
            font-size: 11px;
            font-weight: 600;
            letter-spacing: 1px;
            text-transform: uppercase;
            margin-top: 2px;
            text-shadow: 0 0 4px currentColor;
            color: var(--gold-dim);
        }
        .hgw-servant-state.state-healthy { color: #5ac08a; }
        .hgw-servant-state.state-injured { color: #f0a04b; }
        .hgw-servant-state.state-uncontracted { color: #c77dff; }
        .hgw-servant-state.state-destroyed { color: #e04040; text-shadow: 0 0 6px rgba(190,30,40,0.5); }
        .hgw-servant-state.state-unknown { color: #95a5a6; font-style: italic; }

        .hgw-divider-top {
            position: relative;
            z-index: 2;
            height: 1px;
            background: linear-gradient(90deg, transparent, rgba(180,140,50,0.3) 20%, rgba(210,160,50,0.4) 50%, rgba(180,140,50,0.3) 80%, transparent);
        }
        .hgw-divider-top::after {
            content: '✦';
            position: absolute;
            top: 50%; left: 50%;
            transform: translate(-50%, -50%);
            font-size: 12px;
            color: rgba(200,150,50,0.4);
            background: var(--card-bg);
            padding: 0 10px;
        }

        .hgw-footer {
            padding: 8px 18px;
            display: flex;
            align-items: center;
            justify-content: center;
            gap: 10px;
            position: relative;
        }
        .hgw-footer::before {
            content: '';
            position: absolute;
            top: 0; left: 12%; right: 12%;
            height: 1px;
            background: linear-gradient(90deg, transparent, rgba(180,140,50,0.2), transparent);
        }
        .hgw-footer-text {
            font-family: 'Cinzel', serif;
            font-size: 8px;
            color: rgba(170,130,60,0.35);
            letter-spacing: 3px;
            text-transform: uppercase;
        }
        .hgw-footer-ornament {
            font-size: 10px;
            color: rgba(180,140,50,0.35);
        }

        @keyframes hgw-sigil-glow {
            0%, 100% { opacity: 0.9; text-shadow: 0 0 20px rgba(255, 200, 0, 0.9), 0 0 40px rgba(255, 180, 0, 0.6); }
            50% { opacity: 1; text-shadow: 0 0 30px rgba(255, 215, 0, 1), 0 0 60px rgba(255, 200, 0, 0.9); }
        }
        @keyframes hgw-rune-drift {
            0%, 100% { transform: translateY(0) rotate(0deg); opacity: 0.14; }
            25% { transform: translateY(-6px) rotate(8deg); opacity: 0.24; }
            50% { transform: translateY(-2px) rotate(-6deg); opacity: 0.09; }
            75% { transform: translateY(-9px) rotate(6deg); opacity: 0.2; }
        }
    </style>
</head>
<body>
    <div class="hgw-container">
        <div class="hgw-corner hgw-corner-tl"></div>
        <div class="hgw-corner hgw-corner-tr"></div>
        <div class="hgw-corner hgw-corner-bl"></div>
        <div class="hgw-corner hgw-corner-br"></div>
        <span class="hgw-rune-float">✧</span>
        <span class="hgw-rune-float">✦</span>
        <span class="hgw-rune-float">⁂</span>
        <span class="hgw-rune-float">✧</span>

        <div class="hgw-header" id="hgw-hdr">
            <div class="hgw-header-left">
                <div class="hgw-sigil">🏆</div>
                <div class="hgw-title-group">
                    <span class="hgw-title-main">Holy Grail War</span>
                    <span class="hgw-title-sub">◆ 圣杯战争 ◆</span>
                </div>
            </div>
            <div class="hgw-header-right">
                <span class="hgw-badge">GRAIL</span>
                <span class="hgw-toggle-hint" id="hgw-hint">解封令咒</span>
                <span class="hgw-arrow" id="hgw-arw">⏷</span>
            </div>
        </div>

        <div class="hgw-divider-top" id="hgw-div" style="display:none;"></div>

        <div class="hgw-content" id="hgw-body">
            <div class="hgw-content-inner" id="hgw-inner">
                <div class="hgw-pre-war">⏳ 圣杯战争正在集结...</div>
            </div>
            <div class="hgw-footer">
                <span class="hgw-footer-ornament">✦</span>
                <span class="hgw-footer-text">Finis Coronae Opus</span>
                <span class="hgw-footer-ornament">✦</span>
            </div>
        </div>
    </div>

    <script>
        (function(){
            var CLASS_MAP = {
                'saber':       '剑之骑士 🗡️ Saber',
                'archer':      '弓之骑士 🏹 Archer',
                'lancer':      '枪之骑士 🛡️ Lancer',
                'rider':       '骑乘兵 🐴 Rider',
                'caster':      '魔术师 ✨ Caster',
                'assassin':    '暗杀者 🗡️ Assassin',
                'berserker':   '狂战士 💢 Berserker',
                'ruler':       '裁定者 ⚖️ Ruler',
                'avenger':     '复仇者 🔥 Avenger',
                'saver':          '救世主 👼 Saver',
                'watcher':        '观测者 👁️ Watcher',
                'gatekeeper':     '门之看守者 🚪 Gatekeeper',
                'faker':          '影武者 🎭 Faker',
                'funnyvamp':      '搞笑吸血鬼 🧛 Funny Vamp',
                'alterego':    '他我者 🎭 Alter Ego',
                'mooncancer':  '月之癌 🌕 Moon Cancer',
                'foreigner':   '降临者 🛸 Foreigner',
                'pretender':   '伪装者 🎭 Pretender',
                'shielder':    '盾之英灵 🛡️ Shielder',
                'gunner':      '射手 🔫 Gunner',
                'beast':       '灾厄之兽 🐲 Beast',
                'grandcaster': '冠位魔术师 ✨ Grand Caster',
                'grandruler':  '冠位裁定者 ⚖️ Grand Ruler',
                'grandsaber':     '冠位剑士 🗡️ Grand Saber',
                'grandarcher':    '冠位弓兵 🏹 Grand Archer',
                'grandlancer':    '冠位枪兵 🛡️ Grand Lancer',
                'grandrider':     '冠位骑兵 🐴 Grand Rider',
                'grandassassin':  '冠位暗杀者 🗡️ Grand Assassin',
                'grandberserker': '冠位狂战士 💢 Grand Berserker',
            };

            function normalizeEnglishCapitalization(str) {
                if (!str) return str;
                return str.replace(/\b[A-Z]{2,}(?:\s+[A-Z]{2,})*\b/g, function(match) {
                    return match.split(/\s+/).map(function(word) {
                        if (word === word.toUpperCase() && /[A-Z]/.test(word)) {
                            return word.charAt(0).toUpperCase() + word.slice(1).toLowerCase();
                        }
                        return word;
                    }).join(' ');
                });
            }

            function beautifyClass(raw) {
                if (!raw) return '—';
                var normalized = raw.trim().replace(/\s+/g, '').toLowerCase();
                var mapped = CLASS_MAP[normalized] || raw.trim();
                return normalizeEnglishCapitalization(mapped);
            }

            // 拆分职阶字符串为前缀（中文+emoji）和英文部分
            function splitClassString(fullClass) {
                // 匹配尾部英文（可能包含空格，如 "Grand Saber"）
                var match = fullClass.match(/([A-Z][a-z]*(?:\s+[A-Z][a-z]*)*)$/);
                if (match) {
                    var english = match[0];
                    var prefix = fullClass.substring(0, fullClass.length - english.length);
                    return { prefix: prefix, english: english };
                }
                return { prefix: fullClass, english: '' };
            }

            function triggerGrailBurst(originEl) {
                var rect = originEl.getBoundingClientRect();
                var cx = rect.left + rect.width / 2;
                var cy = rect.top + rect.height;
                var layer = document.createElement('div');
                layer.style.cssText = 'position:fixed;top:0;left:0;width:100vw;height:100vh;pointer-events:none;z-index:99999;overflow:hidden;';
                document.body.appendChild(layer);
                var i, el, angle, dist, dx, dy, size, delay;
                var runeChars = ['✦','✧','⁂','◆','◈','❖','✶','✢','✣','✤'];

                for (i = 0; i < 25; i++) {
                    el = document.createElement('div');
                    angle = (Math.PI * 2 / 25) * i + (Math.random() - 0.5) * 0.4;
                    dist = 50 + Math.random() * 180;
                    dx = Math.cos(angle) * dist;
                    dy = Math.sin(angle) * dist - 30;
                    size = 3 + Math.random() * 5;
                    delay = Math.random() * 180;
                    var hue = 35 + Math.random() * 20;
                    el.style.cssText = 'position:absolute;border-radius:50%;pointer-events:none;width:'+size+'px;height:'+size+'px;left:'+cx+'px;top:'+cy+'px;background:radial-gradient(circle,hsla('+hue+',80%,70%,0.9),hsla('+hue+',70%,50%,0.5),transparent);box-shadow:0 0 '+(3+Math.random()*5)+'px hsla('+hue+',75%,60%,0.6);opacity:0;transform:translate(-50%,-50%) scale(0);transition:none;';
                    layer.appendChild(el);
                    (function(e,ddx,ddy,d){setTimeout(function(){e.style.transition='all 0.7s cubic-bezier(0.22,0.85,0.32,1)';e.style.transform='translate(calc(-50% + '+ddx+'px),calc(-50% + '+ddy+'px)) scale(1)';e.style.opacity='0.85';setTimeout(function(){e.style.transition='opacity 1s ease,transform 1s ease';e.style.opacity='0';e.style.transform='translate(calc(-50% + '+(ddx*1.3)+'px),calc(-50% + '+(ddy*1.3-15)+'px)) scale(0.3)';},500);},d);})(el,dx,dy,delay);
                }

                for (i = 0; i < 6; i++) {
                    el = document.createElement('div');
                    angle = (Math.PI * 2 / 6) * i + (Math.random() - 0.5) * 0.6;
                    dist = 60 + Math.random() * 130;
                    dx = Math.cos(angle) * dist;
                    dy = Math.sin(angle) * dist - 25;
                    delay = 70 + Math.random() * 200;
                    var rot = (Math.random()-0.5)*50;
                    el.style.cssText = 'position:absolute;pointer-events:none;left:'+cx+'px;top:'+cy+'px;font-size:'+(14+Math.random()*10)+'px;color:rgba(220,170,50,0.85);text-shadow:0 0 10px rgba(200,150,40,0.6),0 0 20px rgba(180,130,30,0.3);opacity:0;transform:translate(-50%,-50%) scale(0) rotate('+rot+'deg);font-family:serif;transition:none;';
                    el.textContent = runeChars[Math.floor(Math.random()*runeChars.length)];
                    layer.appendChild(el);
                    (function(e,ddx,ddy,d,r){setTimeout(function(){e.style.transition='all 0.8s cubic-bezier(0.18,0.89,0.32,1.1)';e.style.transform='translate(calc(-50% + '+ddx+'px),calc(-50% + '+ddy+'px)) scale(1) rotate('+(r+20)+'deg)';e.style.opacity='0.8';setTimeout(function(){e.style.transition='opacity 1.2s ease,transform 1.2s ease';e.style.opacity='0';e.style.transform='translate(calc(-50% + '+ddx+'px),calc(-50% + '+(ddy-30)+'px)) scale(0.5) rotate('+(r+40)+'deg)';},600);},d);})(el,dx,dy,delay,rot);
                }

                setTimeout(function(){ if(layer.parentNode) layer.parentNode.removeChild(layer); }, 3500);
            }

            function parseGrailData(rawText) {
                var match = rawText.match(/<圣杯战争>([\s\S]*?)<\/圣杯战争>/);
                if (!match) return null;
                var inner = match[1].trim();
                if (inner === '圣杯战争未开始' || inner.indexOf('圣杯战争未开始') !== -1) {
                    return { preWar: true };
                }
                var lines = inner.split(/\r?\n/).filter(function(l) { return l.trim() !== ''; });
                var masters = [];
                var newFormatRegex = /^(?:\[([^\]]+)\]|([^:]+)):\s*([^|]*?)\s*\|\s*令咒:\s*(\d+)\s*\|\s*从者:\s*([^(]+)\(([^)]+)\)\s*\|\s*([^|]*?)\s*$/;
                var oldFormatRegex = /^(?:\[([^\]]+)\]|([^:]+)):\s*([^|]*?)\s*\|\s*从者:\s*([^(]+)\(([^)]+)\)\s*\|\s*([^|]*?)\s*$/;

                for (var i = 0; i < lines.length; i++) {
                    var line = lines[i];
                    if (!line.trim()) continue;
                    var data = {
                        index: i+1,
                        masterName: '—',
                        masterStatus: '—',
                        commandSpells: '?',
                        servantName: '—',
                        servantClass: '—',
                        servantClassRaw: '',
                        servantStatus: '—'
                    };
                    var m = line.match(newFormatRegex);
                    if (m) {
                        data.masterName = (m[1] || m[2]).trim();
                        data.masterStatus = (m[3] || '').trim();
                        data.commandSpells = parseInt(m[4], 10);
                        data.servantName = m[5].trim();
                        var rawClass = m[6].trim();
                        data.servantClass = beautifyClass(rawClass);
                        data.servantClassRaw = rawClass.replace(/\s+/g, '').toLowerCase();
                        data.servantStatus = (m[7] || '').trim();
                        masters.push(data);
                    } else {
                        var old = line.match(oldFormatRegex);
                        if (old) {
                            data.masterName = (old[1] || old[2]).trim();
                            data.masterStatus = (old[3] || '').trim();
                            data.commandSpells = '?';
                            data.servantName = old[4].trim();
                            var oldRawClass = old[5].trim();
                            data.servantClass = beautifyClass(oldRawClass);
                            data.servantClassRaw = oldRawClass.replace(/\s+/g, '').toLowerCase();
                            data.servantStatus = (old[6] || '').trim();
                            masters.push(data);
                        }
                    }
                }
                return { preWar: false, masters: masters };
            }

            function renderCommandSpells(spells) {
                if (spells === '?' || spells === null || spells === undefined) {
                    return '<div class="hgw-command-count zero"><span>⚜</span> 令咒 ??</div>';
                }
                var num = parseInt(spells, 10);
                if (isNaN(num)) return '<div class="hgw-command-count zero"><span>⚜</span> 令咒 ??</div>';
                var lowClass = (num === 0) ? 'zero' : (num <= 1 ? 'low' : '');
                var starMark = '';
                for (var i = 0; i < num; i++) starMark += '✦';
                if (num === 0) starMark = '✘';
                return '<div class="hgw-command-count ' + lowClass + '"><span>⚜</span> 令咒 ' + num + ' · <span class="hgw-command-stars">' + starMark + '</span></div>';
            }

            function buildCard(data) {
                var masterStatusClass = 'alive';
                var masterStatusText = data.masterStatus;
                if (data.masterStatus.indexOf('死亡') !== -1) { masterStatusClass = 'dead'; masterStatusText = 'DEAD'; }
                else if (data.masterStatus.indexOf('退场') !== -1) { masterStatusClass = 'withdrawn'; masterStatusText = 'WITHDRAWN'; }
                else if (data.masterStatus.indexOf('存活') !== -1) { masterStatusClass = 'alive'; masterStatusText = 'ALIVE'; }

                var commandHtml = renderCommandSpells(data.commandSpells);

                var classExtra = '';
                var raw = data.servantClassRaw;
                if (raw) {
                    if (raw.startsWith('grand')) {
                        var base = raw.substring(5);
                        classExtra = ' hgw-class-' + base + ' hgw-grand';
                    } else {
                        classExtra = ' hgw-class-' + raw;
                    }
                }

                // 拆分职阶显示
                var classParts = splitClassString(data.servantClass);
                var prefixHtml = '<span class="hgw-servant-class-prefix' + classExtra + '">' + escapeHtml(classParts.prefix) + '</span>';
                var englishHtml = '<span class="hgw-servant-class-en' + (raw && raw.startsWith('grand') ? ' hgw-grand' : '') + '">' + escapeHtml(classParts.english) + '</span>';
                var classHtml = prefixHtml + englishHtml;

                var servantStateClass = '';
                var servantStateText = data.servantStatus;
                if (servantStateText.indexOf('健在') !== -1) servantStateClass = 'state-healthy';
                else if (servantStateText.indexOf('重伤') !== -1) servantStateClass = 'state-injured';
                else if (servantStateText.indexOf('契约外') !== -1) servantStateClass = 'state-uncontracted';
                else if (servantStateText.indexOf('消灭') !== -1) servantStateClass = 'state-destroyed';
                else if (servantStateText.indexOf('不明') !== -1) servantStateClass = 'state-unknown';

                return '<div class="hgw-card ' + classExtra + '">' +
                    '<div class="hgw-card-status-marker ' + masterStatusClass + '"></div>' +
                    '<div class="hgw-command-seal">' + (masterStatusClass === 'dead' ? '✟' : '⚜') + '</div>' +
                    '<div class="hgw-master-info">' +
                        '<div class="hgw-master-name">' + escapeHtml(data.masterName) + '</div>' +
                        '<div class="hgw-master-status-text">' + masterStatusText + '</div>' +
                        commandHtml +
                    '</div>' +
                    '<div class="hgw-servant-info">' +
                        '<div class="hgw-servant-class-wrapper">' + classHtml + '</div>' +
                        '<div class="hgw-servant-name">' + escapeHtml(data.servantName) + '</div>' +
                        '<div class="hgw-servant-state ' + servantStateClass + '">' + escapeHtml(servantStateText) + '</div>' +
                    '</div>' +
                '</div>';
            }

            function escapeHtml(str) {
                return String(str).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
            }

            function loadContent() {
                try {
                    var chatMessages = getChatMessages(getCurrentMessageId());
                    if (!chatMessages || chatMessages.length === 0) return;
                    var text = chatMessages[0].message;
                    var data = parseGrailData(text);
                    var inner = document.getElementById('hgw-inner');
                    if (!inner) return;
                    if (!data) {
                        inner.innerHTML = '<div class="hgw-pre-war">⏳ 圣杯战争数据解析失败</div>';
                        return;
                    }
                    if (data.preWar) {
                        inner.innerHTML = '<div class="hgw-pre-war">◆ 圣杯战争尚未开始 ◆</div>';
                    } else {
                        if (data.masters && data.masters.length > 0) {
                            var html = '<div class="hgw-roster">';
                            for (var i = 0; i < data.masters.length; i++) {
                                html += buildCard(data.masters[i]);
                            }
                            html += '</div>';
                            inner.innerHTML = html;
                        } else {
                            inner.innerHTML = '<div class="hgw-pre-war" style="font-size:13px;">✧ 无圣杯战争数据 ✧</div>';
                        }
                    }
                } catch (e) {
                    console.error('圣杯战争面板加载失败:', e);
                }
            }

            var hdr  = document.getElementById('hgw-hdr');
            var body = document.getElementById('hgw-body');
            var arw  = document.getElementById('hgw-arw');
            var hint = document.getElementById('hgw-hint');
            var divd = document.getElementById('hgw-div');

            hdr.addEventListener('click', function(){
                if (body.classList.contains('show')) {
                    body.classList.add('collapsing');
                    body.classList.remove('show');
