                try {
                    const inputArea = window.parent.document.querySelector('#send_textarea');
                    if (inputArea) {
                        inputArea.value = textToSend;
                        inputArea.dispatchEvent(new Event('input', { bubbles: true}));
                        const sendBtn = window.parent.document.querySelector('#send_butt');
                        if(sendBtn) sendBtn.click();
                    }
                } catch(e) {
                    console.warn("兜底方案执行失败:", e);
                }
            }

            /* ================================================================
             * Section 4 — Raw Data Parsing and Dynamic DOM Rendering
             * Reads option text from the hidden data element, parses numbered
             * list entries via regex, and constructs animated <button> nodes
             * with staggered spring-curve entrance animations.
             * ============================================================== */
            const rawDataElement = document.getElementById('raw-options-data');
            if (!rawDataElement || !listContainer) return;

            const rawText = rawDataElement.innerText || rawDataElement.textContent || "";
            const lines = rawText.split(/\r?\n/);
            const options = [];
            let currentOption = "";
            const numRegex = /^\s*\d+[\.、：:]\s*(.*)/;

            lines.forEach(line => {
                const match = line.match(numRegex);
                if (match) {
                    if (currentOption) options.push(currentOption.trim());
                    currentOption = match[1].replace(/^\$\{|\}$/g, '').trim();
                } else if (currentOption && line.trim()) {
                    currentOption += " " + line.trim().replace(/^\$\{|\}$/g, '');
                }
            });
            if (currentOption) options.push(currentOption.trim());

            if (options.length === 0) {
                options.push(...rawText.split(/\r?\n/).filter(line => line.trim().length > 5));
            }

            options.forEach((optText, index) => {
                const btn = document.createElement('button');
                btn.className = 'action-btn';
                btn.style.animation = `springIn 0.6s var(--spring-curve) forwards ${index * 0.08}s`;

                const badge = document.createElement('div');
                badge.className = 'action-num-badge';
                badge.textContent = index + 1;

                const textSpan = document.createElement('span');
                textSpan.className = 'action-text';
                textSpan.textContent = optText;

                btn.appendChild(badge);
                btn.appendChild(textSpan);

                btn.addEventListener('click', function() {
                    executeOption(optText);
                });

                listContainer.appendChild(btn);
            });

            if (options.length === 0) {
                listContainer.innerHTML = `<div style="padding: 15px; opacity: 0.5; font-size: 0.9em; text-align: center; border: 1px dashed var(--glass-border); border-radius: 12px;">Waiting for options...</div>`;
            }
        });
    </script>
</body>
