            font-size: 0.8rem;
            font-weight: 700;
            color: var(--spec-title-color);
            letter-spacing: 0.5px;
        }
        .spec-stock-type {
            font-family: 'Inter', sans-serif;
            font-size: 0.65rem;
            font-weight: 600;
            color: var(--spec-label-color);
            background: rgba(200, 165, 90, 0.1);
            padding: 1px 6px;
            border-radius: 10px;
            align-self: flex-start;
        }
        .spec-stock-price {
            font-family: 'Playfair Display', 'Inter', serif;
            font-size: 1.15rem;
            font-weight: 800;
            color: var(--spec-text-color);
            line-height: 1.2;
        }
        .spec-stock-change {
            font-family: 'Inter', sans-serif;
            font-size: 0.95rem;
            font-weight: 700;
        }
        .spec-stock-prev {
            font-family: 'Inter', sans-serif;
            font-size: 0.72rem;
            color: var(--spec-label-color);
        }
        .spec-stock-heat {
            font-family: 'Inter', sans-serif;
            font-size: 0.68rem;
            color: var(--spec-label-color);
            display: flex;
            align-items: center;
            gap: 4px;
        }
        .spec-stock-driver {
            font-family: 'Inter', sans-serif;
            font-size: 0.7rem;
            color: var(--spec-label-color);
            border-top: 1px dashed rgba(200, 165, 90, 0.2);
            padding-top: 4px;
        }
        .spec-futures-list {
            display: flex;
            flex-wrap: wrap;
            gap: 8px;
            margin: 8px 0;
        }
        .spec-futures-item {
            background: var(--spec-index-bg);
            border: 1px solid var(--spec-index-border);
            border-radius: 8px;
            padding: 6px 12px;
            font-size: 0.78rem;
            color: var(--spec-text-color);
            display: flex;
            flex-wrap: wrap;
            align-items: center;
            gap: 6px;
        }
        .spec-index-box {
            background: var(--spec-index-bg);
            border: 1px solid var(--spec-index-border);
            border-radius: var(--radius-sm);
            padding: 10px 14px;
            margin-top: 8px;
            display: flex;
            align-items: center;
            gap: 12px;
            font-family: 'Inter', sans-serif;
        }
        .spec-index-value {
            font-size: 1.2rem;
            font-weight: 800;
            color: var(--spec-highlight);
        }
        .spec-index-change {
            font-weight: 600;
            font-size: 0.85rem;
        }
        .footer-note {
            text-align: center;
            font-size: 9px;
            color: #b8a080;
            border-top: 1px solid #e8dcc8;
            margin-top: 16px;
            padding-top: 10px;
            font-family: 'Inter', monospace;
            letter-spacing: 1.5px;
        }
        .theme-dark .footer-note {
            color: #8a7d60;
            border-top-color: rgba(180, 150, 90, 0.3);
        }
        @media (max-width: 640px) {
            .worldpaper-inner {
                padding: 10px 12px;
            }
            .section-content.open {
                padding: 10px 12px;
            }
            .currency-table-grid,
            .trade-regions-grid,
            .spec-stock-grid {
                grid-template-columns: 1fr;
            }
            .header-main-title {
                font-size: 15px;
            }
            .header-datetime {
                font-size: 10px;
                padding: 3px 8px;
            }
            .worldpaper-header {
                padding: 10px 12px;
                gap: 6px;
            }
            .header-icon-wrapper {
                font-size: 22px;
            }
            .toggle-hint {
                font-size: 9px;
                padding: 3px 8px;
            }
            .section-header {
                padding: 10px 12px;
                font-size: 15px;
                min-height: 44px;
            }
            .era-badge-main {
                font-size: 12px;
                padding: 4px 10px;
            }
            .l3-toggle {
                min-height: 44px;
                padding: 10px 10px !important;
            }
            .l3-arrow {
                width: 24px;
                height: 24px;
                font-size: 12px;
                margin-top: 0;
            }
            .sub-card {
                padding: 8px 10px;
            }
            .sub-item-block {
                padding: 6px 10px 8px 10px;
            }
            .stat-item {
                flex-wrap: wrap;
                gap: 4px;
                padding: 5px 8px;
            }
            .stat-label {
                font-size: 0.78rem;
            }
            .era-feature-list {
                gap: 5px;
            }
            .era-feature-list .stat-item {
                font-size: 0.78rem;
            }
            .timeline-node {
                margin-left: 4px;
                padding-left: 10px;
                font-size: 0.8rem;
            }
            .base-currency-highlight {
                padding: 10px 14px;
                gap: 8px;
            }
            .base-row-main {
                font-size: 0.95rem;
                gap: 8px;
            }
            .base-row-sub {
                font-size: 0.8rem;
                gap: 6px;
                padding-left: 4px;
            }
            .base-row-sub strong {
                font-size: 0.88rem;
            }
            .base-currency-icon {
                font-size: 24px;
            }
            .climate-phase-wrap {
                padding: 8px 10px;
            }
            .currency-card {
                padding: 12px 14px;
                gap: 5px;
            }
            .currency-rate {
                font-size: 1.15rem;
            }
            .currency-change {
                font-size: 0.95rem;
            }
            .currency-prev-row {
                font-size: 0.76rem;
            }
            .currency-prev-row .prev-num {
                font-size: 0.88rem;
            }
            .currency-driver-row {
                font-size: 0.7rem;
            }
            .currency-name {
                font-size: 0.76rem;
            }
            .spec-stock-price {
