            }
        }
        @media (max-width: 380px) {
            .worldpaper-header {
                padding: 8px 10px;
                gap: 4px;
            }
            .header-main-title {
                font-size: 13px;
                letter-spacing: 0.5px;
            }
            .header-datetime {
