        setTheme(isDark ? 'light' : 'dark');
        localStorage.setItem('worldlogTheme', isDark ? 'light' : 'dark');
    });

    function escapeHtml(s) { return String(s).replace(/[&<>]/g, m => ({'&':'&amp;','<':'&lt;','>':'&gt;'})[m]); }

    function parseListItems(text) {
        const lines = text.split('\n');
        const items = [];
        let current = null;
        for (let line of lines) {
            const trimmed = line.trim();
            if (trimmed.startsWith('- ')) {
                if (current) items.push(current);
                current = trimmed.substring(2).trim();
            } else if (trimmed !== '' && current !== null) {
                current += ' ' + trimmed;
            }
        }
        if (current) items.push(current);
        return items;
    }

    // 提取区块，避免子项 [ ] 干扰 (例如团体进度内的 [团体名])
    function extractBlockWithNesting(text, blockName, allTopLevelNames) {
        const escapedName = blockName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        const escapedNames = allTopLevelNames.map(n => n.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'));
        const nextBlockPattern = '\\r?\\n\\s*\\[(' + escapedNames.join('|') + ')\\]';
        const regex = new RegExp(`\\[${escapedName}\\]([\\s\\S]*?)(?=${nextBlockPattern}|\\r?\\n<|$)`, 'i');
        const match = text.match(regex);
        return match ? match[1].trim() : '';
    }

    // 简单提取（用于扩展区块内的平级子区块）
    function extractBlockSimple(text, blockName) {
        const escapedName = blockName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        const regex = new RegExp(`\\[${escapedName}\\]([\\s\\S]*?)(?=\\r?\\n\\s*\\[|\\r?\\n<|$)`, 'i');
        const match = text.match(regex);
        return match ? match[1].trim() : '';
    }

    function parseWorldLog(raw) {
        const data = { datetime: '', digest: '', statusBlocks: {}, secret: '', backstage: '' };
        const logMatch = raw.match(/<WorldLog[^>]*>([\s\S]*?)<\/WorldLog>/);
        const content = logMatch ? logMatch[1] : raw;

        const digestMatch = content.match(/<HTYQ_WorldDigest>([\s\S]*?)<\/HTYQ_WorldDigest>/);
        data.digest = digestMatch ? digestMatch[1].trim() : '';

        const statusMatch = content.match(/<HTYQ_StatusBlock>([\s\S]*?)<\/HTYQ_StatusBlock>/);
        const statusText = statusMatch ? statusMatch[1] : '';

        if (statusText) {
            // 定义所有可能的顶级区块名
            const baseTopBlocks = [
                '世界状态摘要','直接接触层','近距离层','远距离层','即将发生的日程',
                '事件链','传闻与流言','团体进度','已出场角色状态','剧情记忆摘要',
                '因果链','随机事件','扩展区块'
            ];
            // 动态查找 [近期…行动记录] 的区块名
            const actionBlockMatch = statusText.match(/\[(近期.*?行动记录)\]/);
            const allTopBlockNames = actionBlockMatch ? [...baseTopBlocks, actionBlockMatch[1]] : baseTopBlocks;

            allTopBlockNames.forEach(name => {
                data.statusBlocks[name] = extractBlockWithNesting(statusText, name, allTopBlockNames);
            });
        }

        const secretMatch = content.match(/<HTYQ_Secret>([\s\S]*?)<\/HTYQ_Secret>/);
        data.secret = secretMatch ? secretMatch[1].trim() : '';
        const backMatch = content.match(/<HTYQ_Backstage>([\s\S]*?)<\/HTYQ_Backstage>/);
        data.backstage = backMatch ? backMatch[1].trim() : '';
        return data;
    }

    function parseExtensionBlocks(extText) {
        const blocks = {};
        const titles = [
            '黑市','经济与物资摘要','经济事件可见性','声誉摘要','权力顶点',
            '团体关系','本轮外交事件','内部消息'
        ];
        titles.forEach(title => {
            const content = extractBlockSimple(extText, title);
            if (content) blocks[title] = content;
        });
        return blocks;
    }

    function parseBackstageBlocks(backText) {
        const blocks = {};
        const titles = [
            '待爆发事件链','待回收伏笔','本轮重点','跨区域角色备忘','血仇备忘','缺失补丁'
        ];
        titles.forEach(title => {
            const content = extractBlockSimple(backText, title);
            if (content) blocks[title] = content;
        });
        return blocks;
    }

    function parseReputationSummary(text) {
        if (!text) return [];
        const parts = text.split(/\s*[¦|｜]\s*/);
        const stats = [];
        parts.forEach(part => {
            const match = part.match(/^(.+?)[：:]\s*(.*)$/);
            if (match) {
                stats.push({ label: match[1].trim(), value: match[2].trim() });
            } else if (part.trim()) {
                stats.push({ label: '', value: part.trim() });
            }
        });
        return stats;
    }

    function renderReputationSummary(text) {
        const stats = parseReputationSummary(text);
        if (stats.length === 0) return '';
        let html = '<div class="sub-card"><div class="sub-card-title">⭐ 声誉摘要</div>';
        stats.forEach(stat => {
            html += `<div class="stat-item"><span class="stat-label">${escapeHtml(stat.label)}${stat.label ? '：' : ''}</span><span class="stat-value">${escapeHtml(stat.value)}</span></div>`;
        });
        html += '</div>';
        return html;
    }

    function parseGroupProgress(text) {
        if (!text) return [];
        const groups = [];
        const lines = text.split('\n');
        let currentName = null;
        let currentRegion = '';
        let currentDetails = [];
        for (let line of lines) {
            const trimmed = line.trim();
            if (!trimmed) continue;
            const groupMatch = trimmed.match(/^\[([^\]]+)\](?:（区域[：:]\s*(.+?)）)?\s*[：:]\s*/);
            if (groupMatch) {
                if (currentName) groups.push({ name: currentName, region: currentRegion, details: currentDetails });
                currentName = groupMatch[1];
                currentRegion = groupMatch[2] || '';
                currentDetails = [];
                const rest = trimmed.substring(groupMatch[0].length);
                if (rest.trim()) currentDetails.push(rest.trim());
            } else if (currentName !== null) {
                currentDetails.push(trimmed);
            }
        }
        if (currentName) groups.push({ name: currentName, region: currentRegion, details: currentDetails });
        if (groups.length === 0 && text.trim()) {
            groups.push({ name: '团体进度', region: '', details: [text.trim()] });
        }
        return groups;
    }

    function parseCharacterStates(text) {
        if (!text) return [];
        const lines = text.split('\n');
        const chars = [];
        let i = 0;
        while (i < lines.length) {
            const line = lines[i].trim();
            if (!line) { i++; continue; }
            const charMatch = line.match(/^([^\s：:]+(?:·[^\s：:]+)?)[：:]\s*(.*?)（重要度：(核心|活跃|潜在|背景)）\s*$/);
            if (charMatch) {
                const name = charMatch[1];
                const desc = charMatch[2].trim();
                const importance = charMatch[3];
                let relations = '';
                if (i + 1 < lines.length) {
                    const nextLine = lines[i+1].trim();
                    const relMatch = nextLine.match(/^关系网：\s*→\s*(.*)/);
                    if (relMatch) {
                        relations = relMatch[1].trim();
                        i++;
                    }
                }
                chars.push({ name, description: desc, importance, relations });
            }
            i++;
        }
        return chars;
    }

    function renderGenericBlock(title, content) {
        if (!content || content.trim() === '') return '';
        const lines = content.split('\n').filter(l => l.trim() !== '');
        let body = '';
        if (lines.every(l => l.trim().startsWith('- '))) {
            body = lines.map(l => `<div class="list-item">${escapeHtml(l.replace(/^-\s*/, ''))}</div>`).join('');
        } else {
            body = `<div class="list-item">${escapeHtml(content.trim().replace(/\n/g, '<br>'))}</div>`;
        }
        return `<div class="sub-card"><div class="sub-card-title">📄 ${escapeHtml(title)}</div>${body}</div>`;
    }

    function renderSubCardWithItems(title, items, icon='📋') {
        if (!items || items.length === 0) return '';
        const listHtml = items.map(it => `<div class="list-item">${escapeHtml(it)}</div>`).join('');
        return `<div class="sub-card"><div class="sub-card-title">${icon} ${escapeHtml(title)}</div>${listHtml}</div>`;
    }

    function renderWorldSummary(data) {
        let html = '';
        if (data.digest) {
            html += `<div class="highlight-box"><div style="font-weight:700;margin-bottom:6px;">📜 世界后台推演</div><div style="font-size:0.9rem;line-height:1.6;">${escapeHtml(data.digest)}</div></div>`;
        }
        const summary = data.statusBlocks['世界状态摘要'];
        if (summary) {
            const lines = summary.split('\n').filter(l => l.trim().startsWith('- '));
            if (lines.length) html += renderSubCardWithItems('世界状态摘要', lines.map(l=>l.replace(/^-\s*/,'')), '🌐');
        }
        ['直接接触层','近距离层','远距离层','即将发生的日程'].forEach(layer => {
            const block = data.statusBlocks[layer];
            if (block) html += renderSubCardWithItems(layer, parseListItems(block), layer==='直接接触层'?'📍':layer==='近距离层'?'🔍':layer==='远距离层'?'🌌':'📅');
        });
        return html;
    }

    function renderEventsRumors(data) {
        let html = '';
        ['事件链','传闻与流言','因果链'].forEach(field => {
            const block = data.statusBlocks[field];
            if (block) html += renderSubCardWithItems(field, parseListItems(block), '⛓️');
        });
        const random = data.statusBlocks['随机事件'];
        if (random && !random.includes('本轮无随机事件')) {
            html += renderSubCardWithItems('随机事件', [random.trim()], '🎲');
        }
        return html;
    }

    function renderFactionsCharacters(data, extBlocks) {
        let html = '';

        const groupText = data.statusBlocks['团体进度'];
        if (groupText) {
            const groups = parseGroupProgress(groupText);
            if (groups.length > 0) {
                let groupCardsHtml = '';
                groups.forEach(group => {
                    let cardContent = '';
                    group.details.forEach(line => {
                        const trimmed = line.trim();
                        if (!trimmed) return;
                        let icon = '▪️';
                        if (trimmed.includes('当前目标')) icon = '🎯';
                        else if (trimmed.includes('当前进度')) icon = '📊';
                        else if (trimmed.includes('内部凝聚力')) icon = '🤝';
                        else if (trimmed.includes('资源储备')) icon = '📦';
                        else if (trimmed.includes('关注度')) icon = '👁️';
                        else if (trimmed.includes('核心人物')) icon = '⭐';
                        cardContent += `<div class="group-detail">${icon} ${escapeHtml(trimmed)}</div>`;
                    });
                    const regionLabel = group.region ? `（区域：${escapeHtml(group.region)}）` : '';
                    groupCardsHtml += `<div class="group-card"><div class="group-name">🏛️ ${escapeHtml(group.name)}${regionLabel}</div>${cardContent}</div>`;
                });
                html += `<div class="sub-card"><div class="sub-card-title">🏛️ 团体进度</div>${groupCardsHtml}</div>`;
            }
        }

        const charText = data.statusBlocks['已出场角色状态'];
        if (charText) {
            const chars = parseCharacterStates(charText);
            if (chars.length > 0) {
                let charCardsHtml = '';
                chars.forEach(ch => {
                    let relationsHtml = ch.relations ? ` → ${escapeHtml(ch.relations)}` : '';
                    charCardsHtml += `<div class="group-card"><div class="group-name">👤 ${escapeHtml(ch.name)} <span style="font-size:0.7rem;color:var(--ink-light);">[${escapeHtml(ch.importance)}]</span></div><div class="group-detail">📋 ${escapeHtml(ch.description)}</div>${relationsHtml ? `<div class="group-detail">🔗 关系网：${relationsHtml}</div>` : ''}</div>`;
                });
                html += `<div class="sub-card"><div class="sub-card-title">👥 已出场角色状态</div>${charCardsHtml}</div>`;
            } else {
                html += `<div class="sub-card"><div class="sub-card-title">👥 已出场角色状态</div><div class="list-item">${escapeHtml(charText)}</div></div>`;
            }
        }

        // 近期行动记录（区块名动态）
        const actionKeys = Object.keys(data.statusBlocks).filter(k => k.includes('行动记录'));
        if (actionKeys.length > 0) {
            const actionText = data.statusBlocks[actionKeys[0]];
            if (actionText) {
                const items = parseListItems(actionText);
                if (items.length > 0) html += renderSubCardWithItems('近期行动记录', items, '🎯');
                else if (actionText.trim()) html += `<div class="sub-card"><div class="sub-card-title">🎯 近期行动记录</div><div class="list-item">${escapeHtml(actionText.trim())}</div></div>`;
            }
        }

        if (extBlocks['权力顶点']) html += renderSubCardWithItems('权力顶点', parseListItems(extBlocks['权力顶点']), '👑');
        if (extBlocks['团体关系']) html += renderSubCardWithItems('团体关系', parseListItems(extBlocks['团体关系']), '🤝');
        if (extBlocks['本轮外交事件']) html += renderSubCardWithItems('外交事件', parseListItems(extBlocks['本轮外交事件']), '🕊️');

        return html;
    }

    function renderEconomySecrets(data, extBlocks, secretText) {
        let html = '';
        if (extBlocks['黑市']) html += renderSubCardWithItems('黑市', parseListItems(extBlocks['黑市']), '🌑');
        if (extBlocks['经济与物资摘要']) html += renderSubCardWithItems('经济与物资摘要', parseListItems(extBlocks['经济与物资摘要']), '📦');
        if (extBlocks['经济事件可见性']) html += renderSubCardWithItems('经济事件可见性', parseListItems(extBlocks['经济事件可见性']), '👁️');
        if (extBlocks['声誉摘要']) html += renderReputationSummary(extBlocks['声誉摘要']);
        if (extBlocks['内部消息']) html += renderSubCardWithItems('内部消息', parseListItems(extBlocks['内部消息']), '🔒');
        if (secretText && !secretText.includes('当前无暗面信息')) {
            html += renderSubCardWithItems('信息黑盒与暗资产', [secretText], '🕵️');
        }
        return html;
    }

    function renderBackstage(backText) {
        const blocks = parseBackstageBlocks(backText);
        let html = '';
        for (let [title, content] of Object.entries(blocks)) {
            const items = parseListItems(content);
            let cardBody = '';
            if (items.length > 0) {
                cardBody = items.map(it => `<div class="list-item">${escapeHtml(it)}</div>`).join('');
            } else if (content.trim()) {
                cardBody = `<div class="list-item">${escapeHtml(content.trim())}</div>`;
            }
            if (cardBody) {
                html += `<div class="sub-card"><div class="sub-card-title">📌 ${escapeHtml(title)}</div>${cardBody}</div>`;
            }
        }
        if (!html) html = '<div class="sub-card" style="color:var(--ink-light);">⚙️ 后台无特殊备忘</div>';
        return html;
    }

    function renderAll(data, extBlocks, secretText, backText) {
        let html = '';
        const handledBlocks = new Set([
            '世界状态摘要','直接接触层','近距离层','远距离层','即将发生的日程',
            '事件链','传闻与流言','因果链','随机事件','团体进度','已出场角色状态',
            '扩展区块','剧情记忆摘要',
            ...Object.keys(data.statusBlocks).filter(k => k.includes('行动记录'))
        ]);

        html += `<div class="section-card"><div class="section-header" data-section="s1"><span>🌍 世界动态总览</span><span class="section-arrow">▼</span></div><div class="section-content open" id="s1c">${renderWorldSummary(data)}</div></div>`;
        html += `<div class="section-card"><div class="section-header" data-section="s2"><span>📰 事件与流言</span><span class="section-arrow">▼</span></div><div class="section-content" id="s2c">${renderEventsRumors(data)}</div></div>`;
        html += `<div class="section-card"><div class="section-header" data-section="s3"><span>⚔️ 势力与角色</span><span class="section-arrow">▼</span></div><div class="section-content" id="s3c">${renderFactionsCharacters(data, extBlocks)}</div></div>`;
        html += `<div class="section-card"><div class="section-header" data-section="s4"><span>💰 暗流与金脉</span><span class="section-arrow">▼</span></div><div class="section-content" id="s4c">${renderEconomySecrets(data, extBlocks, secretText)}</div></div>`;
        html += `<div class="section-card"><div class="section-header" data-section="s5"><span>⚙️ 后台推演</span><span class="section-arrow">▼</span></div><div class="section-content" id="s5c">${renderBackstage(backText)}</div></div>`;

        // 显示未被特殊处理的区块（如剧情记忆摘要）
        let extraHtml = '';
        for (let [blockName, content] of Object.entries(data.statusBlocks)) {
            if (handledBlocks.has(blockName)) continue;
            if (content && content.trim()) {
                extraHtml += renderGenericBlock(blockName, content);
            }
        }
        if (extraHtml) {
            html += `<div class="section-card"><div class="section-header" data-section="s6"><span>📋 其他动态</span><span class="section-arrow">▼</span></div><div class="section-content" id="s6c">${extraHtml}</div></div>`;
        }

        return html;
    }

    function setupSectionToggles() {
        document.querySelectorAll('.section-header').forEach(header => {
            header.addEventListener('click', function(e) {
                const section = this.getAttribute('data-section');
                const content = document.getElementById(section + 'c');
                const arrow = this.querySelector('.section-arrow');
                if (content) {
                    const isOpen = content.classList.contains('open');
                    content.classList.toggle('open');
                    arrow.style.transform = isOpen ? 'rotate(0deg)' : 'rotate(180deg)';
                }
            });
        });
    }

    function loadAndRender() {
        const hiddenArea = document.getElementById('rawWorldLogData');
        let rawText = hiddenArea ? hiddenArea.value : '';

        if (!rawText || rawText.trim() === '') {
            document.getElementById('dynamicContent').innerHTML = '<div style="padding:20px;color:var(--ink-light);">📜 没有可用的WorldLog数据</div>';
            return;
        }

        const data = parseWorldLog(rawText);
        const extBlocks = parseExtensionBlocks(data.statusBlocks['扩展区块'] || '');
        document.getElementById('dynamicContent').innerHTML = renderAll(data, extBlocks, data.secret, data.backstage);
        setupSectionToggles();
    }

    const globalBody = document.getElementById('worldlogBody');
    const globalHeader = document.getElementById('globalHeader');
    const globalArrow = document.getElementById('globalArrow');
    const globalHint = document.getElementById('globalHint');
    globalHeader.addEventListener('click', (e) => {
        if (e.target.closest('#themeToggle')) return;
        const isShow = globalBody.classList.contains('show');
        if (isShow) {
            globalBody.classList.remove('show');
            globalArrow.style.transform = 'rotate(0deg)';
            globalHint.innerText = '展开卷宗';
        } else {
            globalBody.classList.add('show');
            globalArrow.style.transform = 'rotate(180deg)';
            globalHint.innerText = '合上卷轴';
            if (!document.getElementById('dynamicContent')?.querySelector('.section-card')) {
                loadAndRender();
            }
        }
    });

    window.addEventListener('load', () => {
        if (document.getElementById('dynamicContent')?.querySelector('.section-card')) return;
        loadAndRender();
    });
})();
</script>
</body>
</html>
