        .chronicle-header:hover { background: linear-gradient(160deg, rgba(26,20,48,0.95) 0%, rgba(34,26,58,0.9) 40%, rgba(28,22,52,0.92) 100%); }
        .theme-light .chronicle-header { background: linear-gradient(160deg, #3a3048 0%, #4a3d58 40%, #3f344e 100%); }
        .theme-light .chronicle-header:hover { background: linear-gradient(160deg, #42384f 0%, #524560 40%, #473c55 100%); }
        .header-icon-group { display:flex; align-items:center; gap:2px; position:relative; z-index:1; flex-shrink:0; }
        .header-icon-main { font-size:20px; filter:drop-shadow(0 0 6px rgba(180,150,220,0.5)); }
        .header-title-area { flex:1; display:flex; flex-direction:column; gap:0px; min-width:0; position:relative; z-index:1; }
        .header-title { font-family:var(--font-display); font-size:15px; font-weight:700; letter-spacing:0.8px; color:#e8ddf5; text-shadow:0 0 10px rgba(180,150,220,0.3); line-height:1.2; }
        .header-time-badge {
