        .toggle-badge { font-size:8px; font-family:var(--font-mono); background:rgba(255,255,255,0.06); color:#c8bdd8; padding:3px 8px; border-radius:12px; letter-spacing:0.8px; border:1px solid rgba(180,150,220,0.18); transition:all 0.3s; white-space:nowrap; }
        .header-caret { font-size:14px; color:var(--accent-lavender); transition:transform 0.4s cubic-bezier(0.25,0.8,0.25,1.2); filter:drop-shadow(0 0 6px rgba(180,150,220,0.5)); width:24px; height:24px; display:flex; align-items:center; justify-content:center; border-radius:50%; background:rgba(255,255,255,0.03); border:1px solid rgba(180,150,220,0.2); }
        .theme-btn { background:none; border:1px solid rgba(180,150,220,0.3); color:var(--accent-lavender); font-size:14px; cursor:pointer; width:26px; height:26px; border-radius:50%; display:flex; align-items:center; justify-content:center; transition:all 0.3s; background:rgba(255,255,255,0.05); backdrop-filter:blur(4px); }
        .theme-btn:hover { background:rgba(180,150,220,0.2); border-color:var(--accent-lavender); box-shadow:0 0 10px rgba(180,150,220,0.4); }
        .chronicle-body { max-height:0; overflow:hidden; transition:max-height 0.55s cubic-bezier(0.33,1,0.68,1); position:relative; z-index:2; }
        .chronicle-body.expanded { max-height:12000px; }
        .chronicle-inner { padding:12px 14px 14px 14px; }
        .major-panel { background:var(--bg-panel); border:1px solid var(--border-subtle); border-radius:var(--radius-lg); margin-bottom:10px; box-shadow:var(--glow-card); overflow:hidden; transition:box-shadow var(--transition-smooth); position:relative; }
        .major-panel:hover { box-shadow:var(--glow-accent); }
        .major-panel::before { content:""; position:absolute; top:0; left:0; width:3px; height:100%; background:linear-gradient(180deg, var(--accent-lavender) 0%, var(--accent-rose) 40%, var(--accent-sky) 100%); border-radius:var(--radius-lg) 0 0 var(--radius-lg); opacity:0.8; }
        .panel-header { display:flex; align-items:center; justify-content:space-between; padding:9px 12px 9px 16px; background:rgba(30,26,50,0.5); cursor:pointer; transition:all 0.25s; font-weight:700; font-size:14px; font-family:var(--font-display); color:var(--text-accent); letter-spacing:0.5px; gap:6px; border-bottom:1px solid transparent; -webkit-tap-highlight-color:transparent; min-height:38px; user-select:none; }
        .theme-light .panel-header { background:rgba(240,235,225,0.55); color:#3a2a18; }
        .panel-header:hover { background:rgba(36,30,58,0.6); border-bottom-color:var(--border-glow); }
        .theme-light .panel-header:hover { background:rgba(235,228,215,0.65); border-bottom-color:rgba(150,120,80,0.35); }
        .panel-icon { font-size:16px; flex-shrink:0; }
        .panel-label { flex:1; display:flex; align-items:center; gap:6px; min-width:0; }
        .panel-badge { font-family:var(--font-mono); font-size:7px; font-weight:600; background:rgba(180,150,220,0.18); color:var(--accent-lavender); padding:2px 6px; border-radius:10px; letter-spacing:1px; white-space:nowrap; }
        .theme-light .panel-badge { background:rgba(130,100,60,0.15); color:#7a5c30; }
        .panel-caret { font-size:12px; transition:transform 0.4s; color:var(--accent-lavender); width:20px; height:20px; display:flex; align-items:center; justify-content:center; border-radius:50%; background:rgba(180,150,220,0.08); flex-shrink:0; }
