        .npc-card { background:var(--bg-card); border:1px solid var(--border-subtle); border-radius:var(--radius-md); padding:12px 14px; box-shadow:var(--glow-card); transition:all var(--transition-smooth); position:relative; overflow:hidden; display:flex; flex-direction:column; gap:6px; }
