        .wealth-destitute { background:rgba(200,120,100,0.2); color:#e09080; border:1px solid rgba(200,120,100,0.35); }
        .wealth-poor { background:rgba(200,150,100,0.2); color:#d4a070; border:1px solid rgba(200,150,100,0.35); }
        .wealth-tight { background:rgba(190,160,110,0.2); color:#c8a860; border:1px solid rgba(190,160,110,0.35); }
