        .wealth-comfortable { background:rgba(130,180,150,0.2); color:#80b890; border:1px solid rgba(130,180,150,0.35); }
        .wealth-welloff { background:rgba(120,170,180,0.2); color:#78a8b4; border:1px solid rgba(120,170,180,0.35); }
        .wealth-rich { background:rgba(180,160,100,0.25); color:#d4c070; border:1px solid rgba(200,170,100,0.5); box-shadow:0 0 6px rgba(200,170,100,0.15); }
        .npc-status-row { font-family:var(--font-mono); font-size:0.65rem; color:var(--text-secondary); display:flex; flex-wrap:wrap; gap:2px 6px; position:relative; z-index:1; line-height:1.4; }
        .npc-status-dot { color:var(--accent-sky); font-weight:700; }
        .npc-chain-section { background:rgba(30,26,50,0.5); border-radius:var(--radius-sm); padding:6px 10px; position:relative; z-index:1; border-left:3px solid var(--accent-lavender); }
        .theme-light .npc-chain-section { background:rgba(235,228,215,0.5); border-left-color:rgba(130,100,60,0.5); }
        .chain-label { font-size:0.6rem; font-weight:700; letter-spacing:0.8px; color:var(--accent-lavender); text-transform:uppercase; margin-bottom:3px; font-family:var(--font-mono); }
        .chain-flow { display:flex; flex-wrap:wrap; align-items:center; gap:3px; font-size:0.68rem; color:var(--text-secondary); line-height:1.5; }

