t type="radio" name="fetchTarget" id="targetB" value="B" style="display:none;" onchange="changeFetchTarget('B')"><div class="mode-radio-circle" style="width:14px; height:14px; border:1px solid var(--text-s); border-radius:50%; margin-right:4px; display:flex; align-items:center; justify-content:center; transition:var(--t-fast); flex-shrink:0;"></div>B</label><label class="mode-radio-label" style="display:inline-flex; align-items:center; cursor:pointer; font-size:0.9em; color:var(--text-m); white-space:nowrap; flex-shrink:0;"><input type="radio" name="fetchTarget" id="targetC" value="C" style="display:none;" onchange="changeFetchTarget('C')"><div class="mode-radio-circle" style="width:14px; height:14px; border:1px solid var(--text-s); border-radius:50%; margin-right:4px; display:flex; align-items:center; justify-content:center; transition:var(--t-fast); flex-shrink:0;"></div>优先B其次A</label></div></div><div style="margin-top:16px; padding-top:12px; border-top:1px dashed var(--border);"><div style="display:flex; gap:6px; margin-bottom:8px; align-items:center;"><span class="i-k" style="font-size:0.9em; margin-right:4px; margin-bottom:0;">指定楼层编辑</span><input type="text" id="cacheFloorInput" class="pollution-input" style="flex:0 0 85px; text-align:center; padding:4px;" placeholder="楼层"><button class="pollution-add-btn" style="padding:4px 12px;" onclick="queryCacheFloor()">查询</button><input type="text" id="cachePresetInput" class="pollution-input" style="flex:1; text-align:right; padding:4px; font-size:0.85em; border:none; background:transparent; min-width:0; color:var(--accent); font-weight:bold;" placeholder="预设: 无" title="当前楼层使用的提示词预设"></div><textarea id="cacheEditArea" style="width:100%; height:150px; background:var(--bg-card); color:var(--text-m); border:1px solid var(--border); border-radius:var(--r3); padding:8px; font-size:0.9em; line-height:1.4; resize:vertical; outline:none;" placeholder="输入楼层号并点击查询... "></textarea><button class="save-theme-btn" style="width:100%; margin-top:8px; border-radius:var(--r-btn);" onclick="saveCacheFloor()">保存修改并重载</button></div><div style="margin-top:16px; padding-top:12px; border-top:1px dashed var(--border);"><div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:8px;"><span class="i-k" style="font-size:0.9em; margin-bottom:0;">全楼层缺失检测</span><button class="pollution-add-btn" style="padding:4px 12px; background:var(--text-s);" onclick="detectEmptyFloors()">开始检测</button></div><div id="emptyFloorList" style="font-size:0.85em; color:var(--text-s); background:var(--bg-card); padding:6px; border-radius:var(--r3); min-height:30px; max-height:80px; overflow-y:auto; margin-bottom:8px; border:1px solid var(--border); word-break:break-all;">未进行检测</div><div style="display:flex; gap:6px;"><input type="text" id="bulkFillInput" class="pollution-input" style="flex:1; padding:6px;" placeholder="输入统一填充的文本..."><button class="pollution-add-btn" style="padding:4px 12px;" onclick="bulkFillFloors()">一键填充</button></div></div></div></div></div></div>
