           window.clearCacheItem = async (idx, sId) => {
               if (!confirm("确定要删除此条数据吗?该操作仅清理隐藏的&#36;6规划数据,不影响正文")) return;
               const chat = window.SillyTavern?.chat || (typeof getContext==='function'?getContext()?.chat:[]);
               if (!chat[idx]) return;
               if (sId !== null && chat[idx].swipes?.[sId]) {
                   if (chat[idx].swipes[sId].extra) delete chat[idx].swipes[sId].extra.qrf_plot;
               }
               if (chat[idx].extra?.qrf_plot) delete chat[idx].extra.qrf_plot;
               if (chat[idx].qrf_plot) delete chat[idx].qrf_plot;
               if (chat[idx].qrf_plot_tasks) delete chat[idx].qrf_plot_tasks;
