           window.queryCacheFloor = () => {
               const chat = window.SillyTavern?.chat || (typeof getContext==='function'?getContext()?.chat:[]);
               const rawInput = $('cacheFloorInput').value.trim();
               const parts = rawInput.split(/[,,]/); // 支持中英文逗号切割
               const floorNum = parseInt(parts[0]);

               if (isNaN(floorNum) || floorNum < 0 || floorNum >= chat.length) {
                   alert("请输入有效的楼层号(0 - " + (chat.length - 1) + ")");
                   return;
               }
               const idx = floorNum;
               const msg = chat[idx];
               currentEditFloor = idx;

               let objName = 'qrf_plot';
               if (parts[1]) {
                   // 若包含隐藏指令,严格遵循指令
                   objName = parts[1].trim();
               } else {
                   // 若未包含隐藏指令,跟随全局对象抓取设置
                   const fetchTarget = localStorage.getItem('st_scenario_fetch_target_v1') || 'A';
                   if (fetchTarget === 'A') objName = 'qrf_plot';
                   else if (fetchTarget === 'B') objName = 'qrf_plot_tasks';
                   else if (fetchTarget === 'C') {
                       objName = (msg.qrf_plot_tasks !== undefined && msg.qrf_plot_tasks !== null) ? 'qrf_plot_tasks' : 'qrf_plot';
                   }
               }
               currentEditObject = objName;

               // 动态查询指定的根目录属性
               const plotText = (msg[objName] !== undefined && msg[objName] !== null) ? msg[objName] : null;
               const presetText = msg.qrf_plot_preset || "";
               if ($('cachePresetInput')) $('cachePresetInput').value = presetText;

               const textArea = $('cacheEditArea');
               if (plotText === null || plotText === undefined) {
                   textArea.value = "";
                   textArea.placeholder = `该楼层暂无 ${objName} 属性创立。可在此直接输入内容以创立关联数据。`;
               } else {
                   // 若查询到的是 JSON 对象,自动序列化为美观的文本以便编辑
                   textArea.value = typeof plotText === 'object' ? JSON.stringify(plotText, null, 2) : plotText;
               }
           };

           window.saveCacheFloor = async () => {
               if (currentEditFloor < 0) {
                   alert("请先查询并指定楼层!");
                   return;
               }
               const chat = window.SillyTavern?.chat || (typeof getContext==='function'?getContext()?.chat:[]);
               const msg = chat[currentEditFloor];
               if (!msg) return;

               let newText = $('cacheEditArea').value.trim();
               const newPreset = $('cachePresetInput').value.trim();

               // 如果输入看起来像 JSON,尝试反序列化以支持对象级写入
               if ((newText.startsWith('{') && newText.endsWith('}')) || (newText.startsWith('[') && newText.endsWith(']'))) {
                   try { newText = JSON.parse(newText); } catch(e) { console.warn("JSON解析失败,作为普通文本保存", e); }
               }

               // 动态写入指定属性
               msg[currentEditObject] = newText;
               msg.qrf_plot_preset = newPreset;

               if (typeof SillyTavern?.saveChat === 'function') await SillyTavern.saveChat();

               alert(`楼层 ${currentEditFloor} 的 ${currentEditObject} 数据已保存!`);
               render();
