           window.detectedEmptyFloors = [];

           window.detectEmptyFloors = () => {
               const chat = window.SillyTavern?.chat || (typeof getContext==='function'?getContext()?.chat:[]);
               const fetchTarget = localStorage.getItem('st_scenario_fetch_target_v1') || 'A';
               window.detectedEmptyFloors =[];

               chat.forEach((msg, idx) => {
                   // 仅检测用户发送的消息
                   if (!msg.is_user) return;

                   let hasA = (msg.qrf_plot !== undefined && msg.qrf_plot !== null && msg.qrf_plot !== "");
                   let hasB = (msg.qrf_plot_tasks !== undefined && msg.qrf_plot_tasks !== null && msg.qrf_plot_tasks !== "");

                   let hasPlot = false;
                   if (fetchTarget === 'A') hasPlot = hasA;
                   else if (fetchTarget === 'B') hasPlot = hasB;
                   else hasPlot = hasB || hasA;

                   if (!hasPlot) window.detectedEmptyFloors.push(idx);
               });

               const display = $('emptyFloorList');
               if (window.detectedEmptyFloors.length === 0) {
                   display.innerText = "检测完毕:全楼层均已包含规划数据。";
