   async function render() {
       const chat = window.SillyTavern?.chat || (typeof getContext==='function'?getContext()?.chat:[]);
       let targetIdx = chat.length - 1;
       const myContent = capsule.value.split('--- START OF FILE')[0].trim();
       for (let i = chat.length - 1; i >= 0; i--) {
           if (chat[i].mes && chat[i].mes.includes(myContent)) { targetIdx = i; break; }
       }

       // 动态获取当前楼层最新的原始文本(支持分支切换和外部实时修改刷新)
       let liveMesText = capsule.value;
       if (targetIdx >= 0 && chat[targetIdx]) {
           const msg = chat[targetIdx];
           liveMesText = msg.mes;
           if (msg.swipes && Array.isArray(msg.swipes)) {
               const sid = msg.swipe_id ?? (msg.swipes.length - 1);
               if (msg.swipes[sid] && msg.swipes[sid].mes) liveMesText = msg.swipes[sid].mes;
           }
       }

   try {
       // --- 10.1 数据加载 ---
       const menuBar = document.querySelector('#render-target .tabs-bar'), amBar = document.querySelector('#render-target .tag-list.scroll-mode');
       const lastMenuX = menuBar ? menuBar.scrollLeft : 0, lastAmX = amBar ? amBar.scrollLeft : 0;

       const unfilteredRaw = liveMesText;
       const unfilteredSix = await fetchContext(targetIdx);
       // 过滤旧格式标签(thought / dm_set / dm_plan 来自旧版 prompt,新 prompt 已不产出,保留兼容 $6 历史数据)
       const filterBlacklist = (text) => text ? text.replace(/<(?:thought|dm_set|dm_plan)>[\s\S]*?(?:<\/(?:thought|dm_set|dm_plan)>|$)/gi, '') : text;
       let raw = filterBlacklist(unfilteredRaw);
       window.lastFullCtx = filterBlacklist(unfilteredSix);

       const btnRaw = $('btn-view-raw'); btnRaw.classList.remove('flash-red');
       const btnSix = $('btn-view-six');
       if (btnSix) btnSix.innerHTML = (window.lastFetchedIdx >= 0 && window.lastFetchedIdx < targetIdx) ? '&#36;6文本⇧' : '&#36;6文本';

       let triggeredWords =[];
       for (const word in pollutionConfig) {
           // 增殖词检测使用未过滤的文本,确保不漏过思维链中的词
           const count = (unfilteredRaw.match(new RegExp(word.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'gi')) || []).length;
           if (count > pollutionConfig[word]) triggeredWords.push(word);
       }
       if (triggeredWords.length > 0) {
           btnRaw.classList.add('flash-red');
           app.classList.add('pollution-alert');
       } else {
           app.classList.remove('pollution-alert');
       }
       if (debugViewMode === 0) {
           $('debug').innerHTML = '';
           if (triggeredWords.length > 0) {
               const escapeReg = (s) => s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
               const pattern = '(' + triggeredWords.map(escapeReg).join('|') + ')';
               const regex = new RegExp(pattern, 'gi');

               const parts = unfilteredRaw.split(regex);
               const frag = document.createDocumentFragment();

               parts.forEach(part => {
                   if (!part) return;
                   const isPolluted = triggeredWords.some(w => w.toLowerCase() === part.toLowerCase());
                   if (isPolluted) {
                       const span = document.createElement('span');
                       span.className = 'highlight-polluted';
                       span.textContent = part;
                       frag.appendChild(span);
                   } else {
                       frag.appendChild(document.createTextNode(part));
                   }
               });
               $('debug').appendChild(frag);
           } else {
               $('debug').innerText = unfilteredRaw;
           }
       } else {
           const fetched = unfilteredSix, tag = localStorage.getItem(filterKey);
           if (tag && fetched) {
               const matches = fetched.match(new RegExp(`<${tag}[^>]*>[\\s\\S]*?<\\/${tag}>`, 'gi'));
               $('debug').innerText = matches ? matches.join('\n\n') : `[已过滤] 未找到 <${tag}> 标签内容`;
           }
           else $('debug').innerText = fetched || "未在当前楼层中找到相关数据 (qrf_plot/qrf_plot_tasks)";
       }

           // 提取用户输入(兼容旧标签名,新 prompt 不再产出)
           const vanillaInput = getTag(raw, '本轮用户输入') || getTag(raw, '用户本轮输入');
           $('user-input-display').innerText = vanillaInput || ''; $('user-input-display').style.display = vanillaInput ? 'block' : 'none'; app.classList.toggle('has-input', !!vanillaInput);
           const target = $('render-target'); target.innerHTML = '';



           // 模式状态显示

           let modeName = '';
           const sourceIdx = (window.lastFetchedIdx >= 0) ? window.lastFetchedIdx : targetIdx;
           if (chat[sourceIdx] && chat[sourceIdx].qrf_plot_preset) {
               modeName = chat[sourceIdx].qrf_plot_preset;
           }
           window.lastPresetName = modeName || null;

           let recallHTML = '', supplementHTML = '', tabModules =[];
           const recallRaw = getTag(raw, 'Recall') || '';
           const amMatches = recallRaw.match(/AM\d+/gi) || [];
           if (amMatches.length === 0) { amMatches.push(...(getTag(raw, 'plot') || '').match(/AM\d+/gi)||[]); }
                   if (amMatches.length || raw.includes('<Recall>')) {
                       const formatAm = (id) => amFolded ? id.toUpperCase().replace(/^AM0+(?=\d)/, 'AM') : id.toUpperCase();
                       const amListHTML = amMatches.length
                           ? amMatches.map(i => `<span class="tag" onclick="showMemoryDetail('${i.toUpperCase()}')">${formatAm(i)}</span>`).join('')
                           : '<span style="font-size:0.95em; opacity:0.8; margin-left:4px;">无</span>';

                       recallHTML = `<div class="sec" style="margin-bottom:7px">
                           <div class="sec-label">记忆召回<div class="sec-label-line"></div><span class="count-badge" ${amMatches.length ? 'style="cursor:pointer" onclick="window.toggleAmFold(event)" title="点击切换缩写"' : ''}>${amMatches.length}</span></div>
                           <div class="tag-list">${amListHTML}</div>
                       </div>`;
