                       if (sm) { summary = sm[1].trim(); }
                       else if (/^\s*[☑▶☐📅]/u.test(line)) { stepLines.push(line); }
                   }

                   // 计算步骤
                   var doneTop = 0, totalTop = 0;
                   var baseIndent = stepLines.length ? Math.min.apply(null, stepLines.map(function(l){ return (l.match(/^(\s*)/) || [''])[1].length; })) : 0;
                   var stepsHTML = stepLines.map(function(line) {
                       var trimmed = line.trim();
                       var indent = (line.match(/^(\s*)/) || [''])[1].length;
                       var isConverge = trimmed.startsWith('📅');
                       var isDone = trimmed[0] === '☑';
                       var isActive = trimmed[0] === '▶';
                       var isTop = indent === baseIndent;
                       if (isTop && !isConverge) totalTop++;
                       if (isDone && isTop) doneTop++;
                       var clean = trimmed.replace(/^[☑▶☐📅]\s*/u, '');
                       var cls = 'ql-step ' + (isConverge ? 'converge' : (isDone ? 'done' : (isActive ? 'active' : 'pending'))) + (isTop ? '' : ' child');
                       return '<div class="' + cls + '" style="--ql-dot:' + tc.dot + '"><span class="ql-step-dot"></span><span class="ql-step-txt">' + clean + '</span></div>';
                   }).join('');

                   // SVG 进度环
                   var ringHTML = '';
                   if (totalTop > 0) {
                       var ratio = doneTop / totalTop;
                       var circ = 2 * Math.PI * 13; // r=13
                       var dash = circ * ratio;
