                       ringHTML = '<div class="ql-ring-wrap"><svg class="ql-ring" viewBox="0 0 32 32"><circle class="ql-ring-bg" cx="16" cy="16" r="13" fill="none" stroke="var(--bg-tag)" stroke-width="3"/><circle class="ql-ring-fill" cx="16" cy="16" r="13" fill="none" stroke="' + tc.bar + '" stroke-width="3" stroke-linecap="round" stroke-dasharray="' + dash.toFixed(1) + ' ' + gap.toFixed(1) + '" transform="rotate(-90 16 16)" style="animation:qlRingFill .8s ease-out both"/></svg><span class="ql-ring-num">' + doneTop + '/' + totalTop + '</span></div>';
                   }

