                               var label = isActive ? 'PRIMARY' : 'ALT-' + (i+1); var ocls = 'qp-ocard' + (isActive ? ' primary' : ''); return '<div class="' + ocls + '"><div class="qp-ocard-head"><span class="qp-ocard-dir">' + dirText + '</span><span class="qp-ocard-label">' + label + '</span></div>' + (consText ? '<div class="qp-ocard-cons">' + consText + '</div>' : '') + '</div>';
                           }).join('');
                           branchHtml = '<div class="qp-ocard-list">' + items + '</div>';
                       }
                   }

                   var npcMotive = '';
                   const npcMatch = block.match(/关键NPC动机底线[：:]\s*([^\n]+(?:\n(?!节拍规划|$)[^\n]+)*)/i);
                   if (npcMatch) npcMotive = npcMatch[1].trim();

                   var beatsHtml = '';
                   const beatsSection = block.match(/节拍规划[：:]\s*([\s\S]*?)$/i);
                   if (beatsSection) {
                       var zones = { '已完成': [], '激活中': [], '未来': [] };
                       var currentZone = null;
                       var zoneLines = beatsSection[1].split(/\r?\n/);
                       for (var zi = 0; zi < zoneLines.length; zi++) {
                           var zl = zoneLines[zi].trim();
                           if (zl === '已完成:' || zl === '已完成') { currentZone = '已完成'; continue; }
                           if (zl === '激活中:' || zl === '激活中') { currentZone = '激活中'; continue; }
                           if (zl === '未来:' || zl === '未来') { currentZone = '未来'; continue; }
                           if (currentZone && (zl.includes('|') || zl.includes('¦'))) zones[currentZone].push(zoneLines[zi]);
                       }

                       var parseBeatNumber = function(str) { return (str.match(/\d+/) || [''])[0]; };
                       var getTempClass = function(t) {
                           t = parseInt(t); if (t <= 3) return 't-lo'; if (t <= 5) return 't-mi'; if (t <= 7) return 't-hi'; return 't-vh';
                       };

                       var zoneHTML = '';
