                   var idx = cardIdx++;
                   return '<div class="qp-card" style="--qp-bar:' + tc.bar + ';--qp-bg:' + tc.bg + ';animation:qlCardIn .4s ease-out ' + (idx * 0.08) + 's both">' +
                       '<div class="qp-header"><span class="qp-badge" style="--ql-bar:' + tc.bar + ';--ql-bg:' + tc.bg + '">' + type + '</span><span class="qp-name">' + taskName + '</span>' + (T ? '<span class="qp-meta-pill">' + T + '/' + M + '</span>' : '') + (paceDesc ? '<span class="qp-meta-pill pace">' + paceDesc + '</span>' : '') + (extended && extended !== '—' && extended !== '-' ? '<span class="qp-meta-pill ext">' + extended + '</span>' : '') + '</div>' +
                       '<div class="qp-thermo-row"><span class="qp-thermo-val ' + (function(){ if(!tempSeq||!T) return 't-lo'; var vals=tempSeq.split(','); var cur=vals[parseInt(T)]; return cur?getTempClass(cur.trim()):'t-lo'; })() + '">' + (function(){ if(!tempSeq||!T) return ''; var vals=tempSeq.split(','); var cur=vals[parseInt(T)]; var names={1:'沉寂',2:'温和',3:'好奇',4:'警觉',5:'紧张',6:'加压',7:'爆发',8:'转折',9:'巅峰',10:'蜕变'}; return cur?(cur.trim()+' '+names[parseInt(cur)]||''):''; })() + '</span><div class="qp-thermo-gauge"><div class="qp-thermo-fill ' + (function(){ if(!tempSeq||!T) return 't-lo'; var vals=tempSeq.split(','); var cur=vals[parseInt(T)]; return cur?getTempClass(cur.trim()):'t-lo'; })() + '" style="width:' + (function(){ if(!tempSeq||!T) return 10; var vals=tempSeq.split(','); var cur=parseInt(vals[parseInt(T)])||0; return Math.round(cur/10*100); })() + '%"></div></div></div>' +
                       branchHtml +
                       (npcMotive ? (function(){ var colon = npcMotive.indexOf('：'); if (colon < 0) colon = npcMotive.indexOf(':'); var npcName = colon > 0 ? npcMotive.substring(0, colon).trim() : ''; var npcText = colon > 0 ? npcMotive.substring(colon + 1).trim() : npcMotive; return '<div class="qp-term"><div class="qp-term-prompt">&gt; ACCESSING DOSSIER</div><div class="qp-term-div"></div><div class="qp-term-body"><div class="qp-term-row"><span class="qp-term-label">NAME</span><span class="qp-term-val">' + npcName + '</span></div><div class="qp-term-row"><span class="qp-term-label">MOTIVE</span><span class="qp-term-val">' + npcText + '</span></div></div><div class="qp-term-div"></div><div class="qp-term-actions"><span>DECRYPT</span><span>ARCHIVE</span><span>EXPORT</span></div></div>'; })() : '') +
