<script>
(function(){
    const getStatusClass = (statusText) => {
        const t = statusText.toLowerCase();
        if(t.includes('角逐') || t.includes('活跃') || t.includes('存活') || t.includes('竞赛')) return 'status-alive';
        if(t.includes('晋级') || t.includes('出线')) return 'status-promote';
        if(t.includes('淘汰') || t.includes('死亡') || t.includes('退场')) return 'status-eliminated';
        if(t.includes('胜利') || t.includes('冠军')) return 'status-victory';
        return 'status-alive';
    };

    const parseTournament = (rawText) => {
        let match = rawText.match(/<比赛>([\s\S]*?)<\/比赛>/);
        if(!match) return null;
        let inner = match[1].trim();
        if(inner === '比赛未开始' || inner.includes('比赛未开始')) return { preWar: true };
        let lines = inner.split(/\r?\n/).filter(l=>l.trim());
        let meta = { name: '通用竞赛', round: '—' };
        let contestants = [];
        let matchups = [];

        for(let line of lines) {
            line = line.trim();
            let matchupMatch = line.match(/^(对抗组|对阵|对抗列表)\s*:\s*(.+)$/i);
            if(matchupMatch) {
                let content = matchupMatch[2].trim();
                if(content) matchups.push(content);
                continue;
            }
            if(line.startsWith('比赛名称:') || line.includes('比赛名称:')) {
                let parts = line.split('|');
                for(let p of parts) {
                    if(p.includes('比赛名称:')) meta.name = p.split('比赛名称:')[1].trim();
                    if(p.includes('轮次:')) meta.round = p.split('轮次:')[1].trim();
                }
                continue;
            }
            let colonIdx = line.indexOf(':');
            if(colonIdx === -1) continue;
            let name = line.slice(0, colonIdx).replace(/[\[\]]/g, '').trim();
            let rest = line.slice(colonIdx+1).trim();
            let parts = rest.split('|').map(s=>s.trim());
            let status = '—';
            let score = '?';
            let members = null;
            let opponent = null;
            let extra = [];
            for(let part of parts) {
                if(part.startsWith('状态:')) status = part.replace('状态:', '').trim();
                else if(part.startsWith('比分:') || part.startsWith('团队比分:') || part.startsWith('积分:')) {
                    let prefix = part.includes('团队比分:') ? '团队比分:' : (part.includes('比分:') ? '比分:' : '积分:');
                    score = part.replace(prefix, '').trim();
                }
                else if(part.startsWith('队员:')) {
                    let membersRaw = part.replace('队员:', '').trim();
                    members = membersRaw.split(/[,，]+/).map(m=>m.trim()).filter(m=>m);
                }
                else if(part.startsWith('对手:')) {
                    opponent = part.replace('对手:', '').trim();
                }
                else if(part.trim() !== '') extra.push(part);
            }
            let type = (members && members.length > 0) ? 'team' : 'solo';
            contestants.push({ type, name, status, score, members, opponent, extra: extra.join(' | ') });
        }
        return { preWar: false, meta, contestants, matchups };
    };

    function buildMatchupFromOpponents(contestants) {
        let pairs = new Set();
        for(let c of contestants) {
            if(c.opponent && c.opponent !== '') {
                let a = c.name;
                let b = c.opponent;
                let key = [a, b].sort().join('<>');
                pairs.add(`${a} VS ${b}`);
            }
        }
        return Array.from(pairs);
    }

    function renderUI(data) {
        const metaDiv = document.getElementById('arenaMetaArea');
        const rosterDiv = document.getElementById('arenaRoster');
        const countBadge = document.getElementById('arenaCountBadge');
        const metaPreview = document.getElementById('arenaMetaPreview');
        const matchupsArea = document.getElementById('arenaMatchupsArea');
        const matchupsListDiv = document.getElementById('arenaMatchupsList');
        if(!metaDiv || !rosterDiv) return;

        if(!data || data.preWar) {
            metaDiv.innerHTML = '<div style="color:#ffd966; text-align:center; text-shadow:0 0 2px black;">⚔️ 比赛尚未开始 ⚔️</div>';
            rosterDiv.innerHTML = '<div style="text-align:center;padding:20px;color:#e6d5a8">等待裁判发布对阵表...</div>';
            countBadge.innerText = '未开赛';
            metaPreview.innerText = '备战区';
            if(matchupsArea) matchupsArea.style.display = 'none';
            return;
        }

        let metaHtml = `<span>🏟️ ${escapeHtml(data.meta.name)}</span><span>🔁 ${escapeHtml(data.meta.round)}</span>`;
        metaDiv.innerHTML = metaHtml;
        metaPreview.innerText = `${data.meta.name} · ${data.meta.round}`;
        let countText = data.contestants.length + (data.contestants.some(c=>c.type==='team') ? ' 支队伍' : ' 名选手');
        countBadge.innerText = countText;

        let finalMatchups = [];
        if(data.matchups && data.matchups.length) {
            finalMatchups = data.matchups;
        } else {
            finalMatchups = buildMatchupFromOpponents(data.contestants);
        }
        if(finalMatchups.length > 0 && matchupsArea) {
            matchupsArea.style.display = 'block';
            matchupsListDiv.innerHTML = finalMatchups.map(m => `<div class="matchup-item">${escapeHtml(m)}</div>`).join('');
        } else if(matchupsArea) {
            matchupsArea.style.display = 'none';
        }

        if(data.contestants.length === 0) {
            rosterDiv.innerHTML = '<div style="text-align:center;color:#e6d5a8">暂无数据</div>';
            return;
        }

        let cards = '';
        for(let c of data.contestants) {
            let statusClass = getStatusClass(c.status);
            let statusShow = c.status || '—';
            let scoreDisplay = c.score !== '?' ? `<div class="arena-score">${c.type==='team' ? '🏅 团队 ' : '⚡ '}${escapeHtml(c.score)}</div>` : '';
            let extraHtml = c.extra ? `<div class="arena-stat-item">📋 ${escapeHtml(c.extra)}</div>` : '';
            let opponentHtml = c.opponent ? `<div class="arena-stat-item">🎯 对手: ${escapeHtml(c.opponent)}</div>` : '';
            let membersHtml = '';
            if(c.type === 'team' && c.members && c.members.length) {
                let memberTags = c.members.map(m => `<span class="arena-member-tag">👤 ${escapeHtml(m)}</span>`).join('');
                membersHtml = `<div class="arena-member-list">${memberTags}</div>`;
            }
            cards += `
                <div class="arena-card">
                    <div class="arena-status-dot ${statusClass}"></div>
                    <div class="arena-name">${c.type==='team' ? '🏢' : '🏅'} ${escapeHtml(c.name)}</div>
                    ${scoreDisplay}
                    <div class="arena-stats">
                        <div class="arena-stat-item">📌 状态: ${escapeHtml(statusShow)}</div>
                        ${opponentHtml}
                        ${extraHtml}
                    </div>
                    ${membersHtml}
                </div>
            `;
        }
        rosterDiv.innerHTML = cards;
    }

    function escapeHtml(str){ return String(str).replace(/[&<>]/g, function(m){if(m==='&')return '&amp;';if(m==='<')return '&lt;';if(m==='>')return '&gt;';return m;}); }

    function loadDataAndRender(){
        try{
            let msgs = getChatMessages(getCurrentMessageId());
            if(!msgs || msgs.length===0) return;
            let text = msgs[0].message;
            let parsed = parseTournament(text);
            renderUI(parsed);
        }catch(e){ console.warn('比赛面板解析错误',e); }
    }

    const header = document.getElementById('arenaHeader');
    const contentDiv = document.getElementById('arenaContent');
    const arrow = document.getElementById('arenaArrow');
    if(header && contentDiv) {
        header.addEventListener('click', (e) => {
            e.stopPropagation();
            if(contentDiv.classList.contains('show')) {
                contentDiv.classList.remove('show');
                arrow.style.transform = 'rotate(0deg)';
            } else {
                contentDiv.classList.add('show');
                arrow.style.transform = 'rotate(180deg)';
                loadDataAndRender();
                try{
                    let rect = header.getBoundingClientRect();
                    let div = document.createElement('div');
                    div.style.cssText = 'position:fixed;top:'+(rect.top+rect.height/2)+'px;left:'+(rect.left+rect.width/2)+'px;pointer-events:none;z-index:9999;font-size:28px;opacity:0.8;animation:float-glow 0.8s ease-out forwards;';
                    div.innerText = '✨';
                    document.body.appendChild(div);
                    setTimeout(()=>div.remove(), 800);
                }catch(e){}
            }
        });
    }
    $(function(){ loadDataAndRender(); });
})();
</script>
