                'grandcaster': '冠位魔术师 ✨ Grand Caster',
                'grandruler':  '冠位裁定者 ⚖️ Grand Ruler',
                'grandsaber':     '冠位剑士 🗡️ Grand Saber',
                'grandarcher':    '冠位弓兵 🏹 Grand Archer',
                'grandlancer':    '冠位枪兵 🛡️ Grand Lancer',
                'grandrider':     '冠位骑兵 🐴 Grand Rider',
                'grandassassin':  '冠位暗杀者 🗡️ Grand Assassin',
                'grandberserker': '冠位狂战士 💢 Grand Berserker',
            };

            function normalizeEnglishCapitalization(str) {
                if (!str) return str;
                return str.replace(/\b[A-Z]{2,}(?:\s+[A-Z]{2,})*\b/g, function(match) {
                    return match.split(/\s+/).map(function(word) {
                        if (word === word.toUpperCase() && /[A-Z]/.test(word)) {
                            return word.charAt(0).toUpperCase() + word.slice(1).toLowerCase();
                        }
                        return word;
                    }).join(' ');
