            function parseGrailData(rawText) {
                var match = rawText.match(/<圣杯战争>([\s\S]*?)<\/圣杯战争>/);
                if (!match) return null;
                var inner = match[1].trim();
                if (inner === '圣杯战争未开始' || inner.indexOf('圣杯战争未开始') !== -1) {
                    return { preWar: true };
                }
                var lines = inner.split(/\r?\n/).filter(function(l) { return l.trim() !== ''; });
                var masters = [];
                var newFormatRegex = /^(?:\[([^\]]+)\]|([^:]+)):\s*([^|]*?)\s*\|\s*令咒:\s*(\d+)\s*\|\s*从者:\s*([^(]+)\(([^)]+)\)\s*\|\s*([^|]*?)\s*$/;
                var oldFormatRegex = /^(?:\[([^\]]+)\]|([^:]+)):\s*([^|]*?)\s*\|\s*从者:\s*([^(]+)\(([^)]+)\)\s*\|\s*([^|]*?)\s*$/;

                for (var i = 0; i < lines.length; i++) {
