                        var old = line.match(oldFormatRegex);
                        if (old) {
                            data.masterName = (old[1] || old[2]).trim();
                            data.masterStatus = (old[3] || '').trim();
                            data.commandSpells = '?';
                            data.servantName = old[4].trim();
