                else if (data.masterStatus.indexOf('存活') !== -1) { masterStatusClass = 'alive'; masterStatusText = 'ALIVE'; }

                var commandHtml = renderCommandSpells(data.commandSpells);

                var classExtra = '';
                var raw = data.servantClassRaw;
                if (raw) {
                    if (raw.startsWith('grand')) {
                        var base = raw.substring(5);
                        classExtra = ' hgw-class-' + base + ' hgw-grand';
                    } else {
                        classExtra = ' hgw-class-' + raw;
                    }
                }

