                var englishHtml = '<span class="hgw-servant-class-en' + (raw && raw.startsWith('grand') ? ' hgw-grand' : '') + '">' + escapeHtml(classParts.english) + '</span>';
                var classHtml = prefixHtml + englishHtml;

                var servantStateClass = '';
                var servantStateText = data.servantStatus;
                if (servantStateText.indexOf('健在') !== -1) servantStateClass = 'state-healthy';
