                        '<div class="hgw-servant-class-wrapper">' + classHtml + '</div>' +
                        '<div class="hgw-servant-name">' + escapeHtml(data.servantName) + '</div>' +
                        '<div class="hgw-servant-state ' + servantStateClass + '">' + escapeHtml(servantStateText) + '</div>' +
                    '</div>' +
                '</div>';
