                    divd.style.display = 'none';
                } else {
                    body.classList.remove('collapsing');
                    body.classList.add('show');
                    arw.style.transform = 'rotate(180deg)';
                    hint.textContent = '封缄圣杯';
                    divd.style.display = 'block';
                    triggerGrailBurst(hdr);
                    loadContent();
                }
            });

            $(function(){ loadContent(); });
