    <script>
        (function() {
            const container = document.getElementById('worldpaperRoot');
            const themeBtn = document.getElementById('themeToggle');
            const currentTheme = localStorage.getItem('worldpaperTheme') || 'light';

            function setTheme(theme) {
                if (theme === 'dark') {
                    container.classList.add('theme-dark');
                    themeBtn.textContent = '☀️';
                } else {
                    container.classList.remove('theme-dark');
                    themeBtn.textContent = '🌙';
                }
            }
            setTheme(currentTheme);
            themeBtn.addEventListener('click', (e) => {
                e.stopPropagation();
                const isDark = container.classList.contains('theme-dark');
                const newTheme = isDark ? 'light' : 'dark';
                setTheme(newTheme);
                localStorage.setItem('worldpaperTheme', newTheme);
            });

            function escapeHtml(str) {
                return String(str).replace(/[&<>]/g, m => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;' })[m]);
            }

            function extractProgress(text) {
                let percent = 0;
                const barMatch = text.match(/\[([█░]+)\]/);
                if (barMatch) {
                    const bar = barMatch[1];
                    const filled = (bar.match(/█/g) || []).length;
                    percent = Math.round((filled / bar.length) * 100);
                }
                const pctMatch = text.match(/(\d+)\s*%/);
                if (pctMatch) percent = parseInt(pctMatch[1]);
                return Math.min(100, Math.max(0, percent));
            }

            function extractForceLevel(text) {
                const suppressMatch = text.match(/抑制力\s*(高|中|低)/);
                const pushMatch = text.match(/推动力\s*(高|中|低)/);
                return {
                    suppress: suppressMatch ? suppressMatch[1] : '?',
                    push: pushMatch ? pushMatch[1] : '?'
                };
            }

            function getStatusClass(status) {
                const s = String(status).trim();
                if (/萌芽|胚胎|embryo/i.test(s)) return 'status-embryo';
                if (/发展|developing|进行/i.test(s)) return 'status-developing';
                if (/临界|critical|变革|前夜/i.test(s)) return 'status-critical';
                return '';
            }

            function parseSubItems(text) {
                const lines = text.split('\n');
                const items = [];
                let currentItem = null;
                for (const line of lines) {
                    const trimmed = line.trim();
                    if (trimmed.startsWith('- ')) {
                        if (currentItem) items.push(currentItem);
                        currentItem = trimmed.substring(2).trim();
                    } else if (trimmed !== '' && currentItem !== null) {
                        currentItem += ' ' + trimmed;
                    }
                }
                if (currentItem) items.push(currentItem);
                return items;
            }

            function parseTradeSubItems(text) {
                return parseSubItems(text);
            }

            function formatSubItem(raw) {
                let html = '';
                const bracketMatch = raw.match(/^\[([^\]]+)\](.*)$/);
                if (bracketMatch) {
                    const name = bracketMatch[1];
                    const rest = bracketMatch[2].trim();
                    const dateMatch = rest.match(/^\(([^)]+)\)\s*:?\s*(.*)/);
                    if (dateMatch) {
                        html += `📖 <strong>${escapeHtml(name)}</strong> (${escapeHtml(dateMatch[1])})`;
                        if (dateMatch[2]) html += `: ${escapeHtml(dateMatch[2].substring(0, 180))}`;
                    } else {
                        html += `📖 <strong>${escapeHtml(name)}</strong>${rest ? ': ' + escapeHtml(rest.substring(0, 180)) : ''}`;
                    }
                } else {
                    const dateMatch = raw.match(/^\(([^)]+)\)\s*:?\s*(.*)/);
                    if (dateMatch) {
                        html += `📖 (${escapeHtml(dateMatch[1])})`;
                        if (dateMatch[2]) html += `: ${escapeHtml(dateMatch[2].substring(0, 180))}`;
                    } else {
                        html += `📖 ${escapeHtml(raw.substring(0, 180))}`;
                    }
                }
                return `<div class="sub-item-line">${html}</div>`;
            }

            function formatChainItem(raw, index) {
                let number = index + 1;
                let content = raw;
                const numMatch = raw.match(/^(\d+)\s*[\.\)]\s*/);
                if (numMatch) {
                    number = parseInt(numMatch[1]);
                    content = raw.substring(numMatch[0].length);
                }
                let formatted = '';
                const bracketMatch = content.match(/^\[([^\]]+)\](.*)$/);
                if (bracketMatch) {
                    const name = bracketMatch[1];
                    const rest = bracketMatch[2].trim();
                    const dateMatch = rest.match(/^\(([^)]+)\)\s*:?\s*(.*)/);
                    if (dateMatch) {
                        formatted = `<strong>${escapeHtml(name)}</strong> (${escapeHtml(dateMatch[1])})`;
                        if (dateMatch[2]) formatted += `: ${escapeHtml(dateMatch[2].substring(0, 180))}`;
                    } else {
                        formatted = `<strong>${escapeHtml(name)}</strong>${rest ? ': ' + escapeHtml(rest.substring(0, 180)) : ''}`;
                    }
                } else {
                    const dateMatch = content.match(/^\(([^)]+)\)\s*:?\s*(.*)/);
                    if (dateMatch) {
                        formatted = `(${escapeHtml(dateMatch[1])})`;
                        if (dateMatch[2]) formatted += `: ${escapeHtml(dateMatch[2].substring(0, 180))}`;
                    } else {
                        formatted = escapeHtml(content.substring(0, 180));
                    }
                }
                return `<div class="sub-item-line"><span style="font-weight:600;">${number}.</span> ${formatted}</div>`;
            }

            function parseWorldPaper(rawContent) {
                const data = {
                    datetimeStr: '',
                    eraSection: { mainHtml: '', potentialHtml: '', dynamicsHtml: '', chronicleHtml: '', stage: '' },
                    economySection: { mainHtml: '' }
                };
                const timeMatch = rawContent.match(/🕒时间:\s*(\d{4})年(\d{1,2})月(\d{1,2})日\/(\d{2}:\d{2})/);
                if (timeMatch) data.datetimeStr = `${timeMatch[1]}年${timeMatch[2]}月${timeMatch[3]}日 ${timeMatch[4]}`;
                else {
                    const alt = rawContent.match(/时间:\s*(\d{4})年(\d{1,2})月(\d{1,2})日/);
                    data.datetimeStr = alt ? `${alt[1]}年${alt[2]}月${alt[3]}日` : '未知纪元';
                }
                const econSplit = rawContent.search(/# ---\s*💰\s*世界经济简报\s*---/);
                const eraRaw = econSplit !== -1 ? rawContent.substring(0, econSplit) : rawContent;
                const econRaw = econSplit !== -1 ? rawContent.substring(econSplit) : '';
                data.eraSection = parseEraSection(eraRaw);
                data.economySection = parseEconomySection(econRaw);
                return data;
            }

            function parseEraSection(text) {
                const result = { mainHtml: '', potentialHtml: '', dynamicsHtml: '', chronicleHtml: '', stage: '' };
                const stageIdx = text.search(/\[🕰️世界时代阶段\]/);
                let stageBlock = '';
                if (stageIdx !== -1) {
                    const after = text.substring(stageIdx);
                    const next = after.match(/\n\[🌱\s*潜在时代演化\]|\n\[🌊世界时局演进动态\]|\n\[🍂\s*岁月史书/);
                    stageBlock = after.substring(0, next ? after.indexOf(next[0]) : after.length);
                } else {
                    stageBlock = text;
                }
                const stageMatch = stageBlock.match(/\[🕰️世界时代阶段\]:\s*(.+?)(?:\n|$)/);
                if (stageMatch) result.stage = stageMatch[1].trim();
                const fieldRegex = /^[-–]\s*\[([^\]]+)\]:\s*(.+)$/gm;
                let match;
                const fields = [];
                while ((match = fieldRegex.exec(stageBlock)) !== null) {
                    if (!/潜在时代|演进动态|岁月史书|已完结|事件链|转折点事件/i.test(match[1])) {
                        fields.push({ label: match[1], value: match[2] });
                    }
                }
                let mainHtml = '';
                if (result.stage) mainHtml += `<div class="era-badge-main"><span class="era-badge-dot"></span>🕰️ 当前时代 · ${escapeHtml(result.stage)}</div>`;
                if (fields.length) {
                    mainHtml += `<div class="era-feature-list">`;
                    const icons = {
                        '核心社会组织形式': '🏛️', '主流世界观/思潮': '💭', '主要经济模式': '⚙️',
                        '技术特征': '🔧', '主导性能源/动力': '⚡', '关键材料标志': '🔩',
                        '社会阶级结构': '👥', '生产力-生产关系矛盾': '⚖️', '世界秩序格局': '🗺️'
                    };
                    fields.forEach(f => {
                        mainHtml += `<div class="stat-item"><span class="stat-icon">${icons[f.label]||'📌'}</span><span class="stat-label">${escapeHtml(f.label)}:</span><span class="stat-value">${escapeHtml(f.value)}</span></div>`;
                    });
                    mainHtml += `</div>`;
                } else {
                    mainHtml += '<div style="color:var(--ink-light);padding:8px;">📜 时代特征数据待填充</div>';
                }
                result.mainHtml = mainHtml;
                const potMatch = text.match(/\[🌱\s*潜在时代演化\][\s\S]*?(?=\n\[🌊|\n#|---|$)/);
                if (potMatch) result.potentialHtml = parsePotentialEras(potMatch[0]);
                const dynMatch = text.match(/\[🌊世界时局演进动态\][\s\S]*?(?=\n\[🍂|\n#|---|$)/);
                if (dynMatch) result.dynamicsHtml = parseWorldDynamics(dynMatch[0]);
                const chrMatch = text.match(/\[🍂\s*岁月史书[^\]]*\][\s\S]*?(?=\n#|---|$)/);
                if (chrMatch) result.chronicleHtml = parseChronicle(chrMatch[0]);
                return result;
            }

            function parsePotentialEras(chunk) {
                let html = '<div class="sub-card"><div class="l3-toggle" data-l3-role="toggle"><span class="l3-arrow">▼</span><div class="sub-card-title">🌱 潜在时代演化</div></div><div class="l3-body open">';
                const lines = chunk.split('\n');
                let found = false;
                for (let i = 0; i < lines.length; i++) {
                    const line = lines[i];
                    const trimmed = line.trim();
                    if (!trimmed || trimmed.startsWith('└─')) continue;
                    const pm = line.match(/^(\s*)-\s*(?:\*{1,2}\([^)]*\)\*{1,2}\s*)?\[([^\]]+)\]:/);
                    if (!pm) continue;
                    const indent = pm[1].length;
                    const name = pm[2];
                    if (/已完结转折点事件影响/i.test(name)) continue;
                    found = true;
                    let parentRest = line.replace(/^(\s*)-\s*(?:\*{1,2}\([^)]*\)\*{1,2}\s*)?\[[^\]]+\]:\s*/, '') + '\n';
                    let j = i + 1;
                    while (j < lines.length) {
                        const nl = lines[j];
                        const nt = nl.trim();
                        if (nt === '') { parentRest += nl + '\n'; j++; continue; }
                        if (nt.startsWith('- [') && (nl.match(/^(\s*)/)[1].length <= indent)) break;
                        if (nt.startsWith('#') || nt.startsWith('[🌊') || nt.startsWith('[🍂')) break;
                        parentRest += nl + '\n';
                        j++;
                    }
                    i = j - 1;
                    const nameClean = name.replace(/\*{1,2}\([^)]*\)\*{1,2}/, '').trim();
                    const desc = (parentRest.match(/(.+?)(?:[|¦]\s*演化开始日期|\n|$)/) || ['', ''])[1].trim();
                    const startDate = (parentRest.match(/演化开始日期:\s*([^|¦\n]+)/) || [])[1] || '';
                    const progress = extractProgress(parentRest);
                    const status = (parentRest.match(/状态:\s*([^|¦\n]+)/) || [])[1] || '';
                    const push = (parentRest.match(/推动:\s*([^|¦\n]+)/) || [])[1] || '';
                    const inhibit = (parentRest.match(/抑制:\s*([^|¦\n]+)/) || [])[1] || '';
                    const impactRegex = /^(\s*)└─\s*\[已完结转折点事件影响\]:/m;
                    const impactMatch = parentRest.match(impactRegex);
                    let hasChildren = !!impactMatch, subBlock = '';
                    if (impactMatch) {
                        const impIndent = impactMatch[1].length;
                        const start = parentRest.indexOf(impactMatch[0]) + impactMatch[0].length;
                        const rem = parentRest.substring(start).split('\n');
                        let content = '';
                        for (let k = 0; k < rem.length; k++) {
                            if (rem[k].trim() === '') { content += rem[k] + '\n'; continue; }
                            if (rem[k].match(/^(\s*)/)[1].length <= impIndent) break;
                            content += rem[k] + '\n';
                        }
                        const items = parseSubItems(content);
                        subBlock = `<div class="sub-item-block l3-body open"><div class="sub-item-title">⚡ 已完结转折事件</div>${items.map(formatSubItem).join('')}</div>`;
                    }
                    html += `<div class="potential-era-group"><div class="sub-card l3-toggle${hasChildren?'':' no-children'}" data-l3-role="toggle" style="margin:0;border-radius:12px 12px ${hasChildren?'0 0':'12px 12px'};border-bottom:${hasChildren?'none':'1px solid var(--subcard-border)'};display:flex;flex-wrap:wrap;align-items:flex-start;gap:6px;">`;
                    if (hasChildren) html += '<span class="l3-arrow">▼</span>';
                    html += `<div style="flex:1;"><div style="display:flex;flex-wrap:wrap;align-items:center;gap:6px;"><strong style="color:var(--subcard-title);">📌 ${escapeHtml(nameClean)}</strong>${status?`<span class="tag ${getStatusClass(status)}">${escapeHtml(status)}</span>`:''}${startDate?`<span style="font-size:0.72rem;color:var(--ink-light);">📅始于 ${escapeHtml(startDate)}</span>`:''}</div>${desc?`<div style="font-size:0.82rem;color:var(--ink-mid);">${escapeHtml(desc)}</div>`:''}<div class="progress-container"><div class="progress-info-row"><span>演化进度</span><span>${progress}%</span></div><div class="progress-bar-bg"><div class="progress-fill ${getStatusClass(status)==='status-critical'?'critical':''}" style="width:${progress}%;"></div></div></div><div style="display:flex;gap:10px;font-size:0.73rem;color:var(--ink-mid);">${push?`<span>🚀 ${escapeHtml(push)}</span>`:''}${inhibit?`<span>🛡️ ${escapeHtml(inhibit)}</span>`:''}</div></div></div>${hasChildren?subBlock:''}</div>`;
                }
                if (!found) html += '<div style="color:var(--ink-light);padding:4px;">暂无显著演化趋势</div>';
                html += '</div></div>';
                return html;
            }

            function parseWorldDynamics(chunk) {
                let html = '<div class="sub-card"><div class="l3-toggle" data-l3-role="toggle"><span class="l3-arrow">▼</span><div class="sub-card-title">🌊 世界时局演进动态</div></div><div class="l3-body open">';
                const dr = chunk.match(/\[-\s*演进驱动力\]:\s*(.+)/);
                if (dr) html += `<div class="stat-item"><span class="stat-icon">🚀</span><span class="stat-label">演进驱动力:</span><span class="stat-value">${escapeHtml(dr[1])}</span></div>`;
                const gp = chunk.match(/时代差格局\]:\s*(.+)/);
                if (gp) html += `<div class="stat-item"><span class="stat-icon">⚖️</span><span class="stat-label">时代差格局:</span><span class="stat-value">${escapeHtml(gp[1])}</span></div>`;
                const tw = chunk.match(/潜在关键转折点\]:([\s\S]*)/);
                if (tw) html += `<div style="margin-top:8px;"><strong>⏳ 潜在关键转折点</strong>${parseTwistEvents(tw[1])}</div>`;
                html += '</div></div>';
                return html;
            }

            function parseTwistEvents(twistText) {
                const lines = twistText.split('\n');
                let html = '';
                let found = false;
                for (let i = 0; i < lines.length; i++) {
                    const line = lines[i];
                    const trimmed = line.trim();
                    if (!trimmed || trimmed.startsWith('└─')) continue;
                    const pm = line.match(/^(\s*)-\s*(?:\*{1,2}\([^)]*\)\*{1,2}\s*)?\[([^\]]+)\]:/);
                    if (!pm) continue;
                    const indent = pm[1].length;
                    const name = pm[2];
                    if (/事件链/i.test(name)) continue;
                    found = true;
                    const isCritical = /临界事件/.test(line);
                    let eraNameForCritical = '';
                    if (isCritical) {
                        const criticalMatch = line.match(/\*{0,2}\(([^)]*?)\)\*{0,2}/);
                        if (criticalMatch) eraNameForCritical = criticalMatch[1].trim();
                    }
                    let parentRest = line.replace(/^(\s*)-\s*(?:\*{1,2}\([^)]*\)\*{1,2}\s*)?\[[^\]]+\]:\s*/, '') + '\n';
                    let j = i + 1;
                    while (j < lines.length) {
                        const nl = lines[j];
                        const nt = nl.trim();
                        if (nt === '') { parentRest += nl + '\n'; j++; continue; }
                        if (nt.startsWith('- [') && (nl.match(/^(\s*)/)[1].length <= indent)) break;
                        if (nt.startsWith('#') || nt.startsWith('[🌊')) break;
                        parentRest += nl + '\n';
                        j++;
                    }
                    i = j - 1;
                    let nameClean = name.replace(/\*{1,2}\([^)]*\)\*{1,2}/, '').trim();
                    const desc = (parentRest.match(/(.+?)(?:[|¦]\s*开始日期|\n|$)/) || ['', ''])[1].trim();
                    const startDate = (parentRest.match(/开始日期:\s*([^|¦\n]+)/) || [])[1] || '';
                    const progress = extractProgress(parentRest);
                    const force = extractForceLevel(parentRest);
                    const overallImpact = (parentRest.match(/总体影响:\s*([^|¦\n]+)/) || [])[1] || '';
                    const chainRegex = /^(\s*)└─\s*\[事件链\]:/m;
                    const chainMatch = parentRest.match(chainRegex);
                    let hasChildren = !!chainMatch, chainBlock = '';
                    if (chainMatch) {
                        const chIndent = chainMatch[1].length;
                        const start = parentRest.indexOf(chainMatch[0]) + chainMatch[0].length;
                        const rem = parentRest.substring(start).split('\n');
                        let content = '';
                        for (let k = 0; k < rem.length; k++) {
                            if (rem[k].trim() === '') { content += rem[k] + '\n'; continue; }
                            if (rem[k].match(/^(\s*)/)[1].length <= chIndent) break;
                            content += rem[k] + '\n';
                        }
                        const items = parseSubItems(content);
                        chainBlock = `<div class="sub-item-block l3-body open"><div class="sub-item-title">🔗 事件链</div>${items.map((it,idx)=>formatChainItem(it,idx)).join('')}</div>`;
                    }
                    html += `<div class="twist-event-group"><div class="sub-card l3-toggle${hasChildren?'':' no-children'}" data-l3-role="toggle" style="margin:0;border-radius:12px 12px ${hasChildren?'0 0':'12px 12px'};border-bottom:${hasChildren?'none':'1px solid var(--subcard-border)'};${isCritical?'border:2px solid rgba(210,130,80,0.6);':''}display:flex;flex-wrap:wrap;align-items:flex-start;gap:6px;">`;
                    if (hasChildren) html += '<span class="l3-arrow">▼</span>';
                    html += `<div style="flex:1;"><div style="display:flex;flex-wrap:wrap;align-items:center;gap:6px;">${isCritical ? `<span class="tag status-critical">⚠ ${eraNameForCritical || '临界事件'}</span>` : ''}<strong>📌 ${escapeHtml(nameClean)}</strong>${startDate?`<span style="font-size:0.72rem;color:var(--ink-light);">📅始于 ${escapeHtml(startDate)}</span>`:''}</div>${desc?`<div style="font-size:0.8rem;color:var(--ink-mid);">${escapeHtml(desc)}</div>`:''}<div class="progress-container"><div class="progress-info-row"><span>事件进度</span><span>${progress}%</span></div><div class="progress-bar-bg"><div class="progress-fill ${isCritical?'critical':''}" style="width:${progress}%;"></div></div></div><div style="display:flex;gap:8px;font-size:0.73rem;">🛡️ <strong>${force.suppress}</strong> 🚀 <strong>${force.push}</strong> ${overallImpact?`📊 ${escapeHtml(overallImpact)}`:''}</div></div></div>${hasChildren?chainBlock:''}</div>`;
                }
                if (!found) return '<div style="color:var(--ink-light);padding:4px;">暂无潜在转折点</div>';
                return html;
            }

            function parseChronicle(chunk) {
                let html = '<div class="sub-card"><div class="l3-toggle" data-l3-role="toggle"><span class="l3-arrow">▼</span><div class="sub-card-title">🍂 岁月史书</div></div><div class="l3-body open">';
                const entries = parseSubItems(chunk);
                let found = false;
                for (const entry of entries) {
                    if (/岁月史书|始于/i.test(entry)) continue;
                    let name = '', rest = entry;
                    const bm = entry.match(/^\[([^\]]+)\]/);
                    if (bm) {
                        name = bm[1].trim();
                        rest = entry.substring(bm[0].length).replace(/^[:：]\s*/, '');
                    } else {
                        const ci = entry.search(/[:：]/);
                        if (ci !== -1) { name = entry.substring(0, ci).trim(); rest = entry.substring(ci + 1).trim(); }
                        else { name = entry.trim(); rest = ''; }
                    }
                    if (!name) continue;
                    found = true;
                    const outcome = (rest.match(/最终结局:\s*([^|¦]+)/) || [])[1] || '';
                    const dateRange = (rest.match(/演化起止:\s*([^|¦]+)/) || [])[1] || '';
                    const desc = (rest.match(/[\|¦]\s*([^|¦]+?)\s*[\|¦]/) || [])[1] || '';
                    const turning = (rest.match(/关键转折:\s*([^|¦]+)/) || [])[1] || '';
                    const impact = (rest.match(/历史影响:\s*([^|¦\n]+)/) || [])[1] || '';
                    html += `<div class="timeline-node ${/成功|定鼎/i.test(outcome)?'event-completed':''}"><strong>📖 ${escapeHtml(name)}</strong> <span style="font-size:0.72rem;color:var(--ink-light);">${escapeHtml(dateRange)}</span>${outcome?`<span class="tag">${escapeHtml(outcome)}</span>`:''}${desc?`<div style="font-size:0.78rem;color:var(--ink-mid);">${escapeHtml(desc)}</div>`:''}${turning?`<div style="font-size:0.73rem;">🔑 ${escapeHtml(turning)}</div>`:''}${impact?`<div style="font-size:0.73rem;">📜 ${escapeHtml(impact)}</div>`:''}</div>`;
                }
                if (!found) html += '<div style="color:var(--ink-light);">暂无记录</div>';
                html += '</div></div>';
                return html;
            }

            function parseEconomySection(econText) {
                if (!econText || econText.trim().length < 20) return { mainHtml: '<div style="color:var(--ink-light);padding:8px;">⛔ 本期无经济详报</div>' };
                let html = '';
                const climateMatch = econText.match(/\[世界经济气候\]:([\s\S]*?)(?=\n\[大宗商品|\n\[货币|\n\[贸易|\n\[经济事件|$)/);
                if (climateMatch) {
                    html += '<div class="sub-card"><div class="l3-toggle" data-l3-role="toggle"><span class="l3-arrow">▼</span><div class="sub-card-title">🌡️ 世界经济气候</div></div><div class="l3-body open">';
                    const cText = climateMatch[1];
                    const phase = (cText.match(/整体周期相位\]:\s*(.+)/) || [])[1] || '';
                    let regionHtml = '';
                    const regionStart = cText.indexOf('[主要贸易区状态]:');
                    if (regionStart !== -1) {
                        const regionText = cText.substring(regionStart + '[主要贸易区状态]:'.length);
                        const regions = parseSubItems(regionText);
                        if (regions.length) {
                            regionHtml = '<div class="trade-regions-grid">';
                            regions.forEach(item => {
                                let name = '', status = '', industry = '';
                                const bm = item.match(/^\[([^\]]+)\]:\s*\[([^\]]+)\],\s*\[([^\]]+)\]/);
                                if (bm) { name = bm[1]; status = bm[2]; industry = bm[3]; }
                                else {
                                    const ci = item.indexOf(':');
                                    if (ci !== -1) {
                                        name = item.substring(0, ci).trim();
                                        const rest = item.substring(ci + 1).trim();
                                        const parts = rest.split(/[,，]/);
                                        if (parts.length >= 2) {
                                            status = parts[0].replace(/[[\]]/g, '').trim();
                                            industry = parts[1].replace(/[[\]]/g, '').trim();
                                        } else { status = rest.replace(/[[\]]/g, '').trim(); }
                                    } else { name = item.trim(); }
                                }
                                if (name) regionHtml += `<div class="region-card"><span class="region-name">${escapeHtml(name)}</span><span class="region-status">${escapeHtml(status)}</span><span class="region-industry">${escapeHtml(industry)}</span></div>`;
                            });
                            regionHtml += '</div>';
                        }
                    }
                    html += `<div class="climate-phase-wrap">${phase?`<div class="stat-item"><span class="stat-icon">📊</span><span class="stat-label">周期相位:</span><span class="stat-value">${escapeHtml(phase)}</span></div>`:''}${regionHtml?`<div style="margin-top:6px;"><span style="font-weight:700;">🌐 主要贸易区状态</span>${regionHtml}</div>`:''}</div></div></div>`;
                }

                const commMatch = econText.match(/\[大宗商品市场\]:([\s\S]*?)(?=\n\[货币|\n\[贸易|\n\[经济事件|$)/);
                if (commMatch) {
                    html += '<div class="sub-card"><div class="l3-toggle" data-l3-role="toggle"><span class="l3-arrow">▼</span><div class="sub-card-title">📦 大宗商品市场</div></div><div class="l3-body open">';
                    const commItems = parseSubItems(commMatch[1]);
                    commItems.forEach(item => {
                        let name = '', value = '';
                        const bm = item.match(/^\[([^\]]+)\]\s*:?\s*(.*)/);
                        if (bm) { name = bm[1]; value = bm[2]; }
                        else {
                            const ci = item.indexOf(':');
                            if (ci !== -1) { name = item.substring(0, ci).trim(); value = item.substring(ci + 1).trim(); }
                            else { name = item; value = ''; }
                        }
                        if (name) {
                            let cls = '';
                            if (/粮|谷物/i.test(name)) cls = 'commodity-grain';
                            else if (/矿|矿产/i.test(name)) cls = 'commodity-mineral';
                            else if (/能|能源/i.test(name)) cls = 'commodity-energy';
                            const trendCls = /↑/.test(value) ? 'trend-up' : (/↓/.test(value) ? 'trend-down' : 'trend-flat');
                            html += `<div class="commodity-card ${cls}"><div class="commodity-icon">${cls==='commodity-grain'?'🌾':(cls==='commodity-mineral'?'⛏️':(cls==='commodity-energy'?'⚡':'📦'))}</div><div class="commodity-info"><span class="commodity-name">${escapeHtml(name)}</span><span class="commodity-value"><span class="trend ${trendCls}">${escapeHtml(value)}</span></span></div></div>`;
                        }
                    });
                    html += '</div></div>';
                }

                const curMatch = econText.match(/\[货币与金融\]:([\s\S]*?)(?=\n\[投机|\n\[贸易|\n\[经济事件|$)/);
                if (curMatch) {
                    html += '<div class="sub-card"><div class="l3-toggle" data-l3-role="toggle"><span class="l3-arrow">▼</span><div class="sub-card-title">💰 货币与金融</div></div><div class="l3-body open">';
                    const curText = curMatch[1];
                    const vol = (curText.match(/综合汇率波动率:\s*([^,，\n]+)/) || [])[1];
                    const credit = (curText.match(/信贷环境\]:\s*([^|¦\n]+)/) || [])[1];
                    const base = (curText.match(/\*{2}基准货币\*{2}:\s*\[([^\]]+)\]/) || [])[1];
                    if (base || vol || credit) {
                        html += `<div class="base-currency-highlight">`;
                        if (base) html += `<div class="base-row-main"><span class="base-currency-icon">🏦</span><span>基准货币: <strong>${escapeHtml(base)}</strong></span></div>`;
                        if (vol) html += `<div class="base-row-sub"><span class="sub-dot"></span><span>📈 综合汇率波动率: <strong>${escapeHtml(vol)}</strong></span></div>`;
                        if (credit) html += `<div class="base-row-sub"><span class="sub-dot"></span><span>💳 信贷环境: <strong>${escapeHtml(credit)}</strong></span></div>`;
                        html += `</div>`;
                    }
                    html += '<div class="currency-table-grid">';
                    const curBlocks = curText.split(/\n\s*-\s*\*{2}/);
                    for (let i = 1; i < curBlocks.length; i++) {
                        const cb = '**' + curBlocks[i];
                        const cName = (cb.match(/^\*{2}([^*]+)\*{2}/) || [])[1] || '';
                        if (!cName || /主要货币|多币种|基准货币/i.test(cName)) continue;
                        if (/汇率波动指数/i.test(cName)) continue;
                        const rate = (cb.match(/兑基准货币:\s*\*{2}([^*]+)\*{2}/) || [])[1] || '—';
                        const prev = (cb.match(/上期:\s*([^,，)]+)/) || [])[1] || '';
                        const change = (cb.match(/涨跌:\s*([↑↓→][^)]+)/) || [])[1] || '';
                        const trendCls = /↑/.test(change) ? 'trend-up' : (/↓/.test(change) ? 'trend-down' : 'trend-flat');
                        const sentiment = (cb.match(/市场情绪:\s*([^|¦\n]+)/) || [])[1] || '';
                        const sentCls = /看涨|bullish/i.test(sentiment) ? 'sentiment-bullish' : (/看跌|bearish/i.test(sentiment) ? 'sentiment-bearish' : 'sentiment-neutral');
                        const driver = (cb.match(/驱动因素:\s*([^|¦\n]+)/) || [])[1] || '';
                        html += `<div class="currency-card">`;
                        html += `<div class="currency-name">💱 ${escapeHtml(cName)}</div>`;
                        html += `<div class="currency-rate">${escapeHtml(rate)}</div>`;
                        if (change) html += `<div class="currency-change ${trendCls}">${escapeHtml(change)}</div>`;
                        if (prev) html += `<div class="currency-prev-row"><span>上期</span><span class="prev-num">${escapeHtml(prev)}</span></div>`;
                        if (sentiment) html += `<span class="currency-sentiment ${sentCls}">${escapeHtml(sentiment)}</span>`;
                        if (driver) html += `<div class="currency-driver-row"><span class="driver-label">📌</span><span class="driver-value">${escapeHtml(driver)}</span></div>`;
                        html += `</div>`;
                    }
                    html += '</div></div></div>';
                }

                // 投机市场（已修复标的子项解析）
                const specMatch = econText.match(/\[投机市场\]:([\s\S]*?)(?=\n\[贸易|\n\[经济事件|$)/);
                if (specMatch) {
                    html += '<div class="sub-card"><div class="l3-toggle" data-l3-role="toggle"><span class="l3-arrow">▼</span><div class="sub-card-title">📈 投机市场</div></div><div class="l3-body open">';
                    const specText = specMatch[1];
                    const sentimentRaw = (specText.match(/市场整体情绪\]:\s*([^\n]+)/) || [])[1] || '';
                    let sentClass = '';
                    if (/狂热|euphoria/i.test(sentimentRaw)) sentClass = 'spec-sentiment-euphoria';
                    else if (/乐观|optimistic/i.test(sentimentRaw)) sentClass = 'spec-sentiment-optimistic';
                    else if (/谨慎|cautious/i.test(sentimentRaw)) sentClass = 'spec-sentiment-cautious';
                    else if (/恐慌|panic/i.test(sentimentRaw)) sentClass = 'spec-sentiment-panic';
                    else if (/萧条|depression/i.test(sentimentRaw)) sentClass = 'spec-sentiment-depression';
                    if (sentimentRaw) html += `<div class="spec-sentiment-badge ${sentClass}">🎭 市场情绪：${escapeHtml(sentimentRaw)}</div>`;

                    const stockSection = specText.match(/\[主要交易标的\]:([\s\S]*?)(?=\n\s*-?\s*\[期货合约\]|\n\s*-?\s*\[投机指数\]|$)/);
                    if (stockSection) {
                        const lines = stockSection[1].split('\n');
                        const stockBlocks = [];
                        let currentBlock = null;
                        const TOP_INDENT = 2;
                        for (const line of lines) {
                            if (line.trim() === '') continue;
                            if (/^\s*-?\s*\[期货合约\]/.test(line) || /^\s*-?\s*\[投机指数\]/.test(line)) break;
                            const leadingSpaces = line.match(/^(\s*)/)[1].length;
                            const trimmed = line.trim();
                            if (trimmed.startsWith('- ') && leadingSpaces <= TOP_INDENT + 1) {
                                if (currentBlock) stockBlocks.push(currentBlock);
                                currentBlock = { header: trimmed.substring(2).trim(), details: [] };
                            } else if (currentBlock) {
                                currentBlock.details.push(trimmed);
                            }
                        }
                        if (currentBlock) stockBlocks.push(currentBlock);

                        if (stockBlocks.length) {
                            html += '<div class="spec-stock-grid">';
                            stockBlocks.forEach(block => {
                                const headMatch = block.header.match(/^([^(]+)\s*\(([^)]+)\)\s*:?\s*(.*)/);
                                let name = '', type = '', detailStr = '';
                                if (headMatch) {
                                    name = headMatch[1].trim();
                                    type = headMatch[2].trim();
                                    detailStr = headMatch[3];
                                } else {
                                    name = block.header.split(':')[0] || block.header;
                                }
                                const allDetailLines = [detailStr, ...block.details].filter(Boolean);
                                const fullDetail = allDetailLines.join(' ');
                                const price = (fullDetail.match(/当前价格:\s*([^(\n]+)/) || [])[1]?.trim() || '';
                                const prev = (fullDetail.match(/上期:\s*([^)\n]+)/) || [])[1]?.trim() || '';
                                const change = (fullDetail.match(/涨跌:\s*([↑↓→]\s*[+-]?\d+(?:\.\d+)?%?)/) || [])[1]?.trim() || '';
                                const heat = (fullDetail.match(/交易热度:\s*([^(\n]+)/) || [])[1]?.trim() || '';
                                const volume = (fullDetail.match(/量能:\s*([^)\n]+)/) || [])[1]?.trim() || '';
                                const driver = (fullDetail.match(/驱动事件:\s*([^\n]+)/) || [])[1]?.trim() || '';
                                const changeCls = /↑/.test(change) ? 'trend-up' : (/↓/.test(change) ? 'trend-down' : 'trend-flat');
                                html += `<div class="spec-stock-card">`;
                                html += `<div class="spec-stock-name">📊 ${escapeHtml(name)}</div>`;
                                if (type) html += `<div class="spec-stock-type">${escapeHtml(type)}</div>`;
                                if (price) html += `<div class="spec-stock-price">${escapeHtml(price)}</div>`;
                                if (change) html += `<div class="spec-stock-change ${changeCls}">${escapeHtml(change)}</div>`;
                                if (prev) html += `<div class="spec-stock-prev">上期 ${escapeHtml(prev)}</div>`;
                                if (heat || volume) html += `<div class="spec-stock-heat">🔥 ${escapeHtml(heat)} ${volume ? '· '+escapeHtml(volume) : ''}</div>`;
                                if (driver) html += `<div class="spec-stock-driver">📌 ${escapeHtml(driver)}</div>`;
                                html += `</div>`;
                            });
                            html += '</div>';
                        }
                    }

                    const futuresSection = specText.match(/\[期货合约\]:([\s\S]*?)(?=\[投机指数\]|$)/);
                    if (futuresSection) {
                        const futuresItems = parseSubItems(futuresSection[1]);
                        if (futuresItems.length) {
                            html += '<div class="spec-futures-list">';
                            futuresItems.forEach(item => {
                                const ci = item.indexOf(':');
                                let name = '', detail = '';
                                if (ci !== -1) { name = item.substring(0, ci).trim(); detail = item.substring(ci+1).trim(); }
                                else { name = item; detail = ''; }
                                html += `<div class="spec-futures-item"><span>📦 ${escapeHtml(name)}</span> ${escapeHtml(detail)}</div>`;
                            });
                            html += '</div>';
                        }
                    }

                    const indexMatch = specText.match(/\[投机指数\]:\s*([\s\S]*)$/);
                    if (indexMatch) {
                        const indexRaw = indexMatch[1].trim();
                        const valMatch = indexRaw.match(/报\s*([\d,.]+)/);
                        const changeMatch = indexRaw.match(/周涨跌\s*([↑↓→]?\s*[\d,.]+%?)/);
                        html += `<div class="spec-index-box"><span>📉 投机指数</span><span class="spec-index-value">${valMatch ? escapeHtml(valMatch[1]) : '—'}</span>${changeMatch ? `<span class="spec-index-change ${/↑/.test(changeMatch[1])?'trend-up':(/↓/.test(changeMatch[1])?'trend-down':'trend-flat')}">${escapeHtml(changeMatch[1])}</span>` : ''}</div>`;
                    }
                    html += '</div></div>';
                }

                const tradeMatch = econText.match(/\[贸易格局\]:([\s\S]*?)(?=\n\[经济事件|$)/);
                if (tradeMatch) {
                    html += '<div class="sub-card"><div class="l3-toggle" data-l3-role="toggle"><span class="l3-arrow">▼</span><div class="sub-card-title">🌐 贸易格局</div></div><div class="l3-body open">';
                    const tradeText = tradeMatch[1];
                    const routeMatch = tradeText.match(/\[主要商路\]:([\s\S]*?)(?=\n\s*-\s*\[贸易政策\]|$)/);
                    if (routeMatch) {
                        html += '<div style="margin:8px 0 0 8px;"><span style="font-weight:700;">🗺️ 主要商路</span></div>';
                        parseTradeSubItems(routeMatch[1]).forEach(item => {
                            let icon = '🛤️';
                            const t = item.toLowerCase();
                            if (/海|航路/i.test(t)) icon = '🚢';
                            else if (/陆|驼/i.test(t)) icon = '🐫';
                            else if (/空|飞艇/i.test(t)) icon = '✈️';
                            html += `<div class="stat-item"><span class="stat-icon">${icon}</span><span class="stat-value">${escapeHtml(item.substring(0,180))}</span></div>`;
                        });
                    }
                    const policyMatch = tradeText.match(/\[贸易政策\]:([\s\S]*?)$/);
                    if (policyMatch) {
                        html += '<div style="margin:8px 0 0 8px;"><span style="font-weight:700;">📜 贸易政策</span></div>';
                        parseTradeSubItems(policyMatch[1]).forEach(item => {
                            html += `<div class="stat-item"><span class="stat-icon">📋</span><span class="stat-value">${escapeHtml(item.substring(0,180))}</span></div>`;
                        });
                    }
                    html += '</div></div>';
                }

                const evMatch = econText.match(/\[经济事件\]:([\s\S]*?)$/);
                if (evMatch) {
                    html += '<div class="sub-card"><div class="l3-toggle" data-l3-role="toggle"><span class="l3-arrow">▼</span><div class="sub-card-title">📰 经济事件</div></div><div class="l3-body open">';
                    parseSubItems(evMatch[1]).forEach(item => {
                        let name = '', rest = item;
                        const bm = item.match(/^\[([^\]]+)\]/);
                        if (bm) {
                            name = bm[1].trim();
                            rest = item.substring(bm[0].length).replace(/^[:：]\s*/, '');
                        } else {
                            const ci = item.search(/[:：]/);
                            if (ci !== -1) { name = item.substring(0, ci).trim(); rest = item.substring(ci + 1).trim(); }
                            else { name = ''; rest = item; }
                        }
                        if (!name) return;
                        const dim = (rest.match(/影响维度:\s*([^|¦]+)/) || [])[1] || '';
                        const status = (rest.match(/当前态势:\s*([^|¦\n]+)/) || [])[1] || '';
                        let desc = rest.replace(/影响维度:\s*[^|¦]+\|?\s*/, '').replace(/当前态势:\s*[^|¦\n]+\s*/, '').replace(/^\s*\|?\s*/, '').trim();
                        // ★ 修复：彻底移除残留的分隔符
                        desc = desc.replace(/[|¦]/g, '').trim();
                        let statusClass = '';
                        if (/恶化|危机|崩溃/i.test(status)) statusClass = 'status-critical';
                        else if (/转折|恢复|改善|好转/i.test(status)) statusClass = 'status-developing';
                        html += `<div class="timeline-node"><strong>📰 ${escapeHtml(name)}</strong>${desc?`<div style="font-size:0.78rem;color:var(--ink-mid);">${escapeHtml(desc)}</div>`:''}<div style="display:flex;gap:4px;margin-top:3px;">${dim?`<span class="tag">📊 ${escapeHtml(dim)}</span>`:''}${status?`<span class="tag ${statusClass}">${escapeHtml(status)}</span>`:''}</div></div>`;
                    });
                    html += '</div></div>';
                }
                return { mainHtml: html || '<div style="color:var(--ink-light);">📉 本期无经济详报</div>' };
            }

            function setupL3ToggleDelegation() {
                const inner = document.getElementById('dynamicContent');
                if (!inner) return;
                if (inner._l3ClickHandler) inner.removeEventListener('click', inner._l3ClickHandler);
                const handler = function(e) {
                    const toggle = e.target.closest('[data-l3-role="toggle"]');
                    if (!toggle) return;
                    let body = null;
                    const pg = toggle.closest('.potential-era-group, .twist-event-group');
                    if (pg) body = pg.querySelector(':scope > .l3-body');
                    else {
                        const sc = toggle.closest('.sub-card');
                        if (sc) body = sc.querySelector(':scope > .l3-body');
                    }
                    if (!body) return;
                    const arrow = toggle.querySelector('.l3-arrow');
                    const isOpen = body.classList.contains('open');
                    if (isOpen) {
                        body.classList.remove('open');
                        if (arrow) arrow.classList.add('collapsed');
                    } else {
                        body.classList.add('open');
                        if (arrow) arrow.classList.remove('collapsed');
                    }
                    e.stopPropagation();
                };
                inner._l3ClickHandler = handler;
                inner.addEventListener('click', handler);
            }

            function renderWorldPaper() {
                try {
                    const containerEl = document.getElementById('dynamicContent');
                    const dateSpan = document.getElementById('briefDatetime');
                    if (!containerEl) return;
                    const rawDataArea = document.getElementById('rawWorldPaperData');
                    let msgText = rawDataArea ? rawDataArea.value : '';
                    if (!msgText || msgText.trim() === '') {
                        containerEl.innerHTML = '<div style="padding:20px;color:var(--ink-light);">📜 没有可用的世界时局数据</div>';
                        if (dateSpan) dateSpan.innerText = '无数据';
                        return;
                    }
                    const worldMatch = msgText.match(/<WorldPaper[^>]*>([\s\S]*?)<\/WorldPaper>/);
                    if (!worldMatch) {
                        containerEl.innerHTML = '<div style="padding:20px;color:#e07060;">⚠️ 未检测到有效的WorldPaper标签</div>';
                        if (dateSpan) dateSpan.innerText = '格式错误';
                        return;
                    }
                    const parsed = parseWorldPaper(worldMatch[1]);
                    if (dateSpan) dateSpan.innerText = '🕰️ ' + (parsed.eraSection.stage || '未知时代');
                    containerEl.innerHTML = `<div class="section-card"><div class="section-header" data-section="eraToggle"><span class="section-header-icon">👑</span><span class="section-header-text">时代快讯<span class="section-badge">ERA</span></span><span class="section-arrow" id="eraArrow">▼</span></div><div class="section-content" id="eraContent">${parsed.eraSection.mainHtml}${parsed.eraSection.potentialHtml}${parsed.eraSection.dynamicsHtml}${parsed.eraSection.chronicleHtml}</div></div><div class="section-card"><div class="section-header" data-section="econToggle"><span class="section-header-icon">💰</span><span class="section-header-text">世界经济简报<span class="section-badge">ECONOMY</span></span><span class="section-arrow" id="econArrow">▼</span></div><div class="section-content" id="econContent">${parsed.economySection.mainHtml||'<div style="color:var(--ink-light);">📉 本期无经济详报</div>'}</div></div>`;
                    setupSectionToggle('eraToggle', 'eraContent', 'eraArrow');
                    setupSectionToggle('econToggle', 'econContent', 'econArrow');
                    setupL3ToggleDelegation();
                } catch (e) {
                    console.error(e);
                    const containerEl = document.getElementById('dynamicContent');
                    if (containerEl) containerEl.innerHTML = '<div style="color:#e07060;">渲染出错，请检查控制台</div>';
                }
            }

            function setupSectionToggle(attr, contentId, arrowId) {
                const header = document.querySelector(`[data-section="${attr}"]`);
                const content = document.getElementById(contentId);
                const arrow = document.getElementById(arrowId);
                if (header && content && arrow) {
                    header.addEventListener('click', (e) => {
                        e.stopPropagation();
                        const isOpen = content.classList.contains('open');
                        content.classList.toggle('open');
                        arrow.style.transform = isOpen ? 'rotate(0deg)' : 'rotate(180deg)';
                    });
                }
            }

            const globalBody = document.getElementById('worldpaperBody');
            const globalHeader = document.getElementById('globalHeader');
            const globalArrow = document.getElementById('globalArrow');
            const globalHint = document.getElementById('globalHint');
            if (globalHeader && globalBody) {
                globalHeader.addEventListener('click', () => {
                    const isShow = globalBody.classList.contains('show');
                    if (isShow) {
                        globalBody.classList.remove('show');
                        globalArrow.style.transform = 'rotate(0deg)';
                        globalHint.innerText = '展开卷宗';
                    } else {
                        globalBody.classList.add('show');
                        globalArrow.style.transform = 'rotate(180deg)';
                        globalHint.innerText = '合上卷轴';
                        if (!document.getElementById('dynamicContent')?.querySelector('.section-card')) renderWorldPaper();
                    }
                });
            }
        })();
    </script>
</body>
</html>
