        .wealth-welloff { background:rgba(120,170,180,0.2); color:#78a8b4; border:1px solid rgba(120,170,180,0.35); }
        .wealth-rich { background:rgba(180,160,100,0.25); color:#d4c070; border:1px solid rgba(200,170,100,0.5); box-shadow:0 0 6px rgba(200,170,100,0.15); }
        .npc-status-row { font-family:var(--font-mono); font-size:0.65rem; color:var(--text-secondary); display:flex; flex-wrap:wrap; gap:2px 6px; position:relative; z-index:1; line-height:1.4; }
        .npc-status-dot { color:var(--accent-sky); font-weight:700; }
        .npc-chain-section { background:rgba(30,26,50,0.5); border-radius:var(--radius-sm); padding:6px 10px; position:relative; z-index:1; border-left:3px solid var(--accent-lavender); }
        .theme-light .npc-chain-section { background:rgba(235,228,215,0.5); border-left-color:rgba(130,100,60,0.5); }
        .chain-label { font-size:0.6rem; font-weight:700; letter-spacing:0.8px; color:var(--accent-lavender); text-transform:uppercase; margin-bottom:3px; font-family:var(--font-mono); }
        .chain-flow { display:flex; flex-wrap:wrap; align-items:center; gap:3px; font-size:0.68rem; color:var(--text-secondary); line-height:1.5; }

        /* 修复1：行为链步骤允许换行 */
        .chain-step {
            background: rgba(180,150,220,0.12);
            padding: 2px 6px;
            border-radius: 5px;
            font-weight: 500;
            white-space: normal;      /* 允许正常换行 */
            word-break: break-word;   /* 长单词/连续字符强制断行 */
            min-width: 0;             /* flex子元素可收缩 */
            font-size: 0.65rem;
        }

        .chain-arrow { color:var(--accent-gold); font-weight:700; flex-shrink:0; font-size:0.7rem; }

        /* 修复2：预测文本同样允许换行 */
        .chain-predict {
            color: var(--accent-rose);
            font-weight: 600;
            font-style: italic;
            font-size: 0.65rem;
            word-break: break-word;
            min-width: 0;
        }

        .chain-debut-tag { background:rgba(220,150,120,0.25); color:#f0b090; padding:2px 6px; border-radius:5px; font-weight:700; font-size:0.6rem; letter-spacing:0.3px; animation:pulseTag 2s ease-in-out infinite; white-space:nowrap; }
        @keyframes pulseTag { 0%,100% { box-shadow:0 0 0 0 rgba(220,150,120,0.5); } 50% { box-shadow:0 0 0 6px rgba(220,150,120,0); } }
        .npc-info-row { display:flex; flex-wrap:wrap; gap:2px 5px; font-size:0.68rem; color:var(--text-secondary); position:relative; z-index:1; line-height:1.5; }
        .npc-info-label { font-weight:700; color:var(--accent-sky); white-space:nowrap; font-size:0.63rem; letter-spacing:0.3px; }
        .npc-info-value { color:var(--text-primary); word-break:break-word; }
        .npc-memory-tags { display:flex; flex-wrap:wrap; gap:3px; position:relative; z-index:1; }
        .memory-tag { font-size:0.62rem; background:rgba(160,140,200,0.12); border:1px solid rgba(160,140,200,0.25); padding:2px 6px; border-radius:8px; color:var(--text-secondary); line-height:1.4; max-width:100%; word-break:break-word; transition:all 0.2s; }
        .memory-tag:hover { background:rgba(180,150,220,0.2); border-color:rgba(180,150,220,0.4); color:var(--text-primary); }
        .footer-line { text-align:center; font-size:7px; color:var(--text-muted); border-top:1px solid var(--border-subtle); margin-top:12px; padding-top:8px; font-family:var(--font-mono); letter-spacing:1.5px; }

        /* 移动端适配 */
        @media (max-width:640px) {
            .npc-grid { grid-template-columns:1fr; gap:8px; }
            .chronicle-inner { padding:10px 10px 12px 10px; }
            .panel-content.open { padding:8px 10px 12px 10px; }
            .chronicle-header { padding:7px 10px; gap:6px; }
            .header-title { font-size:13px; }
            .header-time-badge { font-size:8px; padding:2px 8px; }
            .header-icon-main { font-size:18px; }
            .toggle-badge { font-size:7px; padding:2px 6px; }
            .panel-header { padding:7px 10px 7px 12px; font-size:12px; min-height:36px; }
            .npc-card { padding:10px 12px; gap:5px; }
            .npc-avatar { width:30px; height:30px; font-size:15px; }
            .npc-name { font-size:0.85rem; }
            .npc-chain-section { padding:5px 8px; }
            .chain-flow { font-size:0.64rem; }

            /* 移动端步骤允许换行 */
            .chain-step {
                font-size: 0.62rem;
                padding: 2px 4px;
                white-space: normal;
                word-break: break-word;
                min-width: 0;
            }
            .chain-predict {
                word-break: break-word;
                min-width: 0;
            }
            .chain-arrow { font-size:0.6rem; }
            .npc-info-row { font-size:0.64rem; }
            .memory-tag { font-size:0.58rem; padding:2px 5px; }

            /* +++ 手机端：标题与时间分行显示 (不缩小字体) +++ */
            .chronicle-header {
                flex-wrap: wrap;
                row-gap: 6px;
            }
            .header-time-badge {
                flex-basis: 100%;
                width: 100%;
                margin-left: 0;
                margin-top: 6px;
                text-align: left;
                white-space: normal;
                word-break: break-word;
                background: rgba(255,255,255,0.03);
                border: 1px solid rgba(180,150,220,0.25);
                padding: 4px 10px;
                border-radius: 20px;
                order: 10;
                font-size: 9px;   /* 保持原字体大小 */
            }
            .header-title-area {
                flex: 1;
                min-width: 0;
            }
            .header-title {
                white-space: nowrap;
                overflow-x: auto;
                overflow-y: hidden;
                scrollbar-width: none;
                -webkit-overflow-scrolling: touch;
            }
            .header-title::-webkit-scrollbar {
                display: none;
            }
        }

        @media (max-width:380px) {
            .npc-card { padding:8px 10px; gap:4px; }
            .npc-avatar { width:26px; height:26px; font-size:13px; }
            .npc-name { font-size:0.8rem; }
            .npc-chain-section { padding:4px 6px; }
            .chain-flow { font-size:0.6rem; gap:2px; }
            .chain-arrow { font-size:0.6rem; }

            /* 超小屏再次确保 */
            .chain-step {
                white-space: normal;
                word-break: break-word;
                min-width: 0;
            }
            .chain-predict {
                word-break: break-word;
                min-width: 0;
            }

            .chronicle-header { padding:6px 8px; gap:4px; }
            .header-title { font-size:12px; }
            .header-time-badge { font-size:7px; padding:2px 6px; }
            .panel-header { padding:6px 8px 6px 10px; font-size:11px; min-height:34px; }
            .panel-content.open { padding:6px 8px 8px 8px; }
        }
    </style>
</head>
<body>
    <div class="chronicle-container theme-dark" id="chronicleRoot">
        <div class="chronicle-header" id="globalHeader">
            <div class="header-icon-group">
                <span class="header-icon-main">🎭</span>
            </div>
            <div class="header-title-area">
                <div class="header-title">后台动态观测</div>
            </div>
            <div class="header-time-badge" id="chronicleTimeBadge"></div>
            <div class="header-controls">
                <span class="toggle-badge" id="globalToggleHint">展开</span>
                <span class="header-caret" id="globalCaret">▼</span>
                <button class="theme-btn" id="themeToggle" title="切换主题">🌙</button>
            </div>
        </div>
        <div class="chronicle-body" id="chronicleBody">
            <div class="chronicle-inner" id="dynamicContent">
                <div style="padding:20px;color:var(--text-muted);text-align:center;">点击头部展开角色动态档案……</div>
            </div>
            <div class="footer-line">✧ 角色观测终端 ✧</div>
        </div>
    </div>

    <script>
        (function() {
            const root = document.getElementById('chronicleRoot');
            const themeBtn = document.getElementById('themeToggle');
            const savedTheme = localStorage.getItem('chronicleTheme') || 'dark';

            function applyTheme(theme) {
                if (theme === 'light') {
                    root.classList.add('theme-light');
                    root.classList.remove('theme-dark');
                    themeBtn.textContent = '☀️';
                } else {
                    root.classList.add('theme-dark');
                    root.classList.remove('theme-light');
                    themeBtn.textContent = '🌙';
                }
            }
            applyTheme(savedTheme);
            themeBtn.addEventListener('click', (e) => {
                e.stopPropagation();
                const isLight = root.classList.contains('theme-light');
                const newTheme = isLight ? 'dark' : 'light';
                applyTheme(newTheme);
                localStorage.setItem('chronicleTheme', newTheme);
            });

            function escHtml(str) {
                return String(str).replace(/[&<>]/g, m => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;' })[m]);
            }

            function getMessageText() {
                if (typeof getChatMessages === 'function' && typeof getCurrentMessageId === 'function') {
                    try {
                        const msgs = getChatMessages(getCurrentMessageId());
                        if (msgs && msgs.length) return msgs[0].message || '';
                    } catch (e) {}
                }
                const pres = document.querySelectorAll('pre, code, .message-content, [class*="message"], .chat-message');
                for (const el of pres) {
                    const t = el.textContent || el.innerText || '';
                    if (t.includes('<OffstageDynamic>') || t.includes('行为链:')) return t;
                }
                return '';
            }

            function parseNpcBlock(text) {
                const npc = {
                    name: '',
                    actionChain: [],
                    predict: '',
                    debutReady: false,
                    statusParts: [],
                    wealth: '',
                    longGoal: '',
                    nearPlan: [],
                    relatedEvent: '',
                    memories: []
                };
                let nameMatch = text.match(/💠\s*(.+?)(?:\n|$)/);
                if (!nameMatch) nameMatch = text.match(/<npc\s+act\s*=\s*["']?([^"'>\s]+)["']?\s*>/i);
                if (nameMatch) npc.name = nameMatch[1].trim();
                const chainMatch = text.match(/行为链\s*[:：]\s*(.+?)(?:\n|$)/);
                if (chainMatch) {
                    const chainRaw = chainMatch[1].trim();
                    const predictSplit = chainRaw.split(/→\s*后续预测\s*[:：]\s*/i);
                    if (predictSplit.length >= 2) {
                        const actionsPart = predictSplit[0];
                        const predictPart = predictSplit.slice(1).join('后续预测:');
                        npc.predict = predictPart.replace(/\[准备登场\]/i, '').trim();
                        npc.debutReady = /\[准备登场\]/i.test(predictPart);
                        npc.actionChain = actionsPart.split(/→/).map(s => s.trim()).filter(Boolean);
                    } else {
                        const actions = chainRaw.split(/→/).map(s => s.trim()).filter(Boolean);
                        npc.actionChain = actions;
                    }
                }
                const statusMatch = text.match(/当前状态\s*[:：]\s*(.+?)(?:\n|$)/);
                if (statusMatch) npc.statusParts = statusMatch[1].split(/\s*[|¦]\s*/).filter(Boolean);
                const wealthMatch = text.match(/资金状况\s*[:：]\s*(.+?)(?:\n|$)/);
                if (wealthMatch) npc.wealth = wealthMatch[1].trim();
                const goalMatch = text.match(/长期目标\s*[:：]\s*(.+?)(?:\n|$)/);
                if (goalMatch) npc.longGoal = goalMatch[1].trim();
                const planMatch = text.match(/近期打算\s*[:：]\s*(.+?)(?:\n|$)/);
                if (planMatch) npc.nearPlan = planMatch[1].split(/\s*[|¦]\s*/).filter(Boolean);
                const eventMatch = text.match(/关联事件\s*[:：]\s*\[([^\]]*)\]/);
                if (eventMatch) npc.relatedEvent = eventMatch[1].trim();
                const memMatch = text.match(/关键记忆\s*[:：]\s*(.+?)(?:\n|$)/);
                if (memMatch) {
                    const memRaw = memMatch[1].trim();
                    const memParts = memRaw.split(/[;；]/).filter(Boolean);
                    npc.memories = memParts.map(m => m.replace(/^\d+[\.\、\)]\s*/, '').trim()).filter(Boolean);
                }
                return npc;
            }

            function parseOffstageDynamic(text) {
                const result = { timeStr: '', relationNpcs: [], plotNpcs: [], worldNpcs: [] };
                const offMatch = text.match(/<OffstageDynamic>([\s\S]*?)<\/OffstageDynamic>/i);
                if (!offMatch) return result;
                const inner = offMatch[1];
                const timeMatch = inner.match(/<offstage\s*=\s*["']?🕒角色行动时间段?\s*[:：]\s*\[?([^\]<"]+)\]?["']?\s*>/i);
                if (timeMatch) result.timeStr = timeMatch[1].trim();
                else {
                    const tm2 = inner.match(/角色行动时间段?\s*[:：]\s*\[?(\d+年\d+月\d+日\/\d+:\d+-\d+年\d+月\d+日\/\d+:\d+)\]?/);
                    if (tm2) result.timeStr = tm2[1].trim();
                }
                const subSections = [
                    { tag: '不在场关系列表角色', key: 'relationNpcs', max: Number.MAX_SAFE_INTEGER },
                    { tag: '不在场剧情关联背景角色', key: 'plotNpcs', max: Number.MAX_SAFE_INTEGER },
                    { tag: '不在场时局背景角色', key: 'worldNpcs', max: Number.MAX_SAFE_INTEGER }
                ];
                subSections.forEach(sec => {
                    const openTag = `<${sec.tag}`;
                    const closeTag = `</${sec.tag}>`;
                    const idxStart = inner.indexOf(openTag);
                    if (idxStart === -1) return;
                    const afterOpen = inner.substring(idxStart);
                    const tagEnd = afterOpen.indexOf('>');
                    if (tagEnd === -1) return;
                    const contentStart = tagEnd + 1;
                    const idxClose = afterOpen.indexOf(closeTag);
                    if (idxClose === -1) return;
                    const sectionContent = afterOpen.substring(contentStart, idxClose);
                    const npcBlocks = sectionContent.match(/<npc\s+act\s*=\s*["'][^"']*["'][\s\S]*?<\/npc\s+act\s*>/gi);
                    if (npcBlocks) {
                        npcBlocks.slice(0, sec.max).forEach(block => {
                            const npc = parseNpcBlock(block);
                            if (npc.name) result[sec.key].push(npc);
                        });
                    }
                    if (result[sec.key].length === 0) {
                        const altBlocks = sectionContent.match(/<npc\s+act\s*=\s*["'][^"']*["'][\s\S]*?(?=<npc\s+act|$)/gi);
                        if (altBlocks) {
                            altBlocks.slice(0, sec.max).forEach(block => {
                                const npc = parseNpcBlock(block);
                                if (npc.name && !result[sec.key].find(n => n.name === npc.name)) {
                                    result[sec.key].push(npc);
                                }
                            });
                        }
                    }
                });
                return result;
            }

            function getWealthClass(wealth) {
                const w = wealth.toLowerCase();
                if (/一贫如洗|赤贫|destitute/i.test(w)) return 'wealth-destitute';
                if (/勉强糊口|贫困|poor/i.test(w)) return 'wealth-poor';
                if (/手头拮据|拮据|tight/i.test(w)) return 'wealth-tight';
                if (/收支平衡|平衡|balanced/i.test(w)) return 'wealth-balanced';
                if (/略有盈余|盈余|comfortable/i.test(w)) return 'wealth-comfortable';
                if (/手头宽裕|宽裕|well.?off/i.test(w)) return 'wealth-welloff';
                if (/富足有余|富裕|rich|wealthy/i.test(w)) return 'wealth-rich';
                return 'wealth-balanced';
            }
            function getWealthEmoji(wealth) {
                const w = wealth.toLowerCase();
                if (/一贫如洗|赤贫|destitute/i.test(w)) return '💀';
                if (/勉强糊口|贫困|poor/i.test(w)) return '🪙';
                if (/手头拮据|拮据|tight/i.test(w)) return '💰';
                if (/收支平衡|平衡|balanced/i.test(w)) return '💵';
                if (/略有盈余|盈余|comfortable/i.test(w)) return '💎';
                if (/手头宽裕|宽裕|well.?off/i.test(w)) return '🏦';
                if (/富足有余|富裕|rich|wealthy/i.test(w)) return '👑';
                return '💵';
            }
            function getNpcAvatarEmoji(name) {
                if (!name) return '👤';
                const char = name.charCodeAt(0);
                const emojis = ['🌟'];
                return emojis[char % emojis.length];
            }

            function renderNpcCard(npc) {
                const wealthCls = getWealthClass(npc.wealth);
                const wealthEmoji = getWealthEmoji(npc.wealth);
                const avatarEmoji = getNpcAvatarEmoji(npc.name);
                let html = '<div class="npc-card">';
                html += '<div class="npc-card-top">';
                html += `<div class="npc-avatar">${escHtml(avatarEmoji)}</div>`;
                html += '<div class="npc-identity">';
                html += `<div class="npc-name"><span class="npc-name-icon">💠</span>${escHtml(npc.name)}</div>`;
                if (npc.wealth) html += `<span class="npc-wealth-tag ${wealthCls}">${wealthEmoji} ${escHtml(npc.wealth)}</span>`;
                html += '</div></div>';
                if (npc.statusParts.length > 0) {
                    html += '<div class="npc-status-row">';
                    const labels = ['动作','穿着','位置','正在做'];
                    npc.statusParts.forEach((p,i) => {
                        html += `<span><span class="npc-status-dot">●</span> <strong>${labels[i]||'详情'}:</strong> ${escHtml(p)}</span>`;
                    });
                    html += '</div>';
                }
                if (npc.actionChain.length > 0 || npc.predict) {
                    html += '<div class="npc-chain-section"><div class="chain-label">⚡ 行为链</div><div class="chain-flow">';
                    npc.actionChain.forEach((a,i) => {
                        if (i>0) html += '<span class="chain-arrow">→</span>';
                        html += `<span class="chain-step">${escHtml(a)}</span>`;
                    });
                    if (npc.predict) {
                        html += '<span class="chain-arrow">→</span>';
                        html += `<span class="chain-predict">后续: ${escHtml(npc.predict)}</span>`;
                    }
                    if (npc.debutReady) html += '<span class="chain-debut-tag">⚡准备登场</span>';
                    html += '</div></div>';
                }
                if (npc.longGoal) html += `<div class="npc-info-row"><span class="npc-info-label">🎯 长期目标:</span><span class="npc-info-value">${escHtml(npc.longGoal)}</span></div>`;
                if (npc.nearPlan.length > 0) {
                    html += '<div class="npc-info-row"><span class="npc-info-label">📅 近期打算:</span>';
                    html += `<span class="npc-info-value">${npc.nearPlan.map(p=>escHtml(p)).join(' · ')}</span></div>`;
                }
                if (npc.relatedEvent && npc.relatedEvent !== '无') html += `<div class="npc-info-row"><span class="npc-info-label">🔗 关联事件:</span><span class="npc-info-value">${escHtml(npc.relatedEvent)}</span></div>`;
                if (npc.memories.length > 0) {
                    html += '<div class="npc-memory-tags">';
                    npc.memories.forEach(m => html += `<span class="memory-tag">🧠 ${escHtml(m)}</span>`);
                    html += '</div>';
                }
                html += '</div>';
                return html;
            }

            function renderAll(data) {
                const { offstageData } = data;
                let html = '';
                if (offstageData && (offstageData.relationNpcs.length || offstageData.plotNpcs.length || offstageData.worldNpcs.length)) {
                    const sections = [
                        { key:'relationNpcs', icon:'🤝', title:'不在场关系列表角色', badge:'RELATIONS', npcs:offstageData.relationNpcs },
                        { key:'plotNpcs', icon:'📖', title:'不在场剧情关联背景角色', badge:'PLOT', npcs:offstageData.plotNpcs },
                        { key:'worldNpcs', icon:'🌍', title:'不在场时局背景角色', badge:'WORLD', npcs:offstageData.worldNpcs }
                    ];
                    sections.forEach((sec, idx) => {
                        if (sec.npcs.length > 0) {
                            const panelId = `panel${idx}`;
                            html += `<div class="major-panel">`;
                            html += `<div class="panel-header" data-panel="${panelId}">`;
                            html += `<span class="panel-icon">${sec.icon}</span>`;
                            html += `<span class="panel-label">${escHtml(sec.title)} <span class="panel-badge">${sec.badge} (${sec.npcs.length})</span></span>`;
                            html += `<span class="panel-caret" id="${panelId}Caret">▼</span>`;
                            html += `</div><div class="panel-content" id="${panelId}Content"><div class="npc-grid">`;
                            sec.npcs.forEach(npc => html += renderNpcCard(npc));
                            html += `</div></div></div>`;
                        }
                    });
                } else {
                    html = '<div style="color:var(--text-muted);padding:12px;text-align:center;">📭 暂无后台动态数据</div>';
                }
                return html;
            }

            function parseAllData(rawText) {
                const data = { offstageData: null, globalTime: '' };
                const offIdx = rawText.search(/<OffstageDynamic>/i);
                let offText = '';
                if (offIdx !== -1) {
                    const offMatch = rawText.match(/<OffstageDynamic>[\s\S]*?<\/OffstageDynamic>/i);
                    if (offMatch) offText = offMatch[0];
                }
                if (offText) data.offstageData = parseOffstageDynamic(offText);
                const timeMatch = rawText.match(/🕒角色行动时间段?\s*[:：]\s*\[?([\d年\/月日\:\-]+)\]?/);
                if (timeMatch) data.globalTime = timeMatch[1].trim();
                else if (data.offstageData && data.offstageData.timeStr) data.globalTime = data.offstageData.timeStr;
                return data;
            }

            function updateTimeBadge() {
                const badge = document.getElementById('chronicleTimeBadge');
                if (!badge) return;
                const msgText = getMessageText();
                if (!msgText) {
                    badge.textContent = '';
                    return;
                }
                const parsed = parseAllData(msgText);
                badge.textContent = parsed.globalTime || '';
            }

            function setupPanelToggle(panelDataAttr, contentId, caretId) {
                const header = document.querySelector(`[data-panel="${panelDataAttr}"]`);
                const content = document.getElementById(contentId);
                const caret = document.getElementById(caretId);
                if (header && content && caret) {
                    header.addEventListener('click', (e) => {
                        e.stopPropagation();
                        const isOpen = content.classList.contains('open');
                        content.classList.toggle('open');
                        caret.style.transform = isOpen ? 'rotate(0deg)' : 'rotate(180deg)';
                    });
                }
            }

            function renderChronicle() {
                const container = document.getElementById('dynamicContent');
                if (!container) return;
                const msgText = getMessageText();
                if (!msgText) {
                    container.innerHTML = '<div style="padding:20px;color:var(--text-muted);text-align:center;">📜 等待角色动态数据输入…<br><small>请确保消息中包含 &lt;OffstageDynamic&gt; 标签</small></div>';
                    return;
                }
                const parsed = parseAllData(msgText);
                container.innerHTML = renderAll(parsed);
                ['panel0','panel1','panel2'].forEach(panelId => {
                    const content = document.getElementById(`${panelId}Content`);
                    const caret = document.getElementById(`${panelId}Caret`);
                    if (content && caret) {
                        content.classList.add('open');
                        caret.style.transform = 'rotate(180deg)';
                        setupPanelToggle(panelId, `${panelId}Content`, `${panelId}Caret`);
                    }
                });
            }

            updateTimeBadge();

            const chronicleBody = document.getElementById('chronicleBody');
            const globalHeader = document.getElementById('globalHeader');
            const globalCaret = document.getElementById('globalCaret');
            const globalHint = document.getElementById('globalToggleHint');
            let hasRendered = false;
            if (globalHeader && chronicleBody) {
                globalHeader.addEventListener('click', (e) => {
                    if (e.target.closest('#themeToggle')) return;
                    const isExpanded = chronicleBody.classList.contains('expanded');
                    if (isExpanded) {
                        chronicleBody.classList.remove('expanded');
                        globalCaret.style.transform = 'rotate(0deg)';
                        globalHint.innerText = '展开';
                    } else {
                        chronicleBody.classList.add('expanded');
                        globalCaret.style.transform = 'rotate(180deg)';
                        globalHint.innerText = '收起';
                        if (!hasRendered) {
                            renderChronicle();
                            hasRendered = true;
                        }
                    }
                });
            }
        })();
    </script>
