   let activeThemeItemId = 'accent';

/* ================================================================
 * 2. 工具函数
 * ================================================================ */
   function getPresetTheme(idx) {
       const base = THEME_DEFS[themes[idx - 1] || 'dark'];
       return { colors: { ...base.colors }, radius: { 'r1':'14px','r2':'10px','r3':'6px','rb':'50px','rs':'20px','rt':'6px' }, widths: { 'solid':'1px','dashed':'1px' }, blur: base.blur };
   }
   const getTag = (text, tag) => { const m = new RegExp('<'+tag+'(?=[\\s>])[^>]*>([\\s\\S]*?)<\\/'+tag+'>','i').exec(text); return m ? m[1].trim() : null; };

/* ================================================================
 * 3. 数据提取（$6 隐藏数据抓取）
 * ================================================================ */
   async function fetchContext(specificIdx = null) {
       try {
           let chat = window.SillyTavern?.chat || (typeof getContext==='function'?getContext()?.chat:[]);
           if(!chat || chat.length === 0) return "";

           const getPlot = (m) => {
               if (!m) return null;
               const target = localStorage.getItem('st_scenario_fetch_target_v1') || 'A'; // A, B, C

               const unescapeTasks = (str) => {
                   if (str === null || str === undefined) return "";
                   // 如果是对象或数组,强制转化为带缩进的字符串格式
                   let res = typeof str === 'string' ? str : JSON.stringify(str, null, 2);
                   // 还原被转义的换行符和双引号
                   return res.replace(/\\n/g, '\n').replace(/\\"/g, '"');
               };

               let valB = m.qrf_plot_tasks ? unescapeTasks(m.qrf_plot_tasks) : null;

               let valA = m.qrf_plot;
               if (!valA && m.extra?.qrf_plot) valA = m.extra.qrf_plot;
               if (!valA && m.swipes && Array.isArray(m.swipes)) {
                   const sid = m.swipe_id ?? (m.swipes.length - 1);
                   if (m.swipes[sid]?.extra?.qrf_plot) valA = m.swipes[sid].extra.qrf_plot;
               }
               if (valA && typeof valA !== 'string') valA = JSON.stringify(valA, null, 2);

               if (target === 'A') return valA || null;
               if (target === 'B') return valB || null;
               // target === 'C' (优先B,其次A)
               return valB || valA || null;
           };

           const mode = localStorage.getItem('st_scenario_fetch_mode_v1') || 'basic';
           let startIdx = typeof specificIdx === 'number' ? specificIdx : chat.length - 1;

           if (mode === 'basic') {
               startIdx = chat.length - 1; // 强制从最新层开始找
           } else if (mode === 'fallback' && typeof specificIdx === 'number') {
               startIdx = specificIdx - 1; // 跳过当前层,从上一层开始向回找
           }

          if (mode === 'precise') {
               if (startIdx >= 0 && chat[startIdx]) {
                   const p = getPlot(chat[startIdx]);
                   if (p) { window.lastFetchedIdx = startIdx; return p; }
               }
               window.lastFetchedIdx = -1;
               return "";
           }

           for(let i = startIdx; i >= 0; i--) {
               const p = getPlot(chat[i]);
               if (p) { window.lastFetchedIdx = i; return p; }
           }
       } catch (e) { console.error("History Extract Error:", e); }
       window.lastFetchedIdx = -1;
       return "";
   }

/* ================================================================
 * 4. 设置系统（主题 / 字号 初始化 & 同步）
 * ================================================================ */
   function initSettings() {
       try {
           const fCfg = JSON.parse(localStorage.getItem(fontCfgKey));
           if (fCfg) { fontState = fCfg; document.body.classList.toggle('global-bold', !!fontState.isBold); if($('boldToggle')) $('boldToggle').checked = fontState.isBold; styleTag.textContent = fontState.currentSlot===0?'':(fontState.slots[fontState.currentSlot]||''); }
       } catch(e){}
       try {
           const tCfg = JSON.parse(localStorage.getItem(customThemeKey));
           if (tCfg) {
               themeState.enabled = tCfg.enabled; themeState.currentSlot = tCfg.currentSlot||1;
               if ($('customThemeToggle')) $('customThemeToggle').checked = themeState.enabled;
               for(let i=1; i<=5; i++) { if(tCfg.slots && tCfg.slots[i]) { const d=themeState.slots[i], s=tCfg.slots[i]; themeState.slots[i] = {...d, ...s, colors:{...d.colors,...(s.colors||{})}, radius:{...d.radius,...(s.radius||{})}, widths:{...d.widths,...(s.widths||{})}}; } }
           }
       } catch(e){} updateThemeCSS();
   }
   let lastKnownFetchMode = localStorage.getItem('st_scenario_fetch_mode_v1') || 'basic';
   let lastKnownFetchTarget = localStorage.getItem('st_scenario_fetch_target_v1') || 'A';

   function syncSettings() {
       const theme = localStorage.getItem(themeKey) || 'dark';
       if (app.getAttribute('data-theme') !== theme) { app.setAttribute('data-theme', theme); ['modalOverlay','fontModalOverlay','themeModalOverlay'].forEach(id => $(id).setAttribute('data-theme', theme)); updateThemeCSS(); }
       const fLevel = parseInt(localStorage.getItem(fontKey)) || 3;
       document.documentElement.style.setProperty('--base-fs', fontSizes[fLevel - 1] + 'px');
       if ($('fontIcon')) $('fontIcon').innerText = fLevel;
       try {
           const fontCfg = JSON.parse(localStorage.getItem(fontCfgKey));
           if (fontCfg && fontCfg.isBold !== fontState.isBold) { fontState.isBold = fontCfg.isBold; document.body.classList.toggle('global-bold', fontCfg.isBold); if($('boldToggle')) $('boldToggle').checked = fontCfg.isBold; }
           if ($('themeModalOverlay').style.display !== 'flex') { const themeCfg = JSON.parse(localStorage.getItem(customThemeKey)); if(themeCfg) { themeState = themeCfg; updateThemeCSS(); } }
       } catch (e) {}

       // 检测抓取模式或对象是否被其他楼层的面板改变,如果是则触发全局所有楼层的同步刷新
       const currentMode = localStorage.getItem('st_scenario_fetch_mode_v1') || 'basic';
       const currentTarget = localStorage.getItem('st_scenario_fetch_target_v1') || 'A';
       let needRender = false;
       if (lastKnownFetchMode !== currentMode) { lastKnownFetchMode = currentMode; needRender = true; }
       if (lastKnownFetchTarget !== currentTarget) { lastKnownFetchTarget = currentTarget; needRender = true; }
       if (needRender && typeof render === 'function') render();
   }
   window.updateThemeCSS = () => {
       let data = themeState.enabled ? themeState.slots[themeState.currentSlot] : { ...getPresetTheme(themes.indexOf(localStorage.getItem(themeKey)||'white')+1) };
       const { colors: c, radius: r, widths: w, blur } = data;
       const blurVal = blur ? (c['bg-panel'].includes('rgba(65') ? 'blur(18px) saturate(180%)' : 'blur(12px) saturate(160%)') : 'none';
       const css = `html body #main-app, html body #main-app .modal-overlay { --bg-panel: ${c['bg-panel']} !important; --bg-card: ${c['bg-card']} !important; --accent: ${c.accent} !important; --text-m: ${c['text-m']} !important; --text-s: ${c['text-s']} !important; --border: ${c.border} !important; --bg-tag: ${c['bg-tag']} !important; --c-ok: ${c['c-ok']||'#5adb5e'} !important; --c-warn: ${c['c-warn']||'#ff5c5c'} !important; --t-lo: ${c['t-lo']||'#5adb5e'} !important; --t-mi: ${c['t-mi']||'#b8c44a'} !important; --t-hi: ${c['t-hi']||'#e8a840'} !important; --t-vh: ${c['t-vh']||'#ff5c5c'} !important; --bg-dossier: ${c['bg-dossier']||'rgba(20,10,5,.35)'} !important; --bg-term: ${c['bg-term']||'rgba(10,15,8,.4)'} !important; --frame-mid: ${c['frame-mid']||'#1a6b9a'} !important; --term-color: ${c['term-color']||'#64ff64'} !important; --r1: ${r.r1} !important; --r2: ${r.r2} !important; --r3: ${r.r3} !important; --r-badge: ${r.rb} !important; --r-switch: ${r.rs} !important; --r-btn: ${r.rt} !important; --blur: ${blurVal} !important; --border-w: ${w.solid} !important; --border-w-npc: ${w.dashed} !important; --text-btn: ${c['text-btn']||'#ffffff'} !important; } html body #main-app .save-theme-btn, html body #main-app .slot-btn.active, html body #main-app .float-save-btn, html body #main-app .theme-io-btn, html body #main-app .count-badge { color: var(--text-btn) !important; } html body #main-app .main-container { backdrop-filter: var(--blur) !important; -webkit-backdrop-filter: var(--blur) !important; } html body #main-app .modal-card { background: var(--bg-panel) !important; color: var(--text-m) !important; border: var(--border-w) solid var(--border) !important; box-shadow: 0 10px 40px rgba(0,0,0,${blur?0.5:0.2}), inset 0 ${blur?1:0}px 0 0 rgba(255,255,255,${blur?0.3:0}) !important; }`;
       if (themeStyleTag.textContent !== css) themeStyleTag.textContent = css;
       if (typeof updateStarAccent === 'function') updateStarAccent();
   };

