               header.className = 'cache-header-row';
               header.innerHTML = `<div class="cache-warning">🐱正常情况下用不到此页面功能。剧情规划出问题了再来用吧。🐱</div><div class="cache-help-btn" onclick="showCacheHelp()">i</div>`;
               container.appendChild(header);

               const chat = window.SillyTavern?.chat || (typeof getContext==='function'?getContext()?.chat:[]);
               const fetchTarget = localStorage.getItem('st_scenario_fetch_target_v1') || 'A';
               let foundItems =[];
               for(let i = chat.length - 1; i >= 0 && foundItems.length < 5; i--) {
                   const msg = chat[i]; if(!msg) continue;
                   let plotText = null, swipeIdx = null;

                   let valB = msg.qrf_plot_tasks ? (typeof msg.qrf_plot_tasks === 'string' ? msg.qrf_plot_tasks : JSON.stringify(msg.qrf_plot_tasks)) : null;
                   let valA = msg.qrf_plot;
                   if (!valA && msg.extra?.qrf_plot) valA = msg.extra.qrf_plot;
                   if (!valA && msg.swipes && Array.isArray(msg.swipes)) {
                       const sid = msg.swipe_id ?? (msg.swipes.length - 1);
                       if (msg.swipes[sid]?.extra?.qrf_plot) { valA = msg.swipes[sid].extra.qrf_plot; swipeIdx = sid; }
                   }
                   if (valA && typeof valA !== 'string') valA = JSON.stringify(valA);

                   if (fetchTarget === 'A') plotText = valA || null;
                   else if (fetchTarget === 'B') plotText = valB || null;
                   else plotText = valB || valA || null;

                   if (plotText) foundItems.push({ idx: i, text: plotText, sId: swipeIdx });
               }
               if (foundItems.length === 0) {
                   const empty = document.createElement('div');
