  function log(...args) {
    if (!DEBUG) return;
    console.log('[ReasoningRegexStyler]', ...args);
  }

  function getTopDocument() {
    try {
      return window.top?.document || document;
    } catch {
      return document;
    }
  }

  function getST() {
    if (typeof SillyTavern !== 'undefined') return SillyTavern;
    return null;
  }

  function getChatArray() {
    const st = getST();
    if (st && Array.isArray(st.chat)) return st.chat;
    if (Array.isArray(window.chat)) return window.chat;
    return null;
  }

  function updateBlock(messageId, message) {
    const st = getST();
    if (st && typeof st.updateMessageBlock === 'function') {
      st.updateMessageBlock(messageId, message);
      return;
    }
    if (typeof window.updateMessageBlock === 'function') {
      window.updateMessageBlock(messageId, message);
    }
  }

  function injectStyleOnce(doc) {
    if (!doc || !doc.head) return;
    let style = doc.getElementById(STYLE_ID);
    if (!style) {
      style = doc.createElement('style');
      style.id = STYLE_ID;
      doc.head.appendChild(style);
      log('style created', { inTop: doc === getTopDocument() });
    }
    style.textContent = REASONING_CSS;
  }

  function injectStyle() {
    injectStyleOnce(document);
    injectStyleOnce(getTopDocument());
    log('style injected', { cssLength: REASONING_CSS.length });
  }

  function removeStyle() {
    for (const doc of [document, getTopDocument()]) {
      const style = doc?.getElementById?.(STYLE_ID);
      if (style) style.remove();
    }
    log('style removed');
  }

  /**
   * 核心：流式兼容的解析逻辑 (无头优先)
   */
  function extractReasoningAndClean(text, isStreaming) {
    if (typeof text !== 'string') return null;
    const { prefix, suffix } = getReasoningConfig();

    // 1. 如果包含闭合标签
    if (text.includes(suffix)) {
      const parts = text.split(suffix);
      let reasoningPart = parts[0];
      const cleaned = parts.slice(1).join(suffix).trim();

      // 如果有前缀则从前缀后开始截取
      if (reasoningPart.includes(prefix)) {
        reasoningPart = reasoningPart.split(prefix)[1];
      }

      const title = extractLatestHeaderByPriority(reasoningPart);
      return { reasoning: reasoningPart.trim(), cleaned, state: 'done', title };
    }

    // 2. 流式状态下，没看到闭合标签，则全部内容视为思维链
    if (isStreaming && text.length > 0) {
      let reasoning = text;
      // 如果有前缀则去掉前缀显示
      if (text.startsWith(prefix)) {
        reasoning = text.slice(prefix.length);
      }
      const title = extractLatestHeaderByPriority(reasoning);
      return { reasoning: reasoning.trim(), cleaned: '', state: 'thinking', title };
    }

    // 3. 非流式但有前缀的情况
    if (text.startsWith(prefix)) {
      const reasoning = text.slice(prefix.length).trim();
      const title = extractLatestHeaderByPriority(reasoning);
      return { reasoning, cleaned: '', state: 'thinking', title };
    }

    return null;
  }

  function normalizeHeaderText(str) {
    return String(str || '')
      .replace(/\s+/g, ' ')
      .replace(/[\u200B-\u200D\uFEFF]/g, '')
      .trim();
  }

  function normalizeTpText(str) {
    return String(str || '')
      .replace(/[\u200B-\u200D\uFEFF]/g, '')
      .replace(/\s*\n\s*/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();
  }

  function extractTpInfo(text) {
    const src = String(text || '');
    if (!src || !src.includes('<tp')) return null;

    const match = src.match(/<tp\b[^>]*>\s*([^@|<]*?)\s*(?:@\s*([^@|<]*?)\s*?)?(?:\|\s*([^<]*?)\s*)?<\/tp>/i);
    if (!match) return null;

    const time = normalizeTpText(match[1]);
    const location = normalizeTpText(match[2]);
    const weather = normalizeTpText(match[3]);

    if (!time && !location && !weather) return null;
    return { time, location, weather };
  }

  function findMessageDom(messageId) {
    const selector = `#chat [mesid="${messageId}"]`;
    const inFrame = document.querySelector(selector);
    if (inFrame) return inFrame;
    const topDoc = getTopDocument();
    return topDoc?.querySelector?.(selector) || null;
  }

  function resolveDisplayTitle(state, rawTitle) {
    void rawTitle;
    if (state === 'done' || state === 'thinking') return FIXED_REASONING_TITLE;
    return '';
  }

  function clipTitle(title, maxLen = 42) {
    const t = normalizeHeaderText(title);
    if (!t) return '';
    return t.length > maxLen ? t.slice(0, maxLen) : t;
  }

  function extractLatestHeaderByPriority(text) {
    const src = String(text || '');
    if (!src) return '';

    let best = null;

    const pick = (priority, index, rawTitle) => {
      const title = normalizeHeaderText(rawTitle);
      if (!title || /^[`~!@#$%^&*()_+\-=\[\]{};:'",.<>/?|\\]+$/.test(title)) return;

      if (!best || priority > best.priority || (priority === best.priority && index > best.index)) {
        best = { priority, index, title };
      }
    };

    // 优先级 3: # 标题 / ## 标题
    {
      const re = /^(#{1,2})\s+(.+)$/gm;
      let m;
      while ((m = re.exec(src)) !== null) {
        pick(3, m.index, m[2]);
      }
    }

    // 优先级 2: **标题**（行级）
    {
      const re = /(?:^|\n)\s*\*\*([^*\n][^*\n]*?)\*\*\s*(?=\n|$)/g;
      let m;
      while ((m = re.exec(src)) !== null) {
        pick(2, m.index, m[1]);
      }
    }

    // 优先级 1: - 标题 / • 标题
    {
      const re = /^\s*(?:-|•)\s+(.+)$/gm;
      let m;
      while ((m = re.exec(src)) !== null) {
        pick(1, m.index, m[1]);
      }
    }

    return best?.title || '';
  }

  function applyReasoningToMessage(messageId) {
    const id = Number(messageId);
    if (!Number.isInteger(id) || id < 0) return;

    const chat = getChatArray();
    if (!chat) return;

    const message = chat[id];
    if (!message || message.is_user) return;

    const isStreaming = message.swipe_id === undefined && message.gen_started && !message.extra?.reasoning_duration;

    if (message.extra?.reasoning) {
      const nativeState = message.extra?.reasoning_state;
      const state = nativeState === 'thinking' || nativeState === 'done'
        ? nativeState
        : (isStreaming ? 'thinking' : 'done');

      const { suffix } = getReasoningConfig();
      if (message.mes.includes(suffix)) {
        message.mes = message.mes.split(suffix).slice(1).join(suffix).trim();
        updateBlock(id, message);
      }

      const tpInfo = extractTpInfo(String(message.mes ?? ''));

      // 只从 reasoning 区块提取标题，避免在正文阶段误抓正文首行
      const titleSource = String(message.extra?.reasoning || '');
      const extracted = extractLatestHeaderByPriority(titleSource);
      const title = clipTitle(resolveDisplayTitle(state, extracted));
      if (message.extra.reasoning_header_title !== title) {
        message.extra.reasoning_header_title = title;
      }

      updateReasoningUIState(id, state, title, tpInfo);
      return;
    }

    const parsed = extractReasoningAndClean(String(message.mes ?? ''), isStreaming);
    if (!parsed) {
      updateReasoningUIState(id, 'none', '', null);
      return;
    }

    message.extra = (message.extra && typeof message.extra === 'object') ? message.extra : {};
    message.extra.reasoning = parsed.reasoning;
    message.extra.reasoning_type = 'parsed';
    message.extra.reasoning_state = parsed.state;
    message.mes = parsed.cleaned;

    const title = clipTitle(resolveDisplayTitle(parsed.state, parsed.title));
    const tpInfo = extractTpInfo(parsed.cleaned);
    message.extra.reasoning_header_title = title;

    updateBlock(id, message);
    updateReasoningUIState(id, parsed.state, title, tpInfo);
  }

  function updateReasoningTpMeta(messageDom, tpInfo) {
    const header = messageDom.querySelector('.mes_reasoning_header');
    if (!header) return;

    let meta = header.querySelector('.qqz_reasoning_tp_meta');
    if (!meta) {
      meta = document.createElement('div');
      meta.className = 'qqz_reasoning_tp_meta';
      meta.innerHTML = [
        '<div class="qqz_reasoning_tp_line qqz_reasoning_tp_line--time"><span class="qqz_reasoning_tp_label">时间</span><span class="qqz_reasoning_tp_value"></span></div>',
        '<div class="qqz_reasoning_tp_line qqz_reasoning_tp_line--location"><span class="qqz_reasoning_tp_label">地点</span><span class="qqz_reasoning_tp_value"></span></div>',
        '<div class="qqz_reasoning_tp_line qqz_reasoning_tp_line--weather"><span class="qqz_reasoning_tp_label">天象</span><span class="qqz_reasoning_tp_value"></span></div>'
      ].join('');
      header.appendChild(meta);
    }

    const rows = {
      time: meta.querySelector('.qqz_reasoning_tp_line--time'),
      location: meta.querySelector('.qqz_reasoning_tp_line--location'),
      weather: meta.querySelector('.qqz_reasoning_tp_line--weather')
    };

    const values = {
      time: rows.time?.querySelector('.qqz_reasoning_tp_value'),
      location: rows.location?.querySelector('.qqz_reasoning_tp_value'),
      weather: rows.weather?.querySelector('.qqz_reasoning_tp_value')
    };

    const fields = {
      time: normalizeTpText(tpInfo?.time),
      location: normalizeTpText(tpInfo?.location),
      weather: normalizeTpText(tpInfo?.weather)
    };

    let visibleCount = 0;
    for (const key of ['time', 'location', 'weather']) {
      const row = rows[key];
      const valueNode = values[key];
      const value = fields[key];
      if (!row || !valueNode) continue;

      if (value) {
        valueNode.textContent = value;
        row.hidden = false;
        visibleCount += 1;
      } else {
        valueNode.textContent = '';
        row.hidden = true;
      }
    }

    meta.hidden = visibleCount === 0;
  }

  /**
   * 强制同步 DOM 状态属性
   */
  function updateReasoningUIState(messageId, state, title, tpInfo) {
    requestAnimationFrame(() => {
      const messageDom = findMessageDom(messageId);
      if (!messageDom) return;

      // 【核心】给根节点挂载状态，通过 CSS 物理遮断正文渲染
      if (state === 'thinking') {
        messageDom.setAttribute('data-reasoning-state', 'thinking');
        messageDom.setAttribute('data-is-thinking', 'true');
      } else if (state === 'done') {
        messageDom.setAttribute('data-reasoning-state', 'done');
        messageDom.removeAttribute('data-is-thinking');
      } else {
        messageDom.removeAttribute('data-reasoning-state');
        messageDom.removeAttribute('data-is-thinking');
      }

      const mesDetails = messageDom.querySelector('.mes_reasoning_details');

      if (mesDetails) {
        if (mesDetails.getAttribute('data-state') !== state) {
          mesDetails.setAttribute('data-state', state);
        }
        const config = getReasoningConfig();
        if (state === 'thinking' && config.auto_expand) {
          if (!mesDetails.open) mesDetails.open = true;
        }
      }

      const mesTitle = messageDom.querySelector('.mes_reasoning_header_title');
      if (mesTitle) {
        const finalTitle = clipTitle(resolveDisplayTitle(state, title));
        const prevTitle = mesTitle.getAttribute('data-custom-title') || '';

        if (finalTitle) {
          if (prevTitle !== finalTitle) {
            mesTitle.setAttribute('data-animating', 'true');
            requestAnimationFrame(() => {
              mesTitle.setAttribute('data-custom-title', finalTitle);
              setTimeout(() => mesTitle.removeAttribute('data-animating'), 260);
            });
          }
        } else {
          mesTitle.removeAttribute('data-custom-title');
          mesTitle.removeAttribute('data-animating');
        }
      }

      updateReasoningTpMeta(messageDom, tpInfo);
    });
  }

  function applyReasoningToAllMessages() {
    const chat = getChatArray();
    if (!chat) return;
    for (let i = 0; i < chat.length; i++) applyReasoningToMessage(i);
  }

  let streamTickRaf = 0;

  function scheduleApplyLatestAssistantMessage() {
    if (streamTickRaf) return;
    streamTickRaf = requestAnimationFrame(() => {
      streamTickRaf = 0;
      const chat = getChatArray();
      if (!chat || !chat.length) return;

      for (let i = chat.length - 1; i >= 0; i--) {
        const msg = chat[i];
        if (msg && !msg.is_user) {
          applyReasoningToMessage(i);
          break;
        }
      }
    });
  }

  function bindEvents() {
    if (typeof eventOn === 'function' && typeof tavern_events !== 'undefined') {
      eventOn(tavern_events.MESSAGE_UPDATED, (messageId) => {
        applyReasoningToMessage(messageId);
      });

      eventOn(tavern_events.MESSAGE_RECEIVED, (messageId) => {
        applyReasoningToMessage(messageId);
      });

      eventOn(tavern_events.CHAT_CHANGED, () => {
        injectConfig(); // 切换聊天时再次确保配置注入
        setTimeout(applyReasoningToAllMessages, 50);
      });

      eventOn(tavern_events.CHARACTER_MESSAGE_RENDERED, (messageId) => {
        applyReasoningToMessage(messageId);
      });

      // STREAM_TOKEN_RECEIVED 事件参数是 token 文本，不是 messageId
      eventOn(tavern_events.STREAM_TOKEN_RECEIVED, () => {
        scheduleApplyLatestAssistantMessage();
      });
    } else {
      log('eventOn/tavern_events not available');
    }
  }

  function init() {
    injectConfig();
    injectStyle();
    bindEvents();

    setTimeout(applyReasoningToAllMessages, 100);
    setTimeout(applyReasoningToAllMessages, 800);

    $(window).on('pagehide', removeStyle);
    log('loaded', { scriptId: SCRIPT_ID, debug: DEBUG });
  }

  $(() => init());
})();

// 定义四个需要处理的路径
const RELEVANT_PATHS = [
    '剧情规划.过往任务日志',
    '剧情规划.旧剧情规划参考',
    '世界后台状态.世界时局与经济简报',
    '世界后台状态.自动化系统'
];

// 辅助函数：从完整 data 对象中提取四个路径的值，返回一个新对象
function extractRelevantData(data) {
    const result = {};
    for (const path of RELEVANT_PATHS) {
        const value = _.get(data, path);
        if (value !== undefined) {
            _.set(result, path, value);
        }
    }
    return result;
}

// 辅助函数：将 sourceData 中的四个路径的值合并到 targetData 中（返回新对象，不修改原对象）
function mergeRelevantData(targetData, sourceData) {
    const newData = _.cloneDeep(targetData);
    for (const path of RELEVANT_PATHS) {
        const value = _.get(sourceData, path);
        if (value !== undefined) {
            _.set(newData, path, value);
        }
    }
    return newData;
}

// 辅助函数：获取指定角色、在当前消息之前的最新一条消息的 relevant data
function getLatestRelevantDataByRole(beforeMessageId, role) {
    const allMessages = getChatMessages('0-{{lastMessageId}}', { include_swipes: false });
    for (let i = allMessages.length - 1; i >= 0; i--) {
        const msg = allMessages[i];
        if (msg.message_id < beforeMessageId && msg.role === role) {
            return extractRelevantData(msg.data || {});
        }
    }
    return {};
}

// 用户消息发送时：提取标签 + 继承上一轮 AI 的 relevant data
async function saveAutoData(message_id) {
    try {
        const msgs = getChatMessages(message_id);
        if (!msgs.length) return;
        const msg = msgs[0];
        const content = msg.message || '';

        // 1. 从消息内容中提取四个标签
        const tags = [
            { regex: /<StoryEngine>[\s\S]*?<\/StoryEngine>/i,      path: '剧情规划.过往任务日志', name: '任务日志' },
            { regex: /<QuestPlan>[\s\S]*?<\/QuestPlan>/i,          path: '剧情规划.旧剧情规划参考', name: '剧情规划参考' },
            { regex: /<WorldDynamic>[\s\S]*?<\/WorldDynamic>/i,    path: '世界后台状态.世界时局与经济简报', name: '世界动态' },
            { regex: /<OffstageDynamic>[\s\S]*?<\/OffstageDynamic>/i, path: '世界后台状态.自动化系统', name: '自动化系统' }
        ];

        let hasAny = false;
        const extracted = {};
        const savedTags = [];

        for (const tag of tags) {
            const match = content.match(tag.regex);
            if (match) {
                hasAny = true;
                _.set(extracted, tag.path, match[0]);
                savedTags.push(tag.name);
            }
        }

        // 2. 继承上一轮AI消息的relevant data
        const inherited = getLatestRelevantDataByRole(message_id, 'assistant');

        // 3. 合并：先保留当前消息原有的全部data，然后依次用 inherited、extracted 覆盖四个相关路径
        let finalData = _.cloneDeep(msg.data || {});
        finalData = mergeRelevantData(finalData, inherited);
        finalData = mergeRelevantData(finalData, extracted);

        // 4. 保存回当前用户消息
        await setChatMessages([{ message_id, data: finalData }], { refresh: 'none' });

        // 5. 提示：仅在有标签时显示成功；无标签但有继承时不提示；既无标签也无继承时显示“未检测到标签”
        if (hasAny) {
            const successMsg = `已保存: ${savedTags.join(', ')}`;
            if (typeof toastr !== 'undefined') {
                toastr.success(successMsg, '自动保存', { timeOut: 3000 });
            } else {
                console.log('[自动保存] 成功:', successMsg);
            }
        } else if (Object.keys(inherited).length === 0 && Object.keys(extracted).length === 0) {
            // 既无新标签，也无任何可继承的历史数据
            if (typeof toastr !== 'undefined') {
                toastr.info('未检测到可自动保存的标签', '自动保存', { timeOut: 2000 });
            } else {
                console.log('[自动保存] 未检测到标签');
            }
        }
        // 有继承但无新标签 → 静默，不提示

    } catch (e) {
        console.error('[自动保存] 失败:', e);
        if (typeof toastr !== 'undefined') {
            toastr.error(`保存失败: ${e.message || e}`, '自动保存错误', { timeOut: 5000 });
        }
    }
}

// AI 消息生成后：继承上一轮用户消息的relevant data + 注入占位符
async function processAIMessage(message_id, type) {
    // type === 'quiet' 时（如内部静默生成）通常不需要处理，可根据需要决定
    try {
        const all = getChatMessages(message_id, { include_swipes: false });
        if (!all.length) return;
        const currentMsg = all[0];
        if (currentMsg.role !== 'assistant') return;

        // 1. 继承上一轮用户消息的 relevant data
        const inherited = getLatestRelevantDataByRole(message_id, 'user');
        let newData = _.cloneDeep(currentMsg.data || {});
        if (Object.keys(inherited).length > 0) {
            newData = mergeRelevantData(newData, inherited);
        }

        // 2. 检查并追加占位符 <世界动态/>，若存在 <StatusPlaceHolderImpl/> 则插入到其正下方
        let newMessage = currentMsg.message || '';
        const worldPlaceholder = '<世界动态/>';
        const otherPlaceholder = '<StatusPlaceHolderImpl/>';

        // 仅当消息中尚未包含 <世界动态/> 时才处理
        if (!newMessage.includes(worldPlaceholder)) {
            if (newMessage.includes(otherPlaceholder)) {
                // 找到最后一个 <StatusPlaceHolderImpl/> 的位置，在其后插入换行和 <世界动态/>
                const lastIndex = newMessage.lastIndexOf(otherPlaceholder);
                const before = newMessage.slice(0, lastIndex + otherPlaceholder.length);
                const after = newMessage.slice(lastIndex + otherPlaceholder.length);
                newMessage = before + '\n' + worldPlaceholder + after;
            } else {
                // 没有其他占位符，直接追加到末尾
                newMessage = newMessage + worldPlaceholder;
            }
        }

        // 3. 一次性保存（同时更新 data 和 message）
        await setChatMessages([{
            message_id,
            data: newData,
            message: newMessage
        }], { refresh: 'affected' });

        // 静默处理，不弹出提示
    } catch (e) {
