    // ========== 新增日历变量值内容校验 ==========
    // 相对时间检测正则（禁止使用）
    const RELATIVE_TIME_PATTERN = /\b(今[天日晚]|明[天日晚]|昨[天日晚]|后[天日晚]|前[天日晚]|大后天|大前天|下(周|月|年)|上(周|月|年)|下个|上个|这[周月年]|本[周月年]|未来|过去|即将|稍后|立刻|马上|此刻|现在|当前|最近|片刻|稍等|过一会|一会[儿]?)\b/;
    // 重复规则允许的值
    const ALLOWED_RECUR_RULES = ['无', '每天', '每周', '每月', '每年', '仅工作日', '仅节假日'];

