    function validateFieldValue(fieldName, value, fullPath) {
        const warnings = [];
        if (value === undefined || value === null) return warnings;
        if (fieldName === '时间' || fieldName === '结束时间') {
            if (typeof value === 'string' && RELATIVE_TIME_PATTERN.test(value)) {
                warnings.push(`⚠️ 日历事件字段“${fieldName}”包含相对时间词（如“明天”“下周”），请使用绝对时间或参照“世界.时间”格式。`);
            }
            if (typeof value !== 'string') {
                warnings.push(`⚠️ 日历事件字段“${fieldName}”应为字符串，当前类型为 ${typeof value}。`);
            }
        }
        else if (fieldName === '重复规则') {
            if (!ALLOWED_RECUR_RULES.includes(value)) {
                warnings.push(`⚠️ 日历事件“重复规则”值“${value}”不合法，允许值：${ALLOWED_RECUR_RULES.join('、')}`);
