        }
        else if (fieldName === '标题' || fieldName === '内容') {
            if (typeof value !== 'string' || value.trim() === '') {
                warnings.push(`⚠️ 日历事件必需字段“${fieldName}”不能为空且必须为字符串。`);
            }
        }
        return warnings;
    }

    // 校验整个事件对象
    function validateEventObject(obj, pathPrefix) {
        const warnings = [];
        const requiredFields = ['标题', '内容', '时间'];
        for (const field of requiredFields) {
            if (!obj.hasOwnProperty(field) || obj[field] === undefined || obj[field] === null || (typeof obj[field] === 'string' && obj[field].trim() === '')) {
                warnings.push(`⚠️ 日历事件缺少必需字段“${field}”，完整路径：${pathPrefix}`);
            } else {
                warnings.push(...validateFieldValue(field, obj[field], `${pathPrefix}.${field}`));
            }
        }
        if (obj.hasOwnProperty('重复规则')) {
            warnings.push(...validateFieldValue('重复规则', obj['重复规则'], `${pathPrefix}.重复规则`));
        }
        if (obj.hasOwnProperty('结束时间')) {
            warnings.push(...validateFieldValue('结束时间', obj['结束时间'], `${pathPrefix}.结束时间`));
