            const idPart = pathParts[3];
            if (idPart && !/^[a-zA-Z0-9_]+$/.test(idPart)) {
                warnings.push(`⚠️ 日历事件ID“${idPart}”格式非法，只允许字母、数字和下划线。`);
            }
        }

        if (type === 'add') {
            // add 命令: args[0]=path, args[1]=value
            const value = args[1];
            // 如果直接对整个事件节点赋值，需要校验对象结构
            if (pathParts.length === 4 && value && typeof value === 'object') {
                // 路径深度为4表示就是事件节点本身（无后续属性）
                warnings.push(...validateEventObject(value, path));
            }
            // 如果是深层设置某个字段（如事件.日历.临时.ID.标题），校验该字段
            else if (pathParts.length >= 5) {
                const fieldName = pathParts[4];
                warnings.push(...validateFieldValue(fieldName, value, path));
            }
        }
        else if (type === 'insert') {
            // insert 命令: args[0]=path, args[1]=key, args[2]=value
            const key = args[1];
            const value = args[2];
            // 如果插入操作的目标是一个事件节点（即在ID节点下插入字段）
            if (pathParts.length === 4 && key && value !== undefined) {
                warnings.push(...validateFieldValue(key, value, `${path}.${key}`));
