                const knownTypes = ['delete', 'insert', 'add'];
                const isKnown = knownTypes.includes(cmd.type);
                const typeClass = isKnown ? `type-${cmd.type}` : 'type-default';
                const typeLabel = cmd.type ? cmd.type.toUpperCase() : 'UNKNOWN';

                let warningHtml = '';
                if (cmd.warn) {
                    warningHtml = `
                        <span class="cmd-warning-badge" title="此路径可能存在拼写或层级错误">
                            ⚠️ 路径存疑 ${cmd.warn}
                        </span>
                    `;
                }
                const path = cmd.args[0] || 'Unknown Path';
                let detailsHtml = '';

                if (cmd.type === 'delete') {
                    detailsHtml = `<div style="color: #ff8888;">即将移除该节点</div>`;
                } 
                else if (cmd.type === 'add') {
                    const val = cmd.args[1];
                    detailsHtml = `<div class="cmd-body">变动值: <span style="color: #4488ff; font-weight:bold;">${val}</span></div>`;
                } 
                else if (cmd.type === 'insert') {
                    const key = cmd.args[1] ? cmd.args[1].replace(/^['"]|['"]$/g, '') : '';
                    const val = cmd.args[2] ? cmd.args[2].replace(/^['"]|['"]$/g, '') : '';
                    detailsHtml = `
                        <div class="cmd-body">
                        <div style="margin-bottom:4px;"><strong>Key:</strong> <span class="cmd-value-text">${key}</span></div>
                        <div style="border-top:1px solid #555; padding-top:4px;">
                            <strong>Value:</strong> <span class="cmd-value-text">${val}</span>
                        </div>
                    </div>`;
                }
                else {
                    let rawVal = cmd.args[1];
                    if (typeof rawVal === 'object') {
                        rawVal = JSON.stringify(rawVal, null, 2);
                    } else if (rawVal === undefined) {
                        rawVal = JSON.stringify(cmd.args.slice(1));
                    }
                    detailsHtml = `
                        <div class="cmd-body">
                            <strong>Value / Args:</strong>
                            <div class="cmd-value-text" style="margin-top: 5px;">${rawVal}</div>
                        </div>`;
                }

                return `
                    <div class="cmd-card ${typeClass}">
                        <div class="cmd-header">
                            <div style="display:flex; align-items:center;">
                                <span class="cmd-type">${typeLabel}</span>
                                ${warningHtml}
                            </div>
                            <span style="opacity: 0.5;">#${index + 1}</span>
                        </div>
                        <div class="cmd-path">Target: ${path}</div>
                        ${detailsHtml}
                    </div>
                `;
            }).join('')}
        </div>`;
    }

    function createCenteredPanel(id, title, commands) {
        if ($(`#${id}`).length) $(`#${id}`).remove();

        const contentHtml = renderCommandList(commands);

        let winWidth = 0;
        let winHeight = 0;

        if (window.innerWidth && window.innerWidth > 0) {
            winWidth = window.innerWidth;
            winHeight = window.innerHeight;
        }

        if ((!winWidth || winWidth <= 100) && window.parent && window.parent !== window) {
            try {
                if (window.parent.innerWidth > 0) {
                    console.log('[MVU Debug] 使用父窗口尺寸');
                    winWidth = window.parent.innerWidth;
                    winHeight = window.parent.innerHeight;
                }
            } catch (e) {
                console.warn('[MVU Debug] 无法访问父窗口尺寸 (跨域限制)', e);
            }
        }

        if (!winWidth || winWidth <= 0) winWidth = 1920;
        if (!winHeight || winHeight <= 0) winHeight = 1080;

        console.log(`[MVU Debug] Final Window Size: ${winWidth} x ${winHeight}`);

        const panelWidth = 600;
        const panelHeight = Math.min(winHeight * 0.7, 800);
        const initLeft = Math.max(0, (winWidth - panelWidth) / 2);
        const initTop = Math.max(0, (winHeight - panelHeight) / 2);

        const panelHtml = `
            <div id="${id}" style="
                position: fixed;
                top: ${initTop}px;
                left: ${initLeft}px;
                width: ${panelWidth}px;
                height: ${panelHeight}px;
                min-width: 400px;
                min-height: 300px;
                display: flex;
                flex-direction: column;
                background-color: #1f2026;
                border: 1px solid #4a4d55;
                box-shadow: 0 10px 30px rgba(0,0,0,0.7);
                z-index: 10000;
                border-radius: 8px;
                color: #eee;
            ">
                <div class="panel-header" style="
                    padding: 12px 15px;
                    background-color: #2b2d36;
                    cursor: move;
                    border-bottom: 1px solid #4a4d55;
                    border-radius: 8px 8px 0 0;
                    font-weight: bold;
                    display: flex; justify-content: space-between; align-items: center;
                    flex-shrink: 0;
                ">
                    <span>${title}</span>
                    <span class="panel-close" style="cursor: pointer; opacity: 0.7;">✖</span>
                </div>

                <div class="panel-body" style="
                    padding: 15px;
                    overflow-y: auto;
                    flex: 1;
                    height: 0;
                ">
                    ${contentHtml}
                </div>

                <div class="panel-footer" style="
                    padding: 12px 15px;
                    border-top: 1px solid #4a4d55;
                    background-color: #25272e;
                    border-radius: 0 0 8px 8px;
                    text-align: center;
                    flex-shrink: 0;
                ">
                    <button class="panel-close-btn" style="background-color: #333; color: #eee; border: 1px solid #555; padding: 8px 20px; border-radius: 4px; cursor: pointer; margin: 0 10px;">关闭</button>
                    <button class="panel-confirm-btn" style="background-color: #333; color: #eee; border: 1px solid #555; padding: 8px 20px; border-radius: 4px; cursor: pointer; margin: 0 10px;">清空</button>
                </div>

                <div class="custom-resize-handle"></div>
            </div>
        `;

        $('body').append(panelHtml);
        const $panel = $(`#${id}`);

        if ($.fn.draggable) {
            $panel.draggable({
                handle: '.panel-header',
                containment: 'window'
            });
        }

        if ($.fn.resizable) {
            $panel.resizable({
                handles: {
                    'se': '.custom-resize-handle'
                },
                minWidth: 400,
                minHeight: 300,
            });
        } else {
            console.warn('jQuery UI Resizable 组件未加载');
        }

        $panel.find('.panel-close, .panel-close-btn').on('click', () => $panel.remove());
        $panel.find('.panel-confirm-btn').on('click', () => {
            Allcommands.length = 0;
            NeedToReport.length = 0;
            console.log('用户确认执行命令');
            $panel.remove();
        });
    }

    function analyzePath(path, rules, mistakes) {
        const result = {
            shouldReport: false,
            matchedRule: null,
            warning: null
        };

        // 先匹配静态规则和动态hint
        for (const mistake of mistakes) {
            if (mistake.pattern.test(path)) {
                if (typeof mistake.hint === 'function') {
                    const dynamicMsg = getDynamicHint(mistake, path);
                    if (dynamicMsg) {
                        result.warning = dynamicMsg;
                        break;
                    } else {
                        // 动态函数未返回信息则继续匹配下一条规则
                        continue;
                    }
                } else {
                    result.warning = mistake.hint;
                    break;
                }
            }
        }

        const matched = rules.find(rule => {
            if (rule.endsWith('.**')) {
                const prefix = rule.slice(0, -3);
                return path === prefix || path.startsWith(prefix + '.');
            }
            const pathSegments = path.split('.');
            const ruleSegments = rule.split('.');
            if (pathSegments.length !== ruleSegments.length) {
                return false;
            }
            return ruleSegments.every((seg, i) => {
                return seg === '*' || seg === pathSegments[i];
            });
        });

        if (matched) {
            result.shouldReport = true;
            result.matchedRule = matched;
        }

        return result;
    }

    function onCommandParsed(variables, commands, message) {
        Allcommands.length = 0;
        for(let i = 0; i < commands.length; ++i)
            Allcommands.push(structuredClone(commands[i]));
    }

    function registerShowVarUpdateButton() {
        if (typeof appendInexistentScriptButtons !== 'function' || typeof getButtonEvent !== 'function') {
            console.log('ACU_SCRIPT: 当前环境不支持 script buttons API，跳过按钮注册。');
            return;
        }

        const BTN_NAME = "显示修改的变量";
        appendInexistentScriptButtons([
            { name: BTN_NAME, visible: true }
        ]);

        const eventName = getButtonEvent(BTN_NAME);
        const bindEvent = (typeof eventOn === 'function') ? eventOn : (window.eventOn || null);

        if (bindEvent) {
            bindEvent(eventName, async () => {
               createCenteredPanel('cmd-preview-panel', '📋 变量变更预览', NeedToReport);
            });
        }
    }

    eventOn(Mvu.events.COMMAND_PARSED, (variables, commands, message_content) => {
        NeedToReport.length = 0;
        onCommandParsed(variables, commands, message_content);
        console.log("commands before patch:", Allcommands);
        let repString = "";
        for(let i = 0; i < Allcommands.length; ++i){
            let tmpStr = "";
            let command = Allcommands[i];
            let path = command.args[0];
            let res = analyzePath(path, monitorRules, commonMistakes);
            // 进行日历变量值内容校验（额外警告）
            const calendarWarnings = validateCalendarCommand(command, path);
            let finalWarning = res.warning || '';
            if (calendarWarnings.length > 0) {
                const combinedWarning = finalWarning ? finalWarning + ' ' + calendarWarnings.join(' ') : calendarWarnings.join(' ');
                finalWarning = combinedWarning;
                command.warn = finalWarning;
            } else if (res.warning) {
                command.warn = res.warning;
            } else {
                command.warn = undefined;
            }
            if(res.warning) {
                tmpStr += `${res.warning}`;
            }
            if(calendarWarnings.length > 0) {
                if(tmpStr) tmpStr += '<br>';
                tmpStr += calendarWarnings.join('<br>');
            }
            if(res.shouldReport) {
                if(!tmpStr) tmpStr = `正在 ${command.type} ${path};`;
                else if (!tmpStr.includes(`正在 ${command.type} ${path}`)) {
                    tmpStr = `正在 ${command.type} ${path};<br>` + tmpStr;
                }
            }
            if(tmpStr.length != 0) {
                tmpStr += '<br>';
                NeedToReport.push(command);
            }
            repString += tmpStr;
        }

        console.log("需要报告的路径", NeedToReport);
        console.log("拼接字符串", repString);
        if(repString.length != 0){
            setTimeout(()=>{
                toastr.info(`${repString}`, '变量被修改',{ escapeHtml: false, timeOut: 7000 })
            }, 500);
        }
    });    
    registerShowVarUpdateButton();
})();


