      @media (max-width: 768px) {
        #${ROOT_ID} .wb-panel {
          top: 12px !important;
          right: 12px !important;
          left: 12px !important;
          width: auto !important;
          max-height: calc(100vh - 24px);
        }

        #${ROOT_ID} .panel-head {
          align-items: flex-start;
          flex-wrap: wrap;
        }

        #${ROOT_ID} .panel-title {
          width: 100%;
          white-space: normal;
          overflow: visible;
          text-overflow: clip;
