        #${ROOT_ID} .panel-tools,
        #${ROOT_ID} .tabs {
          width: 100%;
          flex-wrap: wrap;
        }

        #${ROOT_ID} .panel-tools {
          justify-content: flex-end;
        }

        #${ROOT_ID} .tab-btn {
          flex: 1 1 calc(50% - 8px);
          justify-content: center;
        }

        #${ROOT_ID} .entry-row,
        #${ROOT_ID} .dlc-group-bar {
          align-items: flex-start;
          flex-wrap: wrap;
        }

        #${ROOT_ID} .toggle-pill,
        #${ROOT_ID} .group-meta {
          width: 100%;
        }

        #${ROOT_ID} .dlc-subgroup-list {
