        }

        #${ROOT_ID} .dlc-entry-list {
          padding-left: 4px;
        }
      }
    `;
    pdoc.head.appendChild(style);

    root = pdoc.createElement('div');
    root.id = ROOT_ID;
    (pdoc.documentElement || pdoc.body).appendChild(root);

    app = createApp({
      setup() {
        const panelEl = ref(null);
        const panelBodyEl = ref(null);
        const state = reactive({
          open: false,
          activeTab: 'general',
          searchText: '',
          enabledOnly: false,
          sortMode: 'default',
          dlcCollapsedMap: {},
          dlcSubgroupCollapsedMap: {},
          worldbookName: resolveCurrentWorldbookName(),
          entriesRaw: [],
          loading: false,
          error: '',
          busy: false,
          busyText: '',
          initialized: false,
          restoreScrollTop: null,
          dragEnabled: false,
          dragging: false,
          panelPositionMode: 'default',
          panelTop: 56,
          panelLeft: null,
          dragOffsetX: 0,
          dragOffsetY: 0,
        });

        const panelTitle = computed(() => `${state.worldbookName || '未绑定世界书'} 世界书管理`);
        const entriesView = computed(() => state.entriesRaw.map(normalizeEntry));
        const tabEntries = computed(() => entriesView.value.filter((entry) => entry.category === state.activeTab));
        const searchedEntries = computed(() => {
          const query = state.searchText.trim().toLowerCase();
          if (!query) return tabEntries.value;
          return tabEntries.value.filter((entry) => entry.name.toLowerCase().includes(query));
        });
        const visibleEntries = computed(() => sortEntries(
          state.enabledOnly
            ? searchedEntries.value.filter((entry) => entry.enabled)
            : searchedEntries.value,
          state.sortMode,
        ));
        const enabledCount = computed(() => visibleEntries.value.filter((entry) => entry.enabled).length);
        const dlcGroups = computed(() => buildDlcGroups(
          visibleEntries.value,
          state.dlcCollapsedMap,
          state.dlcSubgroupCollapsedMap,
        ));
        const panelStyle = computed(() => {
          if (!state.dragEnabled || state.panelPositionMode !== 'custom' || state.panelLeft == null) {
            return null;
          }
          return {
            top: `${state.panelTop}px`,
            left: `${state.panelLeft}px`,
            right: 'auto',
          };
        });

        function isMobileViewport() {
          return (pwin.innerWidth || window.innerWidth || 0) <= MOBILE_BREAKPOINT;
        }

        function getViewportSize() {
          return {
            width: pwin.innerWidth || window.innerWidth || pdoc.documentElement?.clientWidth || 0,
            height: pwin.innerHeight || window.innerHeight || pdoc.documentElement?.clientHeight || 0,
          };
        }

        function clampPanelPosition(top, left) {
          const panelNode = panelEl.value;
          const { width: viewportWidth, height: viewportHeight } = getViewportSize();
          const panelWidth = panelNode?.offsetWidth || Math.min(420, Math.max(0, viewportWidth - 32));
          const panelHeight = panelNode?.offsetHeight || Math.max(240, viewportHeight - 96);
          const maxLeft = Math.max(PANEL_SAFE_MARGIN, viewportWidth - panelWidth - PANEL_SAFE_MARGIN);
          const maxTop = Math.max(PANEL_SAFE_MARGIN, viewportHeight - panelHeight - PANEL_SAFE_MARGIN);
          return {
            top: Math.min(Math.max(PANEL_SAFE_MARGIN, top), maxTop),
            left: Math.min(Math.max(PANEL_SAFE_MARGIN, left), maxLeft),
          };
        }

        function resetPanelPositionMode() {
          state.panelPositionMode = 'default';
          state.panelTop = 56;
          state.panelLeft = null;
          state.dragging = false;
        }

        function syncViewportMode() {
          state.dragEnabled = !isMobileViewport();
          if (!state.dragEnabled) {
            resetPanelPositionMode();
          }
        }

        function rememberPanelScroll() {
          state.restoreScrollTop = panelBodyEl.value ? panelBodyEl.value.scrollTop : null;
        }

        async function restorePanelScrollIfNeeded() {
          if (state.restoreScrollTop == null) return;
          await nextTick();
          if (panelBodyEl.value) {
            panelBodyEl.value.scrollTop = state.restoreScrollTop;
          }
          state.restoreScrollTop = null;
        }

        async function ensureDesktopPanelPosition() {
          if (!state.dragEnabled || state.panelPositionMode === 'custom') return;
          await nextTick();
          const panelNode = panelEl.value;
          if (!panelNode) return;
          const { width: viewportWidth } = getViewportSize();
          const panelWidth = panelNode.offsetWidth || 420;
          const desiredLeft = viewportWidth - panelWidth - 24;
          const nextPosition = clampPanelPosition(56, desiredLeft);
          state.panelTop = nextPosition.top;
          state.panelLeft = nextPosition.left;
        }

        async function loadWorldbookEntries(options = {}) {
          const { silent = false } = options;
          state.worldbookName = resolveCurrentWorldbookName();
          state.loading = true;
          state.error = '';

          if (!state.worldbookName) {
            state.loading = false;
            state.error = '当前角色卡未绑定世界书';
            if (!silent) {
              showToast('warning', state.error);
            }
            return;
          }

          try {
            const worldbook = await getWorldbook(state.worldbookName);
            state.entriesRaw = Array.isArray(worldbook) ? worldbook : [];
            state.initialized = true;
            if (!silent) {
              showToast('success', `已加载 ${state.worldbookName} 条目：${entriesView.value.length} 项`);
            }
          } catch (error) {
            state.error = error?.message || '读取世界书失败';
            console.error(error);
            showToast('error', state.error, '世界书读取失败');
          } finally {
            state.loading = false;
          }
        }

        async function runWorldbookUpdate(busyText, updater, errorMessage) {
          if (state.busy) return false;

          state.worldbookName = resolveCurrentWorldbookName();
          if (!state.worldbookName) {
            showToast('warning', '当前角色卡未绑定世界书');
            return false;
          }

          rememberPanelScroll();
          state.busy = true;
          state.busyText = busyText;

          try {
            const updated = await updateWorldbookWith(state.worldbookName, updater, { render: 'immediate' });
            state.entriesRaw = Array.isArray(updated) ? updated : state.entriesRaw;
            return true;
          } catch (error) {
            console.error(error);
            showToast('error', error?.message || errorMessage, '世界书更新失败');
            return false;
          } finally {
            state.busy = false;
            state.busyText = '';
            await restorePanelScrollIfNeeded();
          }
        }

        async function toggleEntry(uid, targetEnabled) {
          const current = entriesView.value.find((entry) => entry.uid === uid);
          if (!current) return;
          const nextEnabled = typeof targetEnabled === 'boolean' ? targetEnabled : !current.enabled;
          await runWorldbookUpdate(
            `${nextEnabled ? '启用' : '关闭'}条目中...`,
            (worldbook) => worldbook.map((entry) => (
              entry.uid === uid
                ? { ...entry, enabled: nextEnabled }
                : entry
            )),
            '切换条目失败',
          );
        }

        async function toggleDlcGroup(groupKey, subgroupKey, targetEnabled) {
          const groupItems = entriesView.value.filter((entry) => (
            entry.category === 'dlc'
            && entry.dlcGroupKey === groupKey
            && entry.dlcSubgroupKey === subgroupKey
          ));
          if (!groupItems.length) return;

          const uidSet = new Set(groupItems.map((entry) => entry.uid));
          await runWorldbookUpdate(
            `${targetEnabled ? '批量开启' : '批量关闭'}分组中...`,
            (worldbook) => worldbook.map((entry) => (
              uidSet.has(entry.uid)
                ? { ...entry, enabled: targetEnabled }
                : entry
            )),
            'DLC 分组更新失败',
          );
        }

        function toggleDlcCollapse(groupKey) {
          state.dlcCollapsedMap[groupKey] = !(state.dlcCollapsedMap[groupKey] ?? true);
        }

        function toggleDlcSubgroupCollapse(groupKey, subgroupKey) {
          const stateKey = getDlcSubgroupStateKey(groupKey, subgroupKey);
          state.dlcSubgroupCollapsedMap[stateKey] = !(state.dlcSubgroupCollapsedMap[stateKey] ?? true);
        }

        function handlePanelPointerDown(event) {
          if (!state.dragEnabled || state.busy) return;
          if (event.button != null && event.button !== 0) return;
          if (event.target?.closest?.('button, input, textarea, select, a')) return;
          const panelNode = panelEl.value;
          if (!panelNode) return;
          const rect = panelNode.getBoundingClientRect();
          state.dragging = true;
          state.dragOffsetX = event.clientX - rect.left;
          state.dragOffsetY = event.clientY - rect.top;
          if (typeof event.preventDefault === 'function') {
            event.preventDefault();
          }
        }

        function handleGlobalPointerMove(event) {
          if (!state.dragging || !state.dragEnabled) return;
          const nextTop = event.clientY - state.dragOffsetY;
          const nextLeft = event.clientX - state.dragOffsetX;
          const nextPosition = clampPanelPosition(nextTop, nextLeft);
          state.panelPositionMode = 'custom';
          state.panelTop = nextPosition.top;
          state.panelLeft = nextPosition.left;
        }

        function stopDragging() {
          state.dragging = false;
        }

        async function openPanel() {
          syncViewportMode();
          state.open = true;
          root?.classList.add('is-open');
          if (!state.initialized && !state.loading) {
            await loadWorldbookEntries({ silent: true });
          }
          await ensureDesktopPanelPosition();
        }

        function closePanel() {
          state.open = false;
          state.dragging = false;
          root?.classList.remove('is-open');
        }

        async function togglePanel() {
          if (state.open) {
            closePanel();
            return;
          }
          await openPanel();
        }

        async function handleViewportResize() {
          const wasDragEnabled = state.dragEnabled;
          syncViewportMode();
          if (!state.open) return;
          await nextTick();
          if (!state.dragEnabled) {
            return;
          }
          if (!wasDragEnabled || state.panelPositionMode !== 'custom' || state.panelLeft == null) {
            await ensureDesktopPanelPosition();
            return;
          }
          const nextPosition = clampPanelPosition(state.panelTop, state.panelLeft);
          state.panelTop = nextPosition.top;
          state.panelLeft = nextPosition.left;
        }

        function renderChevron(expanded) {
          return h(
            'span',
            {
              class: ['dlc-chevron', expanded && 'is-expanded'],
              'aria-hidden': 'true',
            },
            [
              h(
                'svg',
                {
                  xmlns: 'http://www.w3.org/2000/svg',
                  width: '24',
                  height: '24',
                  viewBox: '0 0 24 24',
                  fill: 'none',
                  stroke: 'currentColor',
                  'stroke-width': '2',
                  'stroke-linecap': 'round',
                  'stroke-linejoin': 'round',
                },
                [h('path', { d: 'm9 18 6-6-6-6' })],
              ),
            ],
          );
        }

        function renderEntryRow(entry) {
          return h(
            'button',
            {
              key: entry.uid,
              type: 'button',
              class: ['entry-row', entry.enabled && 'is-on'],
              disabled: state.busy,
              onClick: () => toggleEntry(entry.uid),
            },
            [
              h('div', { class: 'entry-main' }, [
                h('div', { class: 'entry-name' }, entry.name),
              ]),
              h('span', { class: 'toggle-pill' }, entry.enabled ? '已启用' : '已关闭'),
            ],
          );
        }

        function renderDlcList() {
          if (!dlcGroups.value.length) {
            return h('div', { class: 'empty-box' }, '当前 DLC 分类没有匹配条目。');
          }

          return dlcGroups.value.map((group) => h(
            'section',
            { key: group.groupKey, class: 'dlc-group' },
            [
              h(
                'button',
                {
                  type: 'button',
                  class: 'dlc-group-bar',
                  onClick: () => toggleDlcCollapse(group.groupKey),
                },
                [
                  h('span', { class: 'dlc-group-label' }, [
                    renderChevron(!group.collapsed),
                    h('span', { class: 'dlc-group-name' }, group.groupKey),
                  ]),
                  h('span', { class: 'group-meta' }, `（${group.enabledCount}/${group.count} 已启用）`),
                ],
              ),
              !group.collapsed && h(
                'div',
                { class: 'dlc-subgroup-list' },
                group.groups.map((subgroup) => h(
                  'section',
                  {
                    key: `${group.groupKey}::${subgroup.subgroupKey}`,
                    class: 'dlc-subgroup',
                  },
                  [
                    h('div', { class: 'dlc-subgroup-bar' }, [
                      h(
                        'button',
                        {
                          type: 'button',
                          class: 'dlc-subgroup-toggle',
                          onClick: () => toggleDlcSubgroupCollapse(group.groupKey, subgroup.subgroupKey),
                        },
                        [
                          renderChevron(!subgroup.collapsed),
                          h('span', { class: 'dlc-subgroup-label' }, [
                            h('span', { class: 'dlc-subgroup-name' }, subgroup.subgroupKey),
                            h('span', { class: 'group-meta' }, `（${subgroup.enabledCount}/${subgroup.count} 已启用）`),
                          ]),
                        ],
                      ),
                      h('div', { class: 'dlc-subgroup-actions' }, [
                        h(
                          'button',
                          {
                            type: 'button',
                            class: 'group-action-btn',
                            disabled: state.busy,
                            onClick: (event) => {
                              event.stopPropagation();
                              toggleDlcGroup(group.groupKey, subgroup.subgroupKey, true);
                            },
                          },
                          '全开',
                        ),
                        h(
                          'button',
                          {
                            type: 'button',
                            class: 'group-action-btn',
                            disabled: state.busy,
                            onClick: (event) => {
                              event.stopPropagation();
                              toggleDlcGroup(group.groupKey, subgroup.subgroupKey, false);
                            },
                          },
                          '全关',
                        ),
                      ]),
                    ]),
                    !subgroup.collapsed && h(
                      'div',
                      { class: 'dlc-entry-list' },
                      subgroup.items.map(renderEntryRow),
                    ),
                  ],
                )),
              ),
            ],
          ));
        }

        function renderToolbarMeta() {
          const children = [
            h('span', null, `当前 Tab：${visibleEntries.value.length} 项 / 已启用 ${enabledCount.value} 项`),
            h(
              'span',
              null,
              state.searchText.trim()
                ? `分类总数：${tabEntries.value.length} 项 / 搜索命中 ${searchedEntries.value.length} 项`
                : `分类总数：${tabEntries.value.length} 项`,
            ),
          ];

          if (state.busy) {
            children.push(
              h('span', { class: 'busy-inline' }, [
                h('span', { class: 'busy-dot' }),
                state.busyText || '正在更新世界书状态...',
              ]),
            );
          }

          return h('div', { class: 'toolbar-meta' }, children);
        }

        function renderBodyContent() {
          if (state.loading) {
            return h('div', { class: 'status-box' }, '正在读取世界书条目...');
          }
          if (state.error) {
            return h('div', { class: 'error-box' }, `读取失败：${state.error}`);
          }
          if (!visibleEntries.value.length) {
            return h('div', { class: 'empty-box' }, '没有匹配的条目。可尝试切换 Tab、清空搜索或刷新。');
          }
          if (state.activeTab === 'dlc') {
            return renderDlcList();
          }
          return visibleEntries.value.map(renderEntryRow);
        }

        syncViewportMode();
        addManagedListener(pwin, 'pointermove', handleGlobalPointerMove);
        addManagedListener(pwin, 'pointerup', stopDragging);
        addManagedListener(pwin, 'pointercancel', stopDragging);
        addManagedListener(pwin, 'resize', handleViewportResize);

        panelApi = {
          openPanel,
          closePanel,
          togglePanel,
          loadWorldbookEntries,
        };

        return () => h('div', null, [
          h('div', { class: 'wb-mask', onClick: closePanel }),
          h(
            'section',
            {
              class: ['wb-panel', state.dragEnabled && 'is-draggable', state.dragging && 'is-dragging'],
              style: panelStyle.value,
              ref: panelEl,
              'aria-label': '世界书管理面板',
            },
            [
              h('div', { class: 'panel-head', onPointerdown: handlePanelPointerDown }, [
                h('div', { class: 'panel-title', title: panelTitle.value }, panelTitle.value),
                h('div', { class: 'panel-tools' }, [
                  h(
                    'button',
                    {
                      type: 'button',
                      class: 'icon-btn',
                      disabled: state.loading || state.busy,
                      onClick: () => loadWorldbookEntries(),
                    },
                    '刷新',
                  ),
                  h(
                    'button',
                    { type: 'button', class: 'icon-btn', onClick: closePanel },
                    '✕',
                  ),
                ]),
              ]),
              h('div', { class: 'panel-toolbar' }, [
                h('div', { class: 'tabs' }, TABS.map((tab) => h(
                  'button',
                  {
                    key: tab.key,
                    type: 'button',
                    class: ['tab-btn', state.activeTab === tab.key && 'is-active'],
                    onClick: () => {
                      state.activeTab = tab.key;
                    },
                  },
                  tab.label,
                ))),
                h('div', { class: 'tabs' }, [
                  h(
                    'button',
                    {
                      type: 'button',
                      class: ['tab-btn', state.enabledOnly && 'is-active'],
                      onClick: () => {
                        state.enabledOnly = !state.enabledOnly;
                      },
                    },
                    state.enabledOnly ? '仅看启用：开' : '仅看启用：关',
                  ),
                  h(
                    'button',
                    {
                      type: 'button',
                      class: ['tab-btn', state.sortMode === 'enabled-first' && 'is-active'],
                      onClick: () => {
                        state.sortMode = state.sortMode === 'enabled-first' ? 'default' : 'enabled-first';
                      },
                    },
                    state.sortMode === 'enabled-first' ? '排序：启用优先' : '排序：默认',
                  ),
                ]),
                h('input', {
                  class: 'search-input',
                  type: 'text',
                  value: state.searchText,
                  placeholder: '按名称搜索当前 Tab 条目',
                  disabled: state.loading,
                  onInput: (event) => {
                    state.searchText = event.target.value;
                  },
                }),
                renderToolbarMeta(),
              ]),
              h(
                'div',
                { class: 'panel-body', ref: panelBodyEl },
                Array.isArray(renderBodyContent()) ? renderBodyContent() : [renderBodyContent()],
              ),
            ],
          ),
        ]);
      },
    });

    app.mount(root);
  }

  function closePanel() {
    panelApi?.closePanel?.();
  }

  async function togglePanel() {
    ensureUiMounted();
    await panelApi?.togglePanel?.();
  }

  function destroy(options = {}) {
    if (destroyed) return;
    destroyed = true;

    const { unregister = false, silent = false } = options;

    while (cleanupTasks.length) {
      const task = cleanupTasks.pop();
      try {
        task?.();
      } catch (error) {
        console.warn('清理世界书 Vue 模块监听失败:', error);
      }
    }

    try {
      app?.unmount?.();
    } catch (error) {
      console.warn('卸载世界书 Vue 应用失败:', error);
    }

    app = null;
    panelApi = null;
    root?.remove();
    style?.remove();
    root = null;
    style = null;

    if (unregister && registeredToHost && typeof host.unregisterModule === 'function') {
      try {
        const result = host.unregisterModule(MODULE_KEY);
        if (!silent && result?.ok) {
          showToast('info', '已从宿主注销世界书模块');
        }
      } catch (error) {
        console.warn('注销世界书 Vue 模块失败:', error);
      }
    }

    if (pwin[INSTANCE_KEY]?.destroy === destroy) {
      delete pwin[INSTANCE_KEY];
    }
  }

  function handleDocumentKeyDown(event) {
    if (event.key === 'Escape') {
      closePanel();
    }
  }

  function handlePageExit() {
    destroy({ unregister: true, silent: true });
  }

  ensureUiMounted();
  addManagedListener(pdoc, 'keydown', handleDocumentKeyDown);
  addManagedListener(window, 'pagehide', handlePageExit);
  addManagedListener(window, 'unload', handlePageExit);

  const registerResult = host.registerModule({
    key: MODULE_KEY,
    name: MODULE_NAME,
    onClick: togglePanel,
  });

  if (!registerResult?.ok) {
    showToast('error', `注册失败：${registerResult?.reason || '未知原因'}`);
    destroy({ unregister: false, silent: true });
    return;
  }

  registeredToHost = true;
  pwin[INSTANCE_KEY] = {
    destroy,
    togglePanel,
    closePanel,
  };
}));
